INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279f2e3c98b0941765832', '装修虽老但仍然坚韧地想要散发出昔日辉煌的余晖，岭南风和经典港派中国风结合的没有违和感，房间设施维护地尚可但卫生仍有提升空间，细节处把握不到位。酒店管理体现了国际化的水准，服务的标准化做得不错，对客人的需求响应比较积极。预定时提出了高楼层、无烟、远离电梯的要求，头晚的房间基本没达到这个要求，一夜因电梯噪音未休息好，看来酒店对客户的需求没有充分关注，管理在细节层面是存在疏漏和待改善之处。次日在夫人的反馈下，酒店更换调整了房间，说明酒店在回应客户需求和应急处理方面还是比较方面。酒店地理位置、设施配套、管理水准方面作为老牌五星还是具备一定的性价比的，没住过的可以感受一下。', '["https://dimg04.c-ctrip.com/images/0234k12000fz1gu33F7D4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000fz14pk19B21_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-10-04', '红棉大床套房', '套房', '家庭亲子', 285, 5.655991810819852, 0, 0.0, 21, 3.091042453358316, 8, '["房间设施", "安静程度", "整体满意度"]'::jsonb, '房间设施', '安静程度', '整体满意度', '未知酒店', '未知地点', '匿名', '装修虽老但仍然坚韧地想要散发出昔日辉煌的余晖，岭南风和经典港派中国风结合的没有违', '装修虽老但仍然坚韧地想要散发出昔日辉煌的余晖，岭南风和经典港派中国风结合的没有违和感，房间设施维护地尚可但卫生仍有提升空间，细节处把握不到位。酒店管理体现了国际化的水准，服务的标准化做得不错，对客人的需求响应比较积极。预定时提出了高楼层、无烟、远离电梯的要求，头晚的房间基本没达到这个要求，一夜因电梯噪音未休息好，看来酒店对客户的需求没有充分关注，管理在细节层面是存在疏漏和待改善之处。次日在夫人的反馈下，酒店更换调整了房间，说明酒店在回应客户需求和应急处理方面还是比较方面。酒店地理位置、设施配套、管理水准方面作为老牌五星还是具备一定的性价比的，没住过的可以感受一下。', '2024-10-04', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279f2e3c98b0941765833', '酒店高大上，房间干净整洁优雅，服务一流。花园设计漂亮心怡，有红色小桥，有大瀑布，还有不同种的鱼游来游去，非常满意的一次住宿。', '["https://dimg04.c-ctrip.com/images/0231e12000gx5i3vr2276_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000gx5mcsq7E23_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236c12000gx4t8997F0B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000gx5op6iF7F7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-28', '花园大床房', '大床房', '独自旅行', 62, 4.143134726391533, 0, 0.0, 32, 3.49650756146648, 7, '["整体满意度", "卫生状况", "公共设施"]'::jsonb, '整体满意度', '卫生状况', '公共设施', '未知酒店', '未知地点', '匿名', '酒店高大上，房间干净整洁优雅，服务一流。花园设计漂亮心怡，有红色小桥，有大瀑布，', '酒店高大上，房间干净整洁优雅，服务一流。花园设计漂亮心怡，有红色小桥，有大瀑布，还有不同种的鱼游来游去，非常满意的一次住宿。', '2024-11-28', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279f2e3c98b0941765834', '订的红棉双床房，给升级了。酒店非常有历史，服务态度很好。大厅很气派，一家出行建议订64平方米的，有两个洗脸台。设施不新了，房间窗户不能打开，一定要开空调换气。双床比较小，2人睡不开。可以不用订早餐，周边吃的很多。住置好，出行方便。', '["https://dimg04.c-ctrip.com/images/0230512000g0uctxqB4E6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000g0tqd6697E1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000g0u7fyq8F4F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2024-10-07', '红棉双床套房', '套房', '家庭亲子', 115, 4.7535901911063645, 0, 0.0, 2, 1.0986122886681098, 7, '["房间设施", "周边配套", "交通便利性"]'::jsonb, '房间设施', '周边配套', '交通便利性', '未知酒店', '未知地点', '匿名', '订的红棉双床房，给升级了。酒店非常有历史，服务态度很好。大厅很气派，一家出行建议', '订的红棉双床房，给升级了。酒店非常有历史，服务态度很好。大厅很气派，一家出行建议订64平方米的，有两个洗脸台。设施不新了，房间窗户不能打开，一定要开空调换气。双床比较小，2人睡不开。可以不用订早餐，周边吃的很多。住置好，出行方便。', '2024-10-07', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279f2e3c98b0941765835', '设施：这个房间标间我必需吐槽下，我性别女，是代父亲出门旅行，房间卫生间不封闭步入式浴缸外无遮挡，非常不方便。住三晚，第一晚结束问服务员，说标间都是这样，就没换房间，以后要是再代父亲出行，我可能不会选择这个酒店。自己来还会住。
服务：清洁很干净，头天叫送了一次矿泉水，第二天就自动多给了水，还主动送了糕点，体验感非常不错。服务员服务意识很强，态度也很好。
饮食：吃了荔湾亭早茶，算是规矩吧，之前在白天鹅吃了早茶，有了对比，比较的话性价比还行。', '["https://dimg04.c-ctrip.com/images/0230812000fzyz4tf171B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230x12000fzyp8lf386E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230r12000fzz8kc430F4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235n12000fzyqo606B8C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230z12000fzy7gzg9086_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232i12000fzz75ut1930_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.8, 3, '2024-10-05', '花园双床房', '双床房', '家庭亲子', 220, 5.3981627015177525, 0, 0.0, 10, 2.3978952727983707, 9, '["房间设施", "客房服务", "性价比"]'::jsonb, '房间设施', '客房服务', '性价比', '未知酒店', '未知地点', '匿名', '设施：这个房间标间我必需吐槽下，我性别女，是代父亲出门旅行，房间卫生间不封闭步入', '设施：这个房间标间我必需吐槽下，我性别女，是代父亲出门旅行，房间卫生间不封闭步入式浴缸外无遮挡，非常不方便。住三晚，第一晚结束问服务员，说标间都是这样，就没换房间，以后要是再代父亲出行，我可能不会选择这个酒店。自己来还会住。
服务：清洁很干净，头天叫送了一次矿泉水，第二天就自动多给了水，还主动送了糕点，体验感非常不错。服务员服务意识很强，态度也很好。
饮食：吃了荔湾亭早茶，算是规矩吧，之前在白天鹅吃了早茶，有了对比，比较的话性价比还行。', '2024-10-05', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279f2e3c98b0941765836', '住了无数次，每次来广州都选这里，主要是周围太方便，吃喝玩乐哪哪都近，对面友谊商店购物全满足，出门口就是地铁便宜的跑遍全广州，门口出租车24小时在线，市中心的地方到哪里哈皮都不怕的士费贵到哪里去。周围吃饭喝茶的地方打开大众点评全是各种老字号扎堆。有人说越秀区是广州的最中心，那花园酒店这里就是是越秀区的中心，非常喜欢这个位置，花园酒店的服务又代表了正宗老广的味道，所以，来广州就来试一试吧，门口的地铁还可以带你去好多地方畅游岭南文化', '["https://dimg04.c-ctrip.com/images/0234612000h9k33ea4683_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233u12000h9jshl36B22_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-12-18', '花园大床房', '大床房', '朋友出游', 215, 5.375278407684165, 0, 0.0, 10, 2.3978952727983707, 9, '["交通便利性", "周边配套", "整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度', '未知酒店', '未知地点', '匿名', '住了无数次，每次来广州都选这里，主要是周围太方便，吃喝玩乐哪哪都近，对面友谊商店', '住了无数次，每次来广州都选这里，主要是周围太方便，吃喝玩乐哪哪都近，对面友谊商店购物全满足，出门口就是地铁便宜的跑遍全广州，门口出租车24小时在线，市中心的地方到哪里哈皮都不怕的士费贵到哪里去。周围吃饭喝茶的地方打开大众点评全是各种老字号扎堆。有人说越秀区是广州的最中心，那花园酒店这里就是是越秀区的中心，非常喜欢这个位置，花园酒店的服务又代表了正宗老广的味道，所以，来广州就来试一试吧，门口的地铁还可以带你去好多地方畅游岭南文化', '2024-12-18', 5, '交通便利性');
