INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279f2e3c98b0941765839', '感谢工作人员YOLO，工作专业，给安排的房间非常好，酒店的庭院非常美，无论是石头浮雕，还是瀑布，都意蕴着中华文化博大精深的浓厚底蕴，作为改革开放y的一面窗口，经典永远不会过时，给花园酒店点赞??另外，酒店地理位置优越，旁边就是地铁口，还有广州酒家、陶陶居等两家著名茶楼，推荐广州酒家炒面，陶陶居水牛奶蛋挞，期待下一次相遇。房间非常大，隔音，完全想不到有些人为啥要求那么苛刻。', '["https://dimg04.c-ctrip.com/images/0236912000fyupv9n1522_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230a12000fyufvsb150A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237112000fyukssbE5A6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p12000fyudzz5BCF4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235912000fyub9fmE0C3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230x12000fytueor0ED9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230k12000fyurdzm4CC0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000fyuivwl75EC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236712000fyubsqn79A0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-04', '花园双床房', '双床房', '其他', 187, 5.236441962829949, 0, 0.0, 2, 1.0986122886681098, 8, '["整体满意度", "交通便利性", "周边配套"]'::jsonb, '整体满意度', '交通便利性', '周边配套', '未知酒店', '未知地点', '匿名', '感谢工作人员YOLO，工作专业，给安排的房间非常好，酒店的庭院非常美，无论是石头', '感谢工作人员YOLO，工作专业，给安排的房间非常好，酒店的庭院非常美，无论是石头浮雕，还是瀑布，都意蕴着中华文化博大精深的浓厚底蕴，作为改革开放y的一面窗口，经典永远不会过时，给花园酒店点赞??另外，酒店地理位置优越，旁边就是地铁口，还有广州酒家、陶陶居等两家著名茶楼，推荐广州酒家炒面，陶陶居水牛奶蛋挞，期待下一次相遇。房间非常大，隔音，完全想不到有些人为啥要求那么苛刻。', '2024-10-04', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279f2e3c98b094176583a', '广州花园酒店名声在外慕名而来，后花园瀑布和锦鲤池让人赞叹不已，下午茶的点心名不虚传，值得以后再来光顾～', '["https://dimg04.c-ctrip.com/images/0230m12000j38dlr86EDA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h12000j38fe8i4ACE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000j36v4m5FD8F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-15', '花园大床房', '大床房', '家庭亲子', 51, 3.951243718581428, 0, 0.0, 6, 1.9459101490553128, 7, '["公共设施", "餐饮设施", "整体满意度"]'::jsonb, '公共设施', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '广州花园酒店名声在外慕名而来，后花园瀑布和锦鲤池让人赞叹不已，下午茶的点心名不虚', '广州花园酒店名声在外慕名而来，后花园瀑布和锦鲤池让人赞叹不已，下午茶的点心名不虚传，值得以后再来光顾～', '2025-03-15', 5, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279f2e3c98b094176583b', '携程的3天2晚大床房套餐，看网上说大床房比较小，而且有施工噪音，在前台加钱升级的红棉房。
泳池很棒，在旁边躺着也很舒服。有毛巾和饮料。旁边有更衣室，桑拿，淋浴。
博物馆，值得参观下。了解酒店历史。
后花园有瀑布和鲤鱼池。在瀑布餐厅旁边的玻璃门出去，通道有点昏暗。出去后感觉进去另一个空间，但是旁边在施工，柴油味，打钻的声音，还有瀑布的隆隆水声，夹杂在一起，体验不是很好。
打卡酒店的瀑布餐厅(自助早餐)，桃圆餐厅(套餐形式的早餐)，30楼行政走廊(下午茶和晚上的欢乐时光)，还有荔湾厅。瀑布餐厅就是西式自助早餐，也有中式的早餐，面摊的细面好吃，但是没有粤式点心，图中的面包(展示柜里)不好吃。行政酒廊菜品太少，不建议去，但服务很到位，靠窗位只有早餐时间开放。荔湾厅吃了个粉，10%的服务费，不是很理解服务在哪里。本来还想去吃晚饭的，失望的不想去。
附近施工的噪音，房间也能听到，客房服务热心得给换了2次房间，但还是有噪音，不勉强，确实环境不允许。房间有些硬件不好，提了意见，酒店送了水果表示歉意，希望能改善吧。
整体体验可以，附近的施工结束后，会再去体验下。', '["https://dimg04.c-ctrip.com/images/0233i12000fcmutqt1F52_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234y12000fcne716DA53_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000fcn8dyhDA87_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000fcmu9dtE667_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000fcn314zCF65_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233a12000fcn8cko83C9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000fcmdll8121F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000fcnealwD4A3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000fcmpyha27CB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.1, 4, '2024-09-02', '花园大床房', '大床房', '情侣出游', 479, 6.173786103901937, 0, 0.0, 7, 2.079441541679836, 9, '["安静程度", "房间设施", "客房服务"]'::jsonb, '安静程度', '房间设施', '客房服务', '未知酒店', '未知地点', '匿名', '携程的3天2晚大床房套餐，看网上说大床房比较小，而且有施工噪音，在前台加钱升级的', '携程的3天2晚大床房套餐，看网上说大床房比较小，而且有施工噪音，在前台加钱升级的红棉房。
泳池很棒，在旁边躺着也很舒服。有毛巾和饮料。旁边有更衣室，桑拿，淋浴。
