INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279fde3c98b094176583f', '服务除了前台偏冷漠外，其他都很好，早餐竹升面加牛腩很不错但一定要早点去，不然排队很长，或者就是选酒廊早餐东西很少但胜在清净。受限于年代久远，房间设施有些古老了，很多开关设置不合理，顶高也有些压抑，但整体细节保养的不错，也有很多诸如化妆凳这样的贴心设置。室外的瀑布很有岭南风情，健身设施较全但有很多在维修。', '["https://dimg04.c-ctrip.com/images/0233r12000g07a6nm02D8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000g077rvs659D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000g06ox8wEB18_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.3, 4, '2024-10-06', '红棉大床套房', '套房', '情侣出游', 152, 5.030437921392435, 0, 0.0, 13, 2.6390573296152584, 9, '["房间设施", "餐饮设施", "前台服务"]'::jsonb, '房间设施', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '服务除了前台偏冷漠外，其他都很好，早餐竹升面加牛腩很不错但一定要早点去，不然排队', '服务除了前台偏冷漠外，其他都很好，早餐竹升面加牛腩很不错但一定要早点去，不然排队很长，或者就是选酒廊早餐东西很少但胜在清净。受限于年代久远，房间设施有些古老了，很多开关设置不合理，顶高也有些压抑，但整体细节保养的不错，也有很多诸如化妆凳这样的贴心设置。室外的瀑布很有岭南风情，健身设施较全但有很多在维修。', '2024-10-06', 4, '房间设施');
