INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279fde3c98b0941765844', '酒店大堂很漂亮，服务态度也很好，家庭出游不错的选择！', '["https://dimg04.c-ctrip.com/images/0231a12000i4ergol8215_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235412000i4ejjzr7304_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236c12000i4efgqzF771_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-28', '花园双床房', '双床房', '家庭亲子', 26, 3.295836866004329, 0, 0.0, 14, 2.70805020110221, 4, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '酒店大堂很漂亮，服务态度也很好，家庭出游不错的选择！', '酒店大堂很漂亮，服务态度也很好，家庭出游不错的选择！', '2025-01-28', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680279fde3c98b0941765845', '这次入住花园酒店是为了庆祝女朋友生日
非常感谢广州花园酒店给了我们这么美好的周末
广州花园酒店虽然已经有接近40年的历史了
但是房间，酒店设施，设计风格
一点都看不出老旧的感觉
——————分割线——————
我们买的是酒店1088的套餐
包含双早+大床房+双人自助茶市（夜晚）
星期六晚上办理入住的时候
可能是晚上比较多人入住
酒店临时加开了办入住的工作人员
仅用十分钟就拿到房卡
因为是庆祝生日，我提前几天就打电话给酒店
想说布置一下房间，结果一打开房门真的很惊喜
（在此感谢当时接电话，帮我安排的总机小黄）
到了荔湾亭，接待我们的男经理（穿黑色衣服）
很热情！还知道是庆祝生日，提出送了两份主食
（点赞????但不记得他的工牌了）
第二天早餐～～
是我吃过最丰盛的酒店早餐之一了
比珠江新城的一些奢侈酒店还丰盛
带我们入坐的是MONEY（好像是这个名字）
是一位外籍人士，但是普通话超级好！
总的来说再次很感谢花园酒店给我们这么好的回忆
不仅给我女朋友一个美好的生日
更为我们洗去一周的班味～～', '["https://dimg04.c-ctrip.com/images/0234o12000gujl10a780D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000gujm6zcB5A1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230x12000gujansl9D28_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000gujl186161D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-24', '花园大床房', '大床房', '情侣出游', 450, 6.111467339502679, 0, 0.0, 6, 1.9459101490553128, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '这次入住花园酒店是为了庆祝女朋友生日', '这次入住花园酒店是为了庆祝女朋友生日
