INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a0ae3c98b0941765846', '客房不错，细节服务挺好。大堂李文和小何服务很好', '["https://dimg04.c-ctrip.com/images/0235z12000jfvi0hz1592_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000jfvrxge3C08_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236w12000jfw58l88C9A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-31', '花园双床房', '双床房', '朋友出游', 23, 3.1780538303479458, 0, 0.0, 4, 1.6094379124341005, 5, '["前台服务", "客房服务"]'::jsonb, '前台服务', '客房服务', NULL, '未知酒店', '未知地点', '匿名', '客房不错，细节服务挺好。大堂李文和小何服务很好', '客房不错，细节服务挺好。大堂李文和小何服务很好', '2025-03-31', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a0ae3c98b0941765847', '来之前比较了很多家，还是挑选了这家底蕴深厚的老牌五星，卫生、设施、管理和服务都有品质保证：
房间整洁宽敞，装修材质好品牌好，床品舒适，遇到的每一位酒店员工都如春风般和煦，前台小姐姐、客房部的小天和他的同事们，积极主动帮助沟通解决遇到的问题，特别暖心。
酒店门口即地铁，自有花园很棒，健身房壁球室俱全，屋顶游泳池两个大泡池很舒适，早餐有三个餐厅选择，各有特色，相当不错！周边可选餐厅很多，白云酒店白云轩，广州酒家，点都德……
非要说一下缺点的话，就是：1、自助早餐食物还可以丰富和提高品质；2、大堂小姐姐的亮闪闪迎宾服不知道是不是岭南风，总觉得有点不搭环境，好在小姐姐们服务还是贴心周到的；3、热忱的门童服务挺加分的，可是能不要安排纤弱的小姐姐吗？门比人都要重了，看着好让人心疼，酒店也要懂得怜香惜玉，哈哈
下次再来广州的首选，还会带家人来小住。', '["https://dimg04.c-ctrip.com/images/0235412000g1mij1p70FB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000g1md76t9939_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234w12000g1miyxx6801_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231812000g1mgkn8520F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000g1mc8qn89BA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000g1md8fnEC3E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000g1mdss197A1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d12000g1o8vsc84F8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-08', '花园大床房', '大床房', '其他', 373, 5.924255797414532, 0, 0.0, 18, 2.9444389791664403, 9, '["房间设施", "前台服务", "交通便利性"]'::jsonb, '房间设施', '前台服务', '交通便利性', '未知酒店', '未知地点', '匿名', '来之前比较了很多家，还是挑选了这家底蕴深厚的老牌五星，卫生、设施、管理和服务都有', '来之前比较了很多家，还是挑选了这家底蕴深厚的老牌五星，卫生、设施、管理和服务都有品质保证：
房间整洁宽敞，装修材质好品牌好，床品舒适，遇到的每一位酒店员工都如春风般和煦，前台小姐姐、客房部的小天和他的同事们，积极主动帮助沟通解决遇到的问题，特别暖心。
酒店门口即地铁，自有花园很棒，健身房壁球室俱全，屋顶游泳池两个大泡池很舒适，早餐有三个餐厅选择，各有特色，相当不错！周边可选餐厅很多，白云酒店白云轩，广州酒家，点都德……
非要说一下缺点的话，就是：1、自助早餐食物还可以丰富和提高品质；2、大堂小姐姐的亮闪闪迎宾服不知道是不是岭南风，总觉得有点不搭环境，好在小姐姐们服务还是贴心周到的；3、热忱的门童服务挺加分的，可是能不要安排纤弱的小姐姐吗？门比人都要重了，看着好让人心疼，酒店也要懂得怜香惜玉，哈哈
下次再来广州的首选，还会带家人来小住。', '2024-10-08', 5, '房间设施');
