INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a0ae3c98b094176584d', '酒店就是一座博物馆，这诺大的博物馆典藏的旧物，一桩一件都值得驻足细品，第二次来才把这家开业快40年的白金酒店的内涵充分发掘，是历史的见证，是时光的沉淀，更是中国文化的伟大传承?????? 
服务来说，整个酒店的服务人员整体还是非常有礼貌和服务态度的，感谢客房部Tia赠送的中秋月饼。
重点说说在酒店的三天都在30层行政酒廊的360°旋转餐厅用餐，被Carrie 的服务一整个感动到，为了中秋节三天我们有最好的体验主动提供了很多升级和附加服务，还有另外几位Echo、Kelly 等小姐姐和早餐的小哥哥都态度亲切，服务殷勤，让整个节日的体验充满温情
所以，
爱才是人生的行囊，
