INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a0ae3c98b094176584e', '广州花园酒店地位位置不错，处于越秀区，然后酒店文化底蕴深厚，四楼居然还有博物馆，这让我十成分惊讶，然后就是我很喜欢这里的行政酒廊，不知道为什么它要搬下来这里的一楼，我觉得这里远不如30 楼的环境，但是这也怪不得这些服务的小姐姐，而且beryle，echo，她们还是很热情的特别是beryle她热情介绍这里，并且有什么吃喝等，很热情的服务，很喜欢她们，但是还是喜欢三十楼，在楼上的安静环境舒适，而且这次再次来是寻找以前来过的餐厅', '["https://dimg04.c-ctrip.com/images/0234g12000frjjx5t2B32_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0233r12000frjjbjeB3B6_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0236w12000frjiyeiE796_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2024-09-26', '花园双床房', '双床房', '其他', 213, 5.365976015021851, 0, 0.0, 1, 0.6931471805599453, 8, '["公共设施", "前台服务", "安静程度"]'::jsonb, '公共设施', '前台服务', '安静程度', '未知酒店', '未知地点', '匿名', '广州花园酒店地位位置不错，处于越秀区，然后酒店文化底蕴深厚，四楼居然还有博物馆，', '广州花园酒店地位位置不错，处于越秀区，然后酒店文化底蕴深厚，四楼居然还有博物馆，这让我十成分惊讶，然后就是我很喜欢这里的行政酒廊，不知道为什么它要搬下来这里的一楼，我觉得这里远不如30 楼的环境，但是这也怪不得这些服务的小姐姐，而且beryle，echo，她们还是很热情的特别是beryle她热情介绍这里，并且有什么吃喝等，很热情的服务，很喜欢她们，但是还是喜欢三十楼，在楼上的安静环境舒适，而且这次再次来是寻找以前来过的餐厅', '2024-09-26', 5, '公共设施');
