INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a15e3c98b0941765853', '广州花园酒店入住体验令人满意，房间布置温馨，空间宽敞，床铺舒适，地理位置优越，交通便利，周边配套设施完善。工作人员热情好客，服务周到，让人有宾至如归的感觉。', '["https://dimg04.c-ctrip.com/images/0233m12000gf9imix1611_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232212000gf9cqyj0EC6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233612000gfadrj1F969_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-01', '花园双床房', '双床房', '情侣出游', 78, 4.3694478524670215, 0, 0.0, 3, 1.3862943611198906, 8, '["整体满意度", "房间设施", "交通便利性"]'::jsonb, '整体满意度', '房间设施', '交通便利性', '未知酒店', '未知地点', '匿名', '广州花园酒店入住体验令人满意，房间布置温馨，空间宽敞，床铺舒适，地理位置优越，交', '广州花园酒店入住体验令人满意，房间布置温馨，空间宽敞，床铺舒适，地理位置优越，交通便利，周边配套设施完善。工作人员热情好客，服务周到，让人有宾至如归的感觉。', '2024-11-01', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a15e3c98b0941765854', '广州花园酒店的入住体验堪称完美，从踏入酒店的那一刻起就感受到了无微不至的尊贵服务！行政酒廊的Jennifer、Cathy和Louis三位工作人员尤为令人印象深刻。客务中心的小琳更是全程暖心护航，无论是行程建议还是突发需求，她总能迅速响应并完美解决。酒店设施高端典雅，窗外城市景观令人沉醉，行政酒廊的精致餐点与静谧氛围更是加分项。这次入住不仅享受了奢华的硬件，更被充满人情味的服务深深打动，绝对是我在广州的首选下榻之地！', '["https://dimg04.c-ctrip.com/images/0233112000jfb07m63599_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233u12000jfb1vk59EA7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233812000jf9qftiB755_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-30', '红棉大床套房', '套房', '情侣出游', 209, 5.3471075307174685, 0, 0.0, 48, 3.8918202981106265, 9, '["前台服务", "整体满意度", "景观/朝向"]'::jsonb, '前台服务', '整体满意度', '景观/朝向', '未知酒店', '未知地点', '匿名', '广州花园酒店的入住体验堪称完美，从踏入酒店的那一刻起就感受到了无微不至的尊贵服务', '广州花园酒店的入住体验堪称完美，从踏入酒店的那一刻起就感受到了无微不至的尊贵服务！行政酒廊的Jennifer、Cathy和Louis三位工作人员尤为令人印象深刻。客务中心的小琳更是全程暖心护航，无论是行程建议还是突发需求，她总能迅速响应并完美解决。酒店设施高端典雅，窗外城市景观令人沉醉，行政酒廊的精致餐点与静谧氛围更是加分项。这次入住不仅享受了奢华的硬件，更被充满人情味的服务深深打动，绝对是我在广州的首选下榻之地！', '2025-03-30', 5, '前台服务');
