INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a15e3c98b0941765858', '尊享行政礼遇（含下午茶及欢乐时光-用餐地点锦鲤酒吧行政酒廊）:多谢当日服务员echo,Carrie,Kitty 的亲切服务，服务很周到，而且时不时的会问我们有没有需要帮助的??食物出品很好，配得上五星级的头衔！', '["https://dimg04.c-ctrip.com/images/0236f12000frw3qsw8019_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000frvht0sFDD3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235512000frw6d5v67C0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000frwaxdd1E17_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000frw452k6B86_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231412000frw243056E1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000frwedpmF278_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231m12000frvvyo03340_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000frw5gggF176_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-26', '花园双床房', '双床房', '家庭亲子', 105, 4.663439094112067, 0, 0.0, 5, 1.791759469228055, 8, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '尊享行政礼遇（含下午茶及欢乐时光-用餐地点锦鲤酒吧行政酒廊）:多谢当日服务员ec', '尊享行政礼遇（含下午茶及欢乐时光-用餐地点锦鲤酒吧行政酒廊）:多谢当日服务员echo,Carrie,Kitty 的亲切服务，服务很周到，而且时不时的会问我们有没有需要帮助的??食物出品很好，配得上五星级的头衔！', '2024-09-26', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a15e3c98b0941765859', '携程的三天两晚套票，中秋假期的尾巴过来广州老派酒店放空身心，一天好好待在酒店享乐就好，除了包早餐，还包含了下午茶，欢乐时光在30楼的行政礼遇，行政酒廊的Carrie、Echo、Kitty服务周到，让这次行程倍感亲切！', '["https://dimg04.c-ctrip.com/images/0230912000fn3bbpa8C50_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0235q12000fn3a82a58E8_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0232q12000fn378y1B695_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0232l12000fn3auy2013F_R_150_150_R5_Q70_D.png"]'::jsonb, 3.5, 3, '2024-09-19', '花园双床房', '双床房', '家庭亲子', 108, 4.691347882229144, 0, 0.0, 2, 1.0986122886681098, 8, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '携程的三天两晚套票，中秋假期的尾巴过来广州老派酒店放空身心，一天好好待在酒店享乐', '携程的三天两晚套票，中秋假期的尾巴过来广州老派酒店放空身心，一天好好待在酒店享乐就好，除了包早餐，还包含了下午茶，欢乐时光在30楼的行政礼遇，行政酒廊的Carrie、Echo、Kitty服务周到，让这次行程倍感亲切！', '2024-09-19', 3, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a1fe3c98b094176585a', '春节期间和家人去广州旅游，入住广州越秀区花园酒店。这是一家老牌5星酒店，可以看到当年的金碧辉煌，大堂背景墙是金色的，登记的前台还得排长队。可以看得出大家对花园酒店的认可。早餐丰富，服务热情周到。后花园太漂亮了。特别提出表扬的是前台mancy（黄女士），看到我们带了孩子，主动为我们升级了房间，非常感谢！给酒店全5星好评，下次来广州一定再住花园酒店。', '["https://dimg04.c-ctrip.com/images/0234612000iaqkfawC09B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000iaqz0854BAA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234d12000iaqy0f283AF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-04', '红棉大床套房', '套房', '家庭亲子', 174, 5.1647859739235145, 0, 0.0, 4, 1.6094379124341005, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '春节期间和家人去广州旅游，入住广州越秀区花园酒店。这是一家老牌5星酒店，可以看到', '春节期间和家人去广州旅游，入住广州越秀区花园酒店。这是一家老牌5星酒店，可以看到当年的金碧辉煌，大堂背景墙是金色的，登记的前台还得排长队。可以看得出大家对花园酒店的认可。早餐丰富，服务热情周到。后花园太漂亮了。特别提出表扬的是前台mancy（黄女士），看到我们带了孩子，主动为我们升级了房间，非常感谢！给酒店全5星好评，下次来广州一定再住花园酒店。', '2025-02-04', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a1fe3c98b094176585b', '非常棒的酒店，从一进酒店就感觉到非常温馨热情，办理入住的前台服务员Yolo耐心细心，还有负责酒店讲解的小李，讲解的很细致。特别感谢酒店给做的房间布置并升级房型，使我们度过了一个快乐假期。谢谢。', '["https://dimg04.c-ctrip.com/images/0230212000fq4c4cg0256_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231l12000fq4hkc04391_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235u12000fq47rfc2BC3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a12000fq49cdg7978_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231g12000fq4gxurFA66_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236d12000fq4xutxBDFF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000fq4j8luBB84_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000fq4t2nhE04F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000fq4sujt7B37_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-24', '花园双床房', '双床房', '家庭亲子', 96, 4.574710978503383, 0, 0.0, 114, 4.74493212836325, 8, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '非常棒的酒店，从一进酒店就感觉到非常温馨热情，办理入住的前台服务员Yolo耐心细', '非常棒的酒店，从一进酒店就感觉到非常温馨热情，办理入住的前台服务员Yolo耐心细心，还有负责酒店讲解的小李，讲解的很细致。特别感谢酒店给做的房间布置并升级房型，使我们度过了一个快乐假期。谢谢。', '2024-09-24', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a1fe3c98b094176585c', '酒店地理位置很好，设施豪华而大气；服务很贴心，过生日还送蛋糕??，不愧是老牌五星酒店。下次来还会入住。', '["https://dimg04.c-ctrip.com/images/0235r12000h0xpim0799E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000h0yjz0n8C4F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000h0xq4bu00D3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000h0yyt9i166C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230x12000h0z2a81EE84_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000h0yppp16D6C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-12-04', '红棉双床套房', '套房', '家庭亲子', 51, 3.951243718581428, 0, 0.0, 4, 1.6094379124341005, 7, '["整体满意度", "交通便利性", "前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务', '未知酒店', '未知地点', '匿名', '酒店地理位置很好，设施豪华而大气；服务很贴心，过生日还送蛋糕??，不愧是老牌五星', '酒店地理位置很好，设施豪华而大气；服务很贴心，过生日还送蛋糕??，不愧是老牌五星酒店。下次来还会入住。', '2024-12-04', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a1fe3c98b094176585d', '总体满意，很有底蕴的五星白金酒店，客房服务非常好，餐饮味道不错，唯一提点小意见，就是行政酒廊环境小，酒水可选择少，餐食精致）（这点很喜欢），当我提出能否提供一碗白米饭，服务员的回答是，我们这里的欢乐时光就是这样，没有白米饭提供，我觉得这样的回答不应该是五星酒店的回答，本人因为特别喜欢行政酒廊，去过很多五星酒店的行政酒廊，所以这种回答让我觉得挺惊讶的，这是这次住店的真实感受，有时间我还是会再去入住的', '["https://dimg04.c-ctrip.com/images/0232v12000fmwdxwwD3DE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000fmwbj4c7DC7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231812000fmwdgb03CF2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234z12000fmwq3lbE26D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-09-19', '花园双床房', '双床房', '其他', 200, 5.303304908059076, 1, 0.6931471805599453, 11, 2.4849066497880004, 8, '["餐饮设施", "客房服务", "整体满意度"]'::jsonb, '餐饮设施', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '总体满意，很有底蕴的五星白金酒店，客房服务非常好，餐饮味道不错，唯一提点小意见，', '总体满意，很有底蕴的五星白金酒店，客房服务非常好，餐饮味道不错，唯一提点小意见，就是行政酒廊环境小，酒水可选择少，餐食精致）（这点很喜欢），当我提出能否提供一碗白米饭，服务员的回答是，我们这里的欢乐时光就是这样，没有白米饭提供，我觉得这样的回答不应该是五星酒店的回答，本人因为特别喜欢行政酒廊，去过很多五星酒店的行政酒廊，所以这种回答让我觉得挺惊讶的，这是这次住店的真实感受，有时间我还是会再去入住的', '2024-09-19', 4, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a1fe3c98b094176585e', '酒店环境优雅，近市中心交通十分便捷。－流的服务水平，有宾至如归的感觉。早餐十分丰盛味道好极了。如有机会，下次再入住。', '["https://dimg04.c-ctrip.com/images/0233z12000gryol737A20_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000gry5gt4B73A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236w12000grycju82E20_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-11-20', '花园双床房', '双床房', '家庭亲子', 58, 4.07753744390572, 0, 0.0, 3, 1.3862943611198906, 6, '["整体满意度", "交通便利性", "餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店环境优雅，近市中心交通十分便捷。－流的服务水平，有宾至如归的感觉。早餐十分丰', '酒店环境优雅，近市中心交通十分便捷。－流的服务水平，有宾至如归的感觉。早餐十分丰盛味道好极了。如有机会，下次再入住。', '2024-11-20', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a1fe3c98b094176585f', '订的基础房型，前台小哥给我升级了套房，非常惊喜，物超所值。酒店离淘金火车站也非常近，出行方便。酒店四楼还有个博物馆，介绍广州酒店发展历史，值得一看。推荐大家来广州住花园酒店。', '["https://dimg04.c-ctrip.com/images/0237112000fzoghsqC67C_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0233k12000fzog8c23130_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0230u12000fzoekeu45B8_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0234312000fzofufb2208_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0234q12000fzoevep9247_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0235b12000fzoe4ek96DC_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231h12000fzof4yiE716_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2024-10-05', '花园大床房', '大床房', '情侣出游', 87, 4.477336814478207, 0, 0.0, 4, 1.6094379124341005, 8, '["整体满意度", "前台服务", "交通便利性"]'::jsonb, '整体满意度', '前台服务', '交通便利性', '未知酒店', '未知地点', '匿名', '订的基础房型，前台小哥给我升级了套房，非常惊喜，物超所值。酒店离淘金火车站也非常', '订的基础房型，前台小哥给我升级了套房，非常惊喜，物超所值。酒店离淘金火车站也非常近，出行方便。酒店四楼还有个博物馆，介绍广州酒店发展历史，值得一看。推荐大家来广州住花园酒店。', '2024-10-05', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a1fe3c98b0941765860', '在携程囤的行政礼遇三天两晚套餐，趁着中秋假期来广州老牌五星酒店放松一下。套餐包含酒店30楼行政酒廊早餐、下午茶和Happy hour，懒得出门的话可以一天三餐都在酒店解决了。早餐还会开放旋转餐厅区域。酒店还送了跟广东省博物馆联名的月饼。行政酒廊的Carrie、Echo服务热情周到，让这次行程倍感亲切！', '["https://dimg04.c-ctrip.com/images/0233j12000fntxnkjD9A9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235r12000fnub0ct53AF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232k12000fntvnoq66BC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000fntwzzc4653_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231912000fnu6mzzE84C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x12000fntpqmwB833_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236y12000fnuc2wz718B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231b12000fnua80i077D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234u12000fntmr789B18_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-20', '花园双床房', '双床房', '家庭亲子', 151, 5.0238805208462765, 0, 0.0, 5, 1.791759469228055, 9, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '在携程囤的行政礼遇三天两晚套餐，趁着中秋假期来广州老牌五星酒店放松一下。套餐包含', '在携程囤的行政礼遇三天两晚套餐，趁着中秋假期来广州老牌五星酒店放松一下。套餐包含酒店30楼行政酒廊早餐、下午茶和Happy hour，懒得出门的话可以一天三餐都在酒店解决了。早餐还会开放旋转餐厅区域。酒店还送了跟广东省博物馆联名的月饼。行政酒廊的Carrie、Echo服务热情周到，让这次行程倍感亲切！', '2024-09-20', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a1fe3c98b0941765861', '30年前爸爸妈妈蜜月时候来过的酒店
这次打卡很有纪念意义啦
非常感谢酒店准备的浪漫惊喜
鲜花水果小蛋糕我家年宝高兴坏了
妈妈说这是她住过最开心的酒店啦
红棉房是次顶配的行政套房超级超级大
服务人员都非常热情周到
特别表扬凌璇阁的一个三哥服务员
对孩子热情他中文超6的
自助早餐出现了NFC果汁还有益力多用料扎实
下午泳池游泳也有人及时送来夏日畅饮
孩子们还可以在后花园喂锦鲤
红棉房送的代金券我们在荔湾亭餐厅消费啦
再次表扬经理送了我们做月饼体验还有糖水！
