INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a1fe3c98b0941765862', '已经连续第二年的九月入住花园。今年恰逢中秋。整个中秋假期都在花园非常愉快地度过。真的好喜欢花园酒店的氛围和瀑布小花园及花园博物馆。酒店暖心送来包装精美的月饼礼盒直接把??节氛围拉满。感谢花园，祝花园酒店越来越好。', '["https://dimg04.c-ctrip.com/images/0233m12000flxmtidDADC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000flxmaez39FD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234u12000flxgtvu0235_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-09-17', '花园双床房', '双床房', '家庭亲子', 106, 4.672828834461906, 1, 0.6931471805599453, 4, 1.6094379124341005, 7, '["整体满意度", "公共设施"]'::jsonb, '整体满意度', '公共设施', NULL, '未知酒店', '未知地点', '匿名', '已经连续第二年的九月入住花园。今年恰逢中秋。整个中秋假期都在花园非常愉快地度过。', '已经连续第二年的九月入住花园。今年恰逢中秋。整个中秋假期都在花园非常愉快地度过。真的好喜欢花园酒店的氛围和瀑布小花园及花园博物馆。酒店暖心送来包装精美的月饼礼盒直接把??节氛围拉满。感谢花园，祝花园酒店越来越好。', '2024-09-17', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a1fe3c98b0941765863', '其实挺一般的，大概是个别评论拔高了期待。
服务是会有点区别对待，荔湾亭中餐厅服务倒是不错。红棉双床房带客厅，但是房间太小，床特别窄，枕套也没洗干净，虽然我有带一次性床品，但小床睡得不舒服。
迷你吧品类齐全；送得鸡尾酒体验，恰逢过敏戒酒，只去酒吧转了圈，环境还行。
中餐厅出品真的不怎么好吃，烧腊和茶点还行，炒菜一言难尽，时蔬里放的菇子是馊的，越吃越不对劲，第二天就拉肚子了…
早餐品类也少，本地特色好像只看到马蹄糕，唯一能夸的只有瀑布。
大堂装修倒是豪华，金碧辉煌的面子工程；博物馆去得时候正好闭馆时间，没有参观到。
下次自己住还是老老实实去万豪索菲特希尔顿之类的吧，至少客房，服务，食品安全能有一样能得到保证？', '["https://dimg04.c-ctrip.com/images/0233x12000fnfbrp722F9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000fnfc78oD549_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231112000fnfhiac4EDF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p12000fnfhj5k4D5A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.8, 3, '2024-09-20', '红棉双床套房', '套房', '家庭亲子', 306, 5.726847747587197, 0, 0.0, 9, 2.302585092994046, 9, '["餐饮设施", "房间设施", "卫生状况"]'::jsonb, '餐饮设施', '房间设施', '卫生状况', '未知酒店', '未知地点', '匿名', '其实挺一般的，大概是个别评论拔高了期待。', '其实挺一般的，大概是个别评论拔高了期待。
服务是会有点区别对待，荔湾亭中餐厅服务倒是不错。红棉双床房带客厅，但是房间太小，床特别窄，枕套也没洗干净，虽然我有带一次性床品，但小床睡得不舒服。
迷你吧品类齐全；送得鸡尾酒体验，恰逢过敏戒酒，只去酒吧转了圈，环境还行。
中餐厅出品真的不怎么好吃，烧腊和茶点还行，炒菜一言难尽，时蔬里放的菇子是馊的，越吃越不对劲，第二天就拉肚子了…
早餐品类也少，本地特色好像只看到马蹄糕，唯一能夸的只有瀑布。
大堂装修倒是豪华，金碧辉煌的面子工程；博物馆去得时候正好闭馆时间，没有参观到。
下次自己住还是老老实实去万豪索菲特希尔顿之类的吧，至少客房，服务，食品安全能有一样能得到保证？', '2024-09-20', 3, '餐饮设施');
