INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a36e3c98b094176586e', '房间整体布局非常人性化好用??全面提供不同的空间场景（寝室/客厅/办公/衣帽化妆间等等）环境干净，还提供不同风味的软包装饮品舒适如家??唯一对我个人来窗户不能打开安全　角度让窒内引入外界新鲜空气产生交换（纯粹我个人喜欢）在此我要称赞客服中心电话咨询服务的小华服务到位全方面介绍酒店各个餐厅的特色并特别推荐30楼的行政酒廊高雅格调非常适合小众商务活动??特别我在行政酒廊遇到的两位职员Cathy和Berdly业务知识够丰富，尤其Cathy对酒店各处环境如数家珍向我推荐必游的酒店博物馆??????和花园酒店的领南特色瀑布花园??????酒店泳池整体感觉不错希望提供一次性泳帽以满足酒店国际宾客入住??', '["https://dimg04.c-ctrip.com/images/0206212000fjg94gg2F30_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0203p12000fjg8u1c60BB_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0232x12000fjfiipf0718_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000fjg12d146FD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000fjg1syvCA6C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000fjfpg8l232A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230w12000fjfnhr61E36_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000fjfgympC90E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000fjg14ut205F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000fjfngbx8EAA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-13', '花园大床房', '大床房', '独自旅行', 299, 5.703782474656201, 0, 0.0, 3, 1.3862943611198906, 9, '["房间设施", "前台服务", "公共设施"]'::jsonb, '房间设施', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '房间整体布局非常人性化好用??全面提供不同的空间场景（寝室/客厅/办公/衣帽化妆', '房间整体布局非常人性化好用??全面提供不同的空间场景（寝室/客厅/办公/衣帽化妆间等等）环境干净，还提供不同风味的软包装饮品舒适如家??唯一对我个人来窗户不能打开安全　角度让窒内引入外界新鲜空气产生交换（纯粹我个人喜欢）在此我要称赞客服中心电话咨询服务的小华服务到位全方面介绍酒店各个餐厅的特色并特别推荐30楼的行政酒廊高雅格调非常适合小众商务活动??特别我在行政酒廊遇到的两位职员Cathy和Berdly业务知识够丰富，尤其Cathy对酒店各处环境如数家珍向我推荐必游的酒店博物馆??????和花园酒店的领南特色瀑布花园??????酒店泳池整体感觉不错希望提供一次性泳帽以满足酒店国际宾客入住??', '2024-09-13', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a36e3c98b094176586f', '广交会起期间 每次都住花园酒店 服务很好 就是人太多早餐需要排队 这次给升级了套房 特别宽敞 还配有踏步机 虽然没使用 但感觉不错', '["https://dimg04.c-ctrip.com/images/0230d12000gh0777h87CC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000gh07lceA893_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236g12000gh07jx28AA4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-03', '城央绿意大床房', '大床房', '商务出差', 65, 4.189654742026425, 0, 0.0, 54, 4.007333185232471, 8, '["整体满意度", "房间设施", "餐饮设施"]'::jsonb, '整体满意度', '房间设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '广交会起期间 每次都住花园酒店 服务很好 就是人太多早餐需要排队 这次给升级了套', '广交会起期间 每次都住花园酒店 服务很好 就是人太多早餐需要排队 这次给升级了套房 特别宽敞 还配有踏步机 虽然没使用 但感觉不错', '2024-11-03', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a36e3c98b0941765870', '很棒的一次体验！
1、刚步入酒店，就被酒店的大堂设计惊艳到了，非常漂亮有特色。大堂里的服务人员很多，每个人都能热情的迎接。某些时段还有表演，小朋友很喜欢。
2、原本订的是大床房，办理入住的时候前台客服很惊喜的给升级了套房。房间里还送了欢迎水果，很丰富。
3、泳池和健身房设施齐全，工作人员也很尽心尽责。泳池边上还有两个按摩浴缸，是小朋友们的玩水乐园。
4、酒店4楼有个博物馆，国庆期间还有打卡活动，小朋友很喜欢，打卡完成还领取了小礼品。
5、酒店的后花园名不虚传，有小桥、瀑布和成群的锦鲤，景色很不错，是拍照的好地方。
6、打卡了荔湾亭，出品稳定，糯米鸡、菠萝包很好吃。
最后提一句，大堂左侧有个面包店，卖的面包很好吃！特别推荐苹果丹麦、菠萝丹麦！', '["https://dimg04.c-ctrip.com/images/0236h12000g19k64kB17B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236g12000g19ds3gA12B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000g19jk6h59BE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000g19lu0r0130_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000g19fk9sC555_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230w12000g19sg9t4FAE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000g19elldF6F6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000g19j1x48FAA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236d12000g19fhztC02C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-10-08', '花园大床房', '大床房', '家庭亲子', 324, 5.783825182329737, 0, 0.0, 20, 3.044522437723423, 9, '["公共设施", "前台服务", "餐饮设施"]'::jsonb, '公共设施', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '很棒的一次体验！', '很棒的一次体验！
1、刚步入酒店，就被酒店的大堂设计惊艳到了，非常漂亮有特色。大堂里的服务人员很多，每个人都能热情的迎接。某些时段还有表演，小朋友很喜欢。
2、原本订的是大床房，办理入住的时候前台客服很惊喜的给升级了套房。房间里还送了欢迎水果，很丰富。
3、泳池和健身房设施齐全，工作人员也很尽心尽责。泳池边上还有两个按摩浴缸，是小朋友们的玩水乐园。
4、酒店4楼有个博物馆，国庆期间还有打卡活动，小朋友很喜欢，打卡完成还领取了小礼品。
5、酒店的后花园名不虚传，有小桥、瀑布和成群的锦鲤，景色很不错，是拍照的好地方。
6、打卡了荔湾亭，出品稳定，糯米鸡、菠萝包很好吃。
最后提一句，大堂左侧有个面包店，卖的面包很好吃！特别推荐苹果丹麦、菠萝丹麦！', '2024-10-08', 4, '公共设施');
