INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a36e3c98b0941765872', '花园酒店每次出差都来 挺好的 不错不错不错错不错不错错不错不错错不错不错错不错不错错不错不错错不错不错好', '["https://dimg04.c-ctrip.com/images/0233i12000hvzzexnA013_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230i12000hw054vt8E13_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000hw0s4h3E525_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-18', '城央绿意大床房', '大床房', '商务出差', 52, 3.970291913552122, 0, 0.0, 23, 3.1780538303479458, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '花园酒店每次出差都来 挺好的 不错不错不错错不错不错错不错不错错不错不错错不错不', '花园酒店每次出差都来 挺好的 不错不错不错错不错不错错不错不错错不错不错错不错不错错不错不错错不错不错好', '2025-01-18', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a36e3c98b0941765873', '大厅还挺震撼的，金碧辉煌，有很多外国人入住。泳池露天在四楼，水凉。性价比还是挺高的。有一个酒店博物馆，值得一看。瀑布在花园里，有一个挺大的花园。是一个有特色的酒店。', '["https://dimg04.c-ctrip.com/images/0231212000g0ibeht0AE3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235c12000g0ia39x6953_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000g0i7abh4875_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000g0iakmj48FF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232o12000g0igz3mA827_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000g0ih9so208D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000g0iaajzC7CB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000g0i904j138A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236x12000g0if8lb6D10_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-10-06', '花园双床房', '双床房', '家庭亲子', 82, 4.418840607796598, 0, 0.0, 6, 1.9459101490553128, 7, '["公共设施", "性价比", "整体满意度"]'::jsonb, '公共设施', '性价比', '整体满意度', '未知酒店', '未知地点', '匿名', '大厅还挺震撼的，金碧辉煌，有很多外国人入住。泳池露天在四楼，水凉。性价比还是挺高', '大厅还挺震撼的，金碧辉煌，有很多外国人入住。泳池露天在四楼，水凉。性价比还是挺高的。有一个酒店博物馆，值得一看。瀑布在花园里，有一个挺大的花园。是一个有特色的酒店。', '2024-10-06', 4, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a36e3c98b0941765874', '床舒适，早餐一般。老字号', '["https://dimg04.c-ctrip.com/images/0231u12000iks495wDBC2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235l12000iksczo65595_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.6, 3, '2025-02-17', '花园大床房', '大床房', '家庭亲子', 12, 2.5649493574615367, 0, 0.0, 4, 1.6094379124341005, 4, '["房间设施", "餐饮设施", "整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '床舒适，早餐一般。老字号', '床舒适，早餐一般。老字号', '2025-02-17', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a36e3c98b0941765875', '前台帮忙升级的粤韵套房，楼层设的迎送岗，酒店的博物馆、瀑布餐厅的早餐、荔湾亭的夜茶氛围，一切都很美好。', '["https://dimg04.c-ctrip.com/images/0230g12000guix9c917DC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000gujpc0i829D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i12000gujprqlD221_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-24', '花园双床房', '双床房', '情侣出游', 51, 3.951243718581428, 0, 0.0, 4, 1.6094379124341005, 8, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '前台帮忙升级的粤韵套房，楼层设的迎送岗，酒店的博物馆、瀑布餐厅的早餐、荔湾亭的夜', '前台帮忙升级的粤韵套房，楼层设的迎送岗，酒店的博物馆、瀑布餐厅的早餐、荔湾亭的夜茶氛围，一切都很美好。', '2024-11-24', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a36e3c98b0941765876', '酒店环境一级棒，门前有澳门的感觉，一进大堂也很高大尚，有博物馆、游泳池，一楼瀑布餐厅环境很棒！但早餐没啥好吃的有点一般。唯一吐槽的就是房间太陈旧了，很破。其它都很好。', '["https://dimg04.c-ctrip.com/images/0234r12000g0wdsfk4CD1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236412000g0w6kfc4462_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233712000g0whnvx2F7F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230712000g0wgjyeBC26_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230l12000g0wgjk406AB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-10-07', '花园双床房', '双床房', '家庭亲子', 83, 4.430816798843313, 0, 0.0, 7, 2.079441541679836, 7, '["房间设施", "公共设施", "餐饮设施"]'::jsonb, '房间设施', '公共设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店环境一级棒，门前有澳门的感觉，一进大堂也很高大尚，有博物馆、游泳池，一楼瀑布', '酒店环境一级棒，门前有澳门的感觉，一进大堂也很高大尚，有博物馆、游泳池，一楼瀑布餐厅环境很棒！但早餐没啥好吃的有点一般。唯一吐槽的就是房间太陈旧了，很破。其它都很好。', '2024-10-07', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a36e3c98b0941765877', '原本只是想趁休息日舒缓一下身心，却没想到“花园”能带给我如此多的惊喜?????? 首先，check in时被告知我被升级至套房了。入住后，主管卫生的许经理更是给予了无微不至的关怀与照顾???? 使得一个人的旅行也倍感温暖???? “花园”的好，好在细节，好在服务，这是新派酒店无法做到的。每一样摆设都彰显心思，每一处地方都恰到好处，值得你去慢慢品味。房间很安静，酒店氛围也很轻松，它的管理也很人性化，根据房间情况给予延迟退房，简直颠覆了我对此概念的认知??。所以，不到“花园”，你是不会知道它有多好的，在此再次谢谢许经理，谢谢携程??????', '["https://dimg04.c-ctrip.com/images/0231312000g0khvdo5B5F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000g0klwi0F0AA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235812000g0kornc8053_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230m12000g0k4gwo3AA9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000g0k0u27FAE4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-10-06', '城央绿意大床房', '大床房', '独自旅行', 271, 5.605802066295998, 0, 0.0, 6, 1.9459101490553128, 9, '["前台服务", "整体满意度", "安静程度"]'::jsonb, '前台服务', '整体满意度', '安静程度', '未知酒店', '未知地点', '匿名', '原本只是想趁休息日舒缓一下身心，却没想到“花园”能带给我如此多的惊喜??????', '原本只是想趁休息日舒缓一下身心，却没想到“花园”能带给我如此多的惊喜?????? 首先，check in时被告知我被升级至套房了。入住后，主管卫生的许经理更是给予了无微不至的关怀与照顾???? 使得一个人的旅行也倍感温暖???? “花园”的好，好在细节，好在服务，这是新派酒店无法做到的。每一样摆设都彰显心思，每一处地方都恰到好处，值得你去慢慢品味。房间很安静，酒店氛围也很轻松，它的管理也很人性化，根据房间情况给予延迟退房，简直颠覆了我对此概念的认知??。所以，不到“花园”，你是不会知道它有多好的，在此再次谢谢许经理，谢谢携程??????', '2024-10-06', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a40e3c98b0941765878', '一次定了三间房四晚，刚刚评价过了', '["https://dimg04.c-ctrip.com/images/0234r12000ibykn2iD84C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-05', '花园大床房', '大床房', '家庭亲子', 16, 2.833213344056216, 0, 0.0, 13, 2.6390573296152584, 2, '[]'::jsonb, NULL, NULL, NULL, '未知酒店', '未知地点', '匿名', '一次定了三间房四晚，刚刚评价过了', '一次定了三间房四晚，刚刚评价过了', '2025-02-05', 5, '家庭亲子');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a40e3c98b0941765879', '朋友推介的历史悠久的酒店，酒店很特别很有特色，酒店大堂有本地和外籍的工作人员，每位服务态度都很好很耐心解答。吃自助晚餐的餐厅也考虑得比较周到，不管是外地的还是外籍的游客都有很多各地方的菜式，海鲜很新鲜很清甜，五成牛排稍微有点生吃得不是很习惯，其他菜式都很有特色，菜品看起来很有食欲。餐厅的不管是厨师还是外籍服务员服务态度都非常好，很热心很耐心，一开始提前了一天也没有预约到座位，但是告知可以先办理入住等到有座位入席吃饭再打电话通知我过来，不用本人在现场排队，这点做得很不错，对于我这种带小朋友的游客来说是很不错的用餐体验。
房间的卫生也做得很好，浴缸也比其他酒店做得更方正一些，很适合带小孩住，洗浴都比较方便。特意带小朋友逛了花园酒店的几十年历史的博物馆，很有意义的一次住宿体验！4楼的泳池也很不错，大夏天在泳池游泳玩玩水枪也是个很棒的选择。
有一点不怎么好的就是，从酒店大堂去地下停车场没有指示牌，要询问工作人员才知道怎么走。酒店内的温度太低了，一进门就感觉到很冷要穿多件小外套，和室外温度相差太多了，可以在原有的温度内稍微调高一些吗？', '["https://dimg04.c-ctrip.com/images/0236m12000fcdg83qDD95_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000fcdup5u6A2E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000fcdoyjl3128_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000fce78bwF6E2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000fcdf42aB896_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234512000fce9f9f2476_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000fcdro6i0B64_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235412000fcdrker109C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234g12000fcddphe43B5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-09-01', '花园双床房', '双床房', '家庭亲子', 469, 6.152732694704104, 0, 0.0, 8, 2.19722457733622, 9, '["餐饮设施", "客房服务", "公共设施"]'::jsonb, '餐饮设施', '客房服务', '公共设施', '未知酒店', '未知地点', '匿名', '朋友推介的历史悠久的酒店，酒店很特别很有特色，酒店大堂有本地和外籍的工作人员，每', '朋友推介的历史悠久的酒店，酒店很特别很有特色，酒店大堂有本地和外籍的工作人员，每位服务态度都很好很耐心解答。吃自助晚餐的餐厅也考虑得比较周到，不管是外地的还是外籍的游客都有很多各地方的菜式，海鲜很新鲜很清甜，五成牛排稍微有点生吃得不是很习惯，其他菜式都很有特色，菜品看起来很有食欲。餐厅的不管是厨师还是外籍服务员服务态度都非常好，很热心很耐心，一开始提前了一天也没有预约到座位，但是告知可以先办理入住等到有座位入席吃饭再打电话通知我过来，不用本人在现场排队，这点做得很不错，对于我这种带小朋友的游客来说是很不错的用餐体验。
房间的卫生也做得很好，浴缸也比其他酒店做得更方正一些，很适合带小孩住，洗浴都比较方便。特意带小朋友逛了花园酒店的几十年历史的博物馆，很有意义的一次住宿体验！4楼的泳池也很不错，大夏天在泳池游泳玩玩水枪也是个很棒的选择。
有一点不怎么好的就是，从酒店大堂去地下停车场没有指示牌，要询问工作人员才知道怎么走。酒店内的温度太低了，一进门就感觉到很冷要穿多件小外套，和室外温度相差太多了，可以在原有的温度内稍微调高一些吗？', '2024-09-01', 4, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a40e3c98b094176587a', '花园酒店不愧为城市的名片，与普通五星级级酒店更多了一份城市的印记与温度。就连洗手间的一堵墙都有木棉花的画，处处都有设计。后花园更是别有洞天。', '["https://dimg04.c-ctrip.com/images/0234p12000g8ej8lz3BE2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000g8ed4hf8347_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236g12000g8eilm25E68_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236a12000g8ednqe85DE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2024-10-21', '红棉双床套房', '套房', '家庭亲子', 70, 4.262679877041316, 0, 0.0, 8, 2.19722457733622, 8, '["整体满意度", "房间设施", "公共设施"]'::jsonb, '整体满意度', '房间设施', '公共设施', '未知酒店', '未知地点', '匿名', '花园酒店不愧为城市的名片，与普通五星级级酒店更多了一份城市的印记与温度。就连洗手', '花园酒店不愧为城市的名片，与普通五星级级酒店更多了一份城市的印记与温度。就连洗手间的一堵墙都有木棉花的画，处处都有设计。后花园更是别有洞天。', '2024-10-21', 4, '整体满意度');
