INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a40e3c98b094176587c', '一次愉快的入住体验！', '["https://dimg04.c-ctrip.com/images/0230c12000igou4mm30B5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-11', '城央绿意双床房', '双床房', '家庭亲子', 10, 2.3978952727983707, 0, 0.0, 9, 2.302585092994046, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '一次愉快的入住体验！', '一次愉快的入住体验！', '2025-02-11', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a40e3c98b094176587d', '花园饭店，不亏是老牌白金五星酒店，工作人员训练有素礼貌热情，大堂非常大气，房间舒适雅致。这次我是带着家人入住，一共订了三家房间，因为一如既往有回家的感觉，家人们都非常满意，果断又续住了两天。另外酒店旁边挨着地铁，出行也很方便。到广州选择花园酒店，一定会给大家带来心灵上的愉悦，强烈推荐入住。这里顺便特别感谢前台经理吴灵伶和Justin, 办理入住时，由于自己操作有误少订了一个房间，他们及时帮我与携程联络，第一时间解决了问题。我爱花园饭店，下次来广州一定还是选择花园酒店。', '["https://dimg04.c-ctrip.com/images/0234j12000jbae4ukA18F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f12000jbadpe3B685_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000jba8qszA690_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000jba8drxD206_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236c12000jba8mko5C37_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-25', '花园双床房', '双床房', '家庭亲子', 236, 5.468060141135132, 0, 0.0, 1, 0.6931471805599453, 9, '["前台服务", "整体满意度", "交通便利性"]'::jsonb, '前台服务', '整体满意度', '交通便利性', '未知酒店', '未知地点', '匿名', '花园饭店，不亏是老牌白金五星酒店，工作人员训练有素礼貌热情，大堂非常大气，房间舒', '花园饭店，不亏是老牌白金五星酒店，工作人员训练有素礼貌热情，大堂非常大气，房间舒适雅致。这次我是带着家人入住，一共订了三家房间，因为一如既往有回家的感觉，家人们都非常满意，果断又续住了两天。另外酒店旁边挨着地铁，出行也很方便。到广州选择花园酒店，一定会给大家带来心灵上的愉悦，强烈推荐入住。这里顺便特别感谢前台经理吴灵伶和Justin, 办理入住时，由于自己操作有误少订了一个房间，他们及时帮我与携程联络，第一时间解决了问题。我爱花园饭店，下次来广州一定还是选择花园酒店。', '2025-03-25', 5, '前台服务');
