INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a40e3c98b094176587f', '服务超棒，下次还是会选花园酒店', '["https://dimg04.c-ctrip.com/images/0236l12000ikdvl0m6AEB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231u12000ikddjm6F4E9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000ikddjm8E3EC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-17', '花园大床房', '大床房', '家庭亲子', 15, 2.772588722239781, 0, 0.0, 3, 1.3862943611198906, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '服务超棒，下次还是会选花园酒店', '服务超棒，下次还是会选花园酒店', '2025-02-17', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a40e3c98b0941765880', '房间布局合理，比红棉大床房少了会客厅，两个人广州旅游足够了，位置很便利，去哪里都很方便，出门就是淘金地铁站，30楼的行政酒廊早餐和下午茶都很丰盛，味道也好，还是个城市旋转观景台，挺有意思。行政酒廊的echo服务很好，点名表扬??', '["https://dimg04.c-ctrip.com/images/0231112000fe1ucrrA4A4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236612000fe1571dDBD2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232k12000fe1lbz542EA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-04', '花园大床房', '大床房', '情侣出游', 114, 4.74493212836325, 1, 0.6931471805599453, 1, 0.6931471805599453, 8, '["交通便利性", "餐饮设施", "前台服务"]'::jsonb, '交通便利性', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '房间布局合理，比红棉大床房少了会客厅，两个人广州旅游足够了，位置很便利，去哪里都', '房间布局合理，比红棉大床房少了会客厅，两个人广州旅游足够了，位置很便利，去哪里都很方便，出门就是淘金地铁站，30楼的行政酒廊早餐和下午茶都很丰盛，味道也好，还是个城市旋转观景台，挺有意思。行政酒廊的echo服务很好，点名表扬??', '2024-09-04', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a40e3c98b0941765881', '酒店升级了房型，酒店地处市中心，闹中取静，出行方便，房间宽敞，干净整洁，很是舒适，出差一直选花园酒店，熟悉的地方很有安全感', '["https://dimg04.c-ctrip.com/images/0230k12000gejs3h5EC77_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234z12000gejfgir9AFA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235612000gejmgx94D6E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-31', '花园大床房', '大床房', '商务出差', 61, 4.127134385045092, 0, 0.0, 1, 0.6931471805599453, 7, '["整体满意度", "交通便利性", "安静程度"]'::jsonb, '整体满意度', '交通便利性', '安静程度', '未知酒店', '未知地点', '匿名', '酒店升级了房型，酒店地处市中心，闹中取静，出行方便，房间宽敞，干净整洁，很是舒适', '酒店升级了房型，酒店地处市中心，闹中取静，出行方便，房间宽敞，干净整洁，很是舒适，出差一直选花园酒店，熟悉的地方很有安全感', '2024-10-31', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a4de3c98b0941765882', '服务非常好，酒店环境也很好，尤其是自带一个花园，有曲径通幽的感觉，瀑布花园、30层的旋转餐厅环境都不错。整体装修啥的会稍微有一点老，毕竟是早批的五星酒店。', '["https://dimg04.c-ctrip.com/images/0232912000g0fj6zyB536_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000g0fzwun218A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000g0fj70026F0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000g0fv19k75E2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231512000g0fob26CB52_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234112000g0fxiga0C9D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236k12000g0fj81g2CD6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000g0fjxfz4D1E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-06', '花园大床房', '大床房', '其他', 77, 4.356708826689592, 0, 0.0, 2, 1.0986122886681098, 8, '["公共设施", "整体满意度"]'::jsonb, '公共设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '服务非常好，酒店环境也很好，尤其是自带一个花园，有曲径通幽的感觉，瀑布花园、30', '服务非常好，酒店环境也很好，尤其是自带一个花园，有曲径通幽的感觉，瀑布花园、30层的旋转餐厅环境都不错。整体装修啥的会稍微有一点老，毕竟是早批的五星酒店。', '2024-10-06', 5, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a4de3c98b0941765883', '第3次入住酒店了，离地铁口很近，酒店有专门的停车场，解决了在广州这里停车这个头疼事。地点很方便周边吃喝玩很多选择。房间虽然不大，服务，特别好，很舒适。因为有老人特意换了没有浴缸的冲凉房。', '["https://dimg04.c-ctrip.com/images/0234m12000fh2miw86E68_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234t12000fh2smsm2BD9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000fh2rxkz66B6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-09', '花园双床房', '双床房', '家庭亲子', 93, 4.543294782270004, 0, 0.0, 5, 1.791759469228055, 8, '["交通便利性", "周边配套", "房间设施"]'::jsonb, '交通便利性', '周边配套', '房间设施', '未知酒店', '未知地点', '匿名', '第3次入住酒店了，离地铁口很近，酒店有专门的停车场，解决了在广州这里停车这个头疼', '第3次入住酒店了，离地铁口很近，酒店有专门的停车场，解决了在广州这里停车这个头疼事。地点很方便周边吃喝玩很多选择。房间虽然不大，服务，特别好，很舒适。因为有老人特意换了没有浴缸的冲凉房。', '2024-09-09', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a4de3c98b0941765884', '来之前特意查了酒店的历史，特别有历史感的酒店，40年的历史，外管还是很有质感。我是冲着贝隶铭去的，名设计师的手笔。酒店有一个花园，挺有格调的，孩子在花园喂鱼，可以玩挺久。这里有很多的外国人入住，服务员的态度非常棒。说一下不足的地方，酒店房间设施确实比较旧了，但是有一说一，几十年的酒店，设备要求肯定不如新酒店。酒店的浴室设计比较奇怪，浴室没有地方挂衣服，出来洗手盆那里穿的话，其实通过对面的镜子会被房间的人看到。说一下地理位置，非常优越，地铁五号线一分钟路程，去各大景点路程都不算远。房费在这个地点不算贵了，所以大家可以根据自己的需求选择。', '["https://dimg04.c-ctrip.com/images/0236j12000fbyoyek0BC2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231g12000fbyluahBCFA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000fbynf2r2EAF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235512000fbyk5m609F6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234912000fbyrahiDCEE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235p12000fbyp13aED08_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-31', '花园双床房', '双床房', '家庭亲子', 270, 5.602118820879701, 0, 0.0, 12, 2.5649493574615367, 9, '["房间设施", "交通便利性", "性价比"]'::jsonb, '房间设施', '交通便利性', '性价比', '未知酒店', '未知地点', '匿名', '来之前特意查了酒店的历史，特别有历史感的酒店，40年的历史，外管还是很有质感。我', '来之前特意查了酒店的历史，特别有历史感的酒店，40年的历史，外管还是很有质感。我是冲着贝隶铭去的，名设计师的手笔。酒店有一个花园，挺有格调的，孩子在花园喂鱼，可以玩挺久。这里有很多的外国人入住，服务员的态度非常棒。说一下不足的地方，酒店房间设施确实比较旧了，但是有一说一，几十年的酒店，设备要求肯定不如新酒店。酒店的浴室设计比较奇怪，浴室没有地方挂衣服，出来洗手盆那里穿的话，其实通过对面的镜子会被房间的人看到。说一下地理位置，非常优越，地铁五号线一分钟路程，去各大景点路程都不算远。房费在这个地点不算贵了，所以大家可以根据自己的需求选择。', '2024-08-31', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a4de3c98b0941765885', '房间安排非常舒适，卫生整理及时。酒店后花园让人感到温暖、温馨??；早餐丰富、服务生态度绝对到位。值得推荐！', '["https://dimg04.c-ctrip.com/images/0234x12000gmbgp2379D1_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0234m12000gmbghb4764B_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0235312000gmbgm8u1005_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0233712000gmbgd58F0EC_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2024-11-11', '花园大床房', '大床房', '家庭亲子', 53, 3.9889840465642745, 0, 0.0, 4, 1.6094379124341005, 7, '["整体满意度", "客房服务", "餐饮设施"]'::jsonb, '整体满意度', '客房服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '房间安排非常舒适，卫生整理及时。酒店后花园让人感到温暖、温馨??；早餐丰富、服务', '房间安排非常舒适，卫生整理及时。酒店后花园让人感到温暖、温馨??；早餐丰富、服务生态度绝对到位。值得推荐！', '2024-11-11', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a4de3c98b0941765886', '酒店氛围很好，亲子游合适', '["https://dimg04.c-ctrip.com/images/0231i12000ibf7nso9105_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-05', '花园大床房', '大床房', '家庭亲子', 12, 2.5649493574615367, 0, 0.0, 5, 1.791759469228055, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '酒店氛围很好，亲子游合适', '酒店氛围很好，亲子游合适', '2025-02-05', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a4de3c98b0941765887', '太暖心了，服务超级好，值得你们预定', '["https://dimg04.c-ctrip.com/images/0234c12000hwj96rk97A7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-01-19', '城央绿意双床房', '双床房', '家庭亲子', 17, 2.8903717578961645, 0, 0.0, 5, 1.791759469228055, 3, '["整体满意度", "前台服务"]'::jsonb, '整体满意度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '太暖心了，服务超级好，值得你们预定', '太暖心了，服务超级好，值得你们预定', '2025-01-19', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a4de3c98b0941765888', '假期就是吃吃喝喝的时候，又来花园酒店了。前台姐姐热情地将我的红棉房升级到粤韵房，两张1.3米的床，体验感更好。洗漱台有两个，干湿分离且两人不干扰。酒店服务员都热情好客，让人如沐春风。在荔湾亭订位后进了晚餐，环境和服务都很不错，出品也物有所值。酒店还有个博物馆，可以了解酒店的辉煌历史。早餐种类很丰富，整体是很好的体验，值得再去。', '["https://dimg04.c-ctrip.com/images/0234p12000fbxfun69C6F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231j12000fbx9pv65BAA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000fbx9uz59CCD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231512000fbxcnvw7BAA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-31', '红棉双床套房', '套房', '家庭亲子', 164, 5.10594547390058, 0, 0.0, 1, 0.6931471805599453, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '假期就是吃吃喝喝的时候，又来花园酒店了。前台姐姐热情地将我的红棉房升级到粤韵房，', '假期就是吃吃喝喝的时候，又来花园酒店了。前台姐姐热情地将我的红棉房升级到粤韵房，两张1.3米的床，体验感更好。洗漱台有两个，干湿分离且两人不干扰。酒店服务员都热情好客，让人如沐春风。在荔湾亭订位后进了晚餐，环境和服务都很不错，出品也物有所值。酒店还有个博物馆，可以了解酒店的辉煌历史。早餐种类很丰富，整体是很好的体验，值得再去。', '2024-08-31', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a4de3c98b0941765889', '很感谢花园酒店前台的热情接待，给我升级安排的房间安静舒适，酒店的设施和服务让我感到宾至如归。房间宽敞明亮，床铺舒适，让我得以安享良好的睡眠。此外，每到一处的员工都有着热情服务和细致入微的照顾让我倍感温馨。酒店还提供了丰富的自助早餐和各种休闲设施，令我倍感放松。花园酒店是老广州的五星酒店，亦是广州的地标，在某些人的心里是一个时代无法磨灭的记忆！', '["https://dimg04.c-ctrip.com/images/0233u12000ew91ayf2E31_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000ew946yiD273_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234y12000ew93dr832F0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230r12000ew938zl7BA4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235w12000ew92er519B3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000ew92h6mCD3A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233g12000ew935lz3D5F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000ew91ayh90F3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000ew93bfuD5AC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-25', '花园双床房', '双床房', '商务出差', 172, 5.153291594497779, 5, 1.791759469228055, 21, 3.091042453358316, 9, '["前台服务", "房间设施", "整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '很感谢花园酒店前台的热情接待，给我升级安排的房间安静舒适，酒店的设施和服务让我感', '很感谢花园酒店前台的热情接待，给我升级安排的房间安静舒适，酒店的设施和服务让我感到宾至如归。房间宽敞明亮，床铺舒适，让我得以安享良好的睡眠。此外，每到一处的员工都有着热情服务和细致入微的照顾让我倍感温馨。酒店还提供了丰富的自助早餐和各种休闲设施，令我倍感放松。花园酒店是老广州的五星酒店，亦是广州的地标，在某些人的心里是一个时代无法磨灭的记忆！', '2024-07-25', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a4de3c98b094176588a', '值得推荐，博物馆可以看看', '["https://dimg04.c-ctrip.com/images/0233u12000i69tgu28CB1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000i6brgir4DE0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234u12000i6brgr37934_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-30', '花园双床房', '双床房', '家庭亲子', 12, 2.5649493574615367, 0, 0.0, 8, 2.19722457733622, 3, '["整体满意度", "周边配套"]'::jsonb, '整体满意度', '周边配套', NULL, '未知酒店', '未知地点', '匿名', '值得推荐，博物馆可以看看', '值得推荐，博物馆可以看看', '2025-01-30', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a4de3c98b094176588b', '很多年没有入住花园了，装修很有中国特色，房间大，还给我升级房型，特别喜欢瀑布花园，是城市里的一个绿洲，服务员很细心', '["https://dimg04.c-ctrip.com/images/0234s12000gjzkzgz07BC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o12000gk09bej3229_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230z12000gjz86khE5F1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000gk0dn5f51C1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000gjzj28k5022_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000gk0ih7eEDD3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232u12000gjzrpwlE9FD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000gjzvag93853_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-07', '花园大床房', '大床房', '商务出差', 57, 4.060443010546419, 0, 0.0, 9, 2.302585092994046, 7, '["整体满意度", "房间设施", "前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '很多年没有入住花园了，装修很有中国特色，房间大，还给我升级房型，特别喜欢瀑布花园', '很多年没有入住花园了，装修很有中国特色，房间大，还给我升级房型，特别喜欢瀑布花园，是城市里的一个绿洲，服务员很细心', '2024-11-07', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a5ee3c98b094176588c', '布置的很有新年气氛', '["https://dimg04.c-ctrip.com/images/0235n12000iawqq4b00C9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-02-04', '花园双床房', '双床房', '家庭亲子', 9, 2.302585092994046, 0, 0.0, 26, 3.295836866004329, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '布置的很有新年气氛', '布置的很有新年气氛', '2025-02-04', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a5ee3c98b094176588d', '这次携家人入住广州花园酒店，感觉非常好，住宿环境非常好，菜品精致，味道好，孩子们对游泳池更是喜欢，总之，体验很好。再有，感谢行政酒廊的Kitty,Deepa，Beryle ，Cunchan四位小姐姐的热情服务。', '["https://dimg04.c-ctrip.com/images/0236c12000fb6oo365CBC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230t12000fb6rrmx3403_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000fb6r5mj85F3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230712000fb6oqxp68A9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-30', '花园大床房', '大床房', '家庭亲子', 105, 4.663439094112067, 0, 0.0, 5, 1.791759469228055, 7, '["整体满意度", "餐饮设施", "公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施', '未知酒店', '未知地点', '匿名', '这次携家人入住广州花园酒店，感觉非常好，住宿环境非常好，菜品精致，味道好，孩子们', '这次携家人入住广州花园酒店，感觉非常好，住宿环境非常好，菜品精致，味道好，孩子们对游泳池更是喜欢，总之，体验很好。再有，感谢行政酒廊的Kitty,Deepa，Beryle ，Cunchan四位小姐姐的热情服务。', '2024-08-30', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a5ee3c98b094176588e', '超出预期的酒店！酒店大堂，园景很漂亮，工作人员热情，前台还帮忙升级了房型，很惊喜。
我们带着小孩连住两个晚上，小孩子很喜欢。
体验了位于30层的行政酒廊，服务很好，餐食也很棒，可以远眺小蛮腰，强烈推荐。还要感谢行政酒廊Echo, Cathy, Bergle的热情服务~', '["https://dimg04.c-ctrip.com/images/0235w12000fceepdmAE58_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-01', '花园大床房', '大床房', '家庭亲子', 134, 4.90527477843843, 1, 0.6931471805599453, 16, 2.833213344056216, 8, '["整体满意度", "前台服务", "景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向', '未知酒店', '未知地点', '匿名', '超出预期的酒店！酒店大堂，园景很漂亮，工作人员热情，前台还帮忙升级了房型，很惊喜', '超出预期的酒店！酒店大堂，园景很漂亮，工作人员热情，前台还帮忙升级了房型，很惊喜。
我们带着小孩连住两个晚上，小孩子很喜欢。
体验了位于30层的行政酒廊，服务很好，餐食也很棒，可以远眺小蛮腰，强烈推荐。还要感谢行政酒廊Echo, Cathy, Bergle的热情服务~', '2024-09-01', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a5ee3c98b094176588f', '第一次开到花园，感受到十分浓厚的白金五星底蕴，外国友人很多，一片祥和，门口就是淘金A口，出行十分方便，对面有广州友谊商场和丽柏，购物也是相当的方便，期待下次再来', '["https://dimg04.c-ctrip.com/images/0232w12000fpre35iC0F9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000fprjiuxC247_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232w12000fprk38e0E35_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000fprzn3eCB62_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000fps2a7zFBCA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o12000fpscmbe9583_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234k12000fpryg9kBD2C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-23', '花园大床房', '大床房', '情侣出游', 80, 4.394449154672439, 0, 0.0, 19, 2.995732273553991, 8, '["交通便利性", "周边配套", "整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度', '未知酒店', '未知地点', '匿名', '第一次开到花园，感受到十分浓厚的白金五星底蕴，外国友人很多，一片祥和，门口就是淘', '第一次开到花园，感受到十分浓厚的白金五星底蕴，外国友人很多，一片祥和，门口就是淘金A口，出行十分方便，对面有广州友谊商场和丽柏，购物也是相当的方便，期待下次再来', '2024-09-23', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a5ee3c98b0941765890', '一如既往的好，喜欢。床特别舒服。环境也好。早餐也丰富', '["https://dimg04.c-ctrip.com/images/0231h12000heo245i7CCF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000henggyxCBCC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000hemqlwk376E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-12-25', '花园双床房', '双床房', '朋友出游', 26, 3.295836866004329, 0, 0.0, 65, 4.189654742026425, 5, '["房间设施", "餐饮设施", "整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '一如既往的好，喜欢。床特别舒服。环境也好。早餐也丰富', '一如既往的好，喜欢。床特别舒服。环境也好。早餐也丰富', '2024-12-25', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a5ee3c98b0941765891', '买的携程的套餐，红棉房有一房一厅，淋浴室有浴缸，也有花洒，分开的。房间很干净。宝宝过生日，提前打电话说明还送了蛋糕。酒店自带后花园+博物馆，大厅富丽堂皇。在酒店就可以逛一天，晚上在日本餐厅吃的饭，用的套餐的400消费金额。晚上滴滴去花城汇看喷泉。一切都很完美', '["https://dimg04.c-ctrip.com/images/0233i12000f9mdvuc9DFA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234912000f9m9pkn5A2D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231b12000f9lmjk1E30B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-27', '红棉大床套房', '套房', '家庭亲子', 129, 4.867534450455582, 0, 0.0, 9, 2.302585092994046, 9, '["房间设施", "整体满意度", "客房服务"]'::jsonb, '房间设施', '整体满意度', '客房服务', '未知酒店', '未知地点', '匿名', '买的携程的套餐，红棉房有一房一厅，淋浴室有浴缸，也有花洒，分开的。房间很干净。宝', '买的携程的套餐，红棉房有一房一厅，淋浴室有浴缸，也有花洒，分开的。房间很干净。宝宝过生日，提前打电话说明还送了蛋糕。酒店自带后花园+博物馆，大厅富丽堂皇。在酒店就可以逛一天，晚上在日本餐厅吃的饭，用的套餐的400消费金额。晚上滴滴去花城汇看喷泉。一切都很完美', '2024-08-27', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a5ee3c98b0941765892', '老牌五星，历史悠久，酒店保养的挺好，大堂富丽堂皇，园林设计很用心，值得一逛，四楼的酒店博物馆也很值得看看，总体是个很值得体验的酒店，酒店交通便利，地铁口就在旁边，唯一不足是酒店早餐普通，但是也能满足基本需求了', '["https://dimg04.c-ctrip.com/images/0232u12000fbnkfi0732C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000fbnkbaz4FD6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234k12000fbnct51B820_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233n12000fbnquf9F48E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-31', '城央绿意大床房', '大床房', '情侣出游', 104, 4.653960350157523, 0, 0.0, 7, 2.079441541679836, 8, '["整体满意度", "交通便利性", "餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施', '未知酒店', '未知地点', '匿名', '老牌五星，历史悠久，酒店保养的挺好，大堂富丽堂皇，园林设计很用心，值得一逛，四楼', '老牌五星，历史悠久，酒店保养的挺好，大堂富丽堂皇，园林设计很用心，值得一逛，四楼的酒店博物馆也很值得看看，总体是个很值得体验的酒店，酒店交通便利，地铁口就在旁边，唯一不足是酒店早餐普通，但是也能满足基本需求了', '2024-08-31', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a5ee3c98b0941765893', '二十年后再次入住花园酒店，没有那年那月的惊艳，只有一些怀旧的回顾。重返二楼荔湾亭，再上30楼，还是满满的贴心服务。两点不太满意之处，房间二并一后大一些但格局不太好，特别浴室的镜子斑斑驳驳更有年代感；另外就是客房服务不到位和僵化，因床头插座不明显，昨天上午离店时遗漏充电器，昨晚想起打电话过去，第一通电话说服务员没有上报，等落实后再回电，当时我还寻思是否我放在行李箱，再次大寻找不果后，也未等到酒店回电。我只能再次打电话，此次我非常明确进行描述，登记后二十来分钟回电说找到。我让帮忙叫一个到付的闪送之类，回复只能顺丰到付或是自取，没有考虑客人因为没有充电器的不便。只是服务僵化的问题，缺乏变通。另外就是房间服务员没有及时上报失物，存在瑕疵；再之就是酒店接到电话后，存在回复不及时等，相对遗憾。', '["https://dimg04.c-ctrip.com/images/0234712000f97t4db1B11_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000f97klto2C88_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000f97h4i0FBB2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-08-26', '红棉大床套房', '套房', '商务出差', 345, 5.846438775057725, 0, 0.0, 24, 3.218875824868201, 8, '["客房服务", "房间设施", "整体满意度"]'::jsonb, '客房服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '二十年后再次入住花园酒店，没有那年那月的惊艳，只有一些怀旧的回顾。重返二楼荔湾亭', '二十年后再次入住花园酒店，没有那年那月的惊艳，只有一些怀旧的回顾。重返二楼荔湾亭，再上30楼，还是满满的贴心服务。两点不太满意之处，房间二并一后大一些但格局不太好，特别浴室的镜子斑斑驳驳更有年代感；另外就是客房服务不到位和僵化，因床头插座不明显，昨天上午离店时遗漏充电器，昨晚想起打电话过去，第一通电话说服务员没有上报，等落实后再回电，当时我还寻思是否我放在行李箱，再次大寻找不果后，也未等到酒店回电。我只能再次打电话，此次我非常明确进行描述，登记后二十来分钟回电说找到。我让帮忙叫一个到付的闪送之类，回复只能顺丰到付或是自取，没有考虑客人因为没有充电器的不便。只是服务僵化的问题，缺乏变通。另外就是房间服务员没有及时上报失物，存在瑕疵；再之就是酒店接到电话后，存在回复不及时等，相对遗憾。', '2024-08-26', 4, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a5ee3c98b0941765894', '酒店位置很方便，服务也很好，各种设施很全，二楼和三楼的餐厅也很不错，酒店有不少外国人，还有后面的瀑布和园子造景也相当不错，各方面都符合老牌酒店的水准，住的是套房，酒店通风要是再好些的话就更完美了', '["https://dimg04.c-ctrip.com/images/0234q12000fbywo8x3FAB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-08-31', '红棉大床套房', '套房', '商务出差', 97, 4.584967478670572, 0, 0.0, 9, 2.302585092994046, 8, '["周边配套", "整体满意度", "餐饮设施"]'::jsonb, '周边配套', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店位置很方便，服务也很好，各种设施很全，二楼和三楼的餐厅也很不错，酒店有不少外', '酒店位置很方便，服务也很好，各种设施很全，二楼和三楼的餐厅也很不错，酒店有不少外国人，还有后面的瀑布和园子造景也相当不错，各方面都符合老牌酒店的水准，住的是套房，酒店通风要是再好些的话就更完美了', '2024-08-31', 4, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a5ee3c98b0941765895', '五星级的服务值得点赞，虽然房间的装修有点旧，但是卫生，细节都有五星级标准，酒店大厅大气高级，每个楼层都配备服务人员开电梯，带了两个小孩，还免费送了两小孩的早餐及行政酒廊，入住体验好非常好，早餐瀑布餐厅和30楼的旋转餐厅，环境很好，餐食也很不错', '["https://dimg04.c-ctrip.com/images/0236012000f9wg7wj4D9A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000f9wuz8f5930_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230a12000f9whqydFBD6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-27', '花园双床房', '双床房', '家庭亲子', 121, 4.804021044733257, 0, 0.0, 1, 0.6931471805599453, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '五星级的服务值得点赞，虽然房间的装修有点旧，但是卫生，细节都有五星级标准，酒店大', '五星级的服务值得点赞，虽然房间的装修有点旧，但是卫生，细节都有五星级标准，酒店大厅大气高级，每个楼层都配备服务人员开电梯，带了两个小孩，还免费送了两小孩的早餐及行政酒廊，入住体验好非常好，早餐瀑布餐厅和30楼的旋转餐厅，环境很好，餐食也很不错', '2024-08-27', 5, '整体满意度');
