INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a69e3c98b094176589a', '1、前台服务员Gilian很nice，服务态度很好，很耐心，感谢给我们升级房间。
2、其他服务员态度也很棒，每次见面都打招呼，还主动按电梯。
3、粤韵套房很赞，一房一厅，面积很大，设施很新。房间还赠送了行政礼遇，包含下午茶和晚间的happy hour，超级赞，家人都非常满意。
4、30楼旋转餐厅太棒了，慢悠悠旋转，早餐非常丰富，都很好吃，超出预期。
5、酒店后花园值得散步，打卡拍照，太美了。
6、酒店交通便捷，旁边就是淘金地铁口，去哪里都很方便，都能乘坐地铁到达。', '["https://dimg04.c-ctrip.com/images/0232x12000f9h8h1wEC8F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234a12000f9gviye687A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-26', '花园大床房', '大床房', '家庭亲子', 234, 5.459585514144159, 1, 0.6931471805599453, 9, 2.302585092994046, 9, '["前台服务", "房间设施", "交通便利性"]'::jsonb, '前台服务', '房间设施', '交通便利性', '未知酒店', '未知地点', '匿名', '1、前台服务员Gilian很nice，服务态度很好，很耐心，感谢给我们升级房间。', '1、前台服务员Gilian很nice，服务态度很好，很耐心，感谢给我们升级房间。
2、其他服务员态度也很棒，每次见面都打招呼，还主动按电梯。
3、粤韵套房很赞，一房一厅，面积很大，设施很新。房间还赠送了行政礼遇，包含下午茶和晚间的happy hour，超级赞，家人都非常满意。
4、30楼旋转餐厅太棒了，慢悠悠旋转，早餐非常丰富，都很好吃，超出预期。
5、酒店后花园值得散步，打卡拍照，太美了。
6、酒店交通便捷，旁边就是淘金地铁口，去哪里都很方便，都能乘坐地铁到达。', '2024-08-26', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a69e3c98b094176589b', '非常好，房间很大，近地铁口。', '["https://dimg04.c-ctrip.com/images/0231y12000hwjqqh60129_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2025-01-19', '粤韵双床套房', '套房', '家庭亲子', 14, 2.70805020110221, 0, 0.0, 13, 2.6390573296152584, 5, '["房间设施", "交通便利性", "整体满意度"]'::jsonb, '房间设施', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '非常好，房间很大，近地铁口。', '非常好，房间很大，近地铁口。', '2025-01-19', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a69e3c98b094176589c', '24号退房，房间虽小，但东西很齐全，还有博物馆。30楼的欢乐时光，下午茶体验感都很好，服务非常棒！但是30楼的早餐服务不如1楼的早餐服务，服务员说话也不好听，一大早心情就把心情破坏了，体验感太不好了！所以我住了五天四晚，只去30楼吃了一次早餐。1楼的早餐服务就很棒，服务员也很有礼貌，引导完等你坐下来会很耐心的询问需要咖啡吗？如有需要他们会帮你打好送过来。总体来说，除了30楼那次早餐体验的不舒服，酒店的其他方面我都很喜欢。', '["https://dimg04.c-ctrip.com/images/0232a12000f8ptnvgC851_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230c12000f8pl6ibE787_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000f8p5nfn23ED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-08-25', '花园大床房', '大床房', '情侣出游', 212, 5.3612921657094255, 0, 0.0, 3, 1.3862943611198906, 9, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '24号退房，房间虽小，但东西很齐全，还有博物馆。30楼的欢乐时光，下午茶体验感都', '24号退房，房间虽小，但东西很齐全，还有博物馆。30楼的欢乐时光，下午茶体验感都很好，服务非常棒！但是30楼的早餐服务不如1楼的早餐服务，服务员说话也不好听，一大早心情就把心情破坏了，体验感太不好了！所以我住了五天四晚，只去30楼吃了一次早餐。1楼的早餐服务就很棒，服务员也很有礼貌，引导完等你坐下来会很耐心的询问需要咖啡吗？如有需要他们会帮你打好送过来。总体来说，除了30楼那次早餐体验的不舒服，酒店的其他方面我都很喜欢。', '2024-08-25', 4, '餐饮设施');
