INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a75e3c98b09417658a0', '本次入住很满意，不愧是老牌五星级酒店，各方面都做的不错', '["https://dimg04.c-ctrip.com/images/0230312000hahv0082962_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-12-25', '花园双床房', '双床房', '其他', 27, 3.332204510175204, 0, 0.0, 6, 1.9459101490553128, 5, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '本次入住很满意，不愧是老牌五星级酒店，各方面都做的不错', '本次入住很满意，不愧是老牌五星级酒店，各方面都做的不错', '2024-12-25', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a75e3c98b09417658a1', '在广州玩，做功课，按照酒店博物馆的顺序依次住了，白天鹅，中国大酒店，和花园酒店
总的体验下来，这家真的最最贴心，下次还会来的
金庸说来了这里如进荣国府，一楼大厅的红楼梦壁画确实美丽，前台办理入住的时候很贴心，回答也很耐心，这是唯一一家我们到了就能入住的，其他两家均要到两三点，说要打扫。接着酒店后面的花园很美，酒店的电梯很方便，房间布局合适，床品整洁，都没有出去玩就呆在酒店逛逛了，不累不热，另外酒店的早餐在一楼和顶楼，我们选择了顶楼的旋转餐厅，视野非常好，菜品很多，下次来想多吃些甜品', '["https://dimg04.c-ctrip.com/images/0236j12000euq2g20AB4E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000euqd25vADD6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235n12000euq5sfk256B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236k12000euq4u1806B4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235z12000euq57ko693D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231h12000euq9kn9C2AF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i12000euq56t102B2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231512000euq7tubF556_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000euq9knd38BD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-21', '红棉双床套房', '套房', '朋友出游', 243, 5.497168225293202, 2, 1.0986122886681098, 22, 3.1354942159291497, 9, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '在广州玩，做功课，按照酒店博物馆的顺序依次住了，白天鹅，中国大酒店，和花园酒店', '在广州玩，做功课，按照酒店博物馆的顺序依次住了，白天鹅，中国大酒店，和花园酒店
总的体验下来，这家真的最最贴心，下次还会来的
金庸说来了这里如进荣国府，一楼大厅的红楼梦壁画确实美丽，前台办理入住的时候很贴心，回答也很耐心，这是唯一一家我们到了就能入住的，其他两家均要到两三点，说要打扫。接着酒店后面的花园很美，酒店的电梯很方便，房间布局合适，床品整洁，都没有出去玩就呆在酒店逛逛了，不累不热，另外酒店的早餐在一楼和顶楼，我们选择了顶楼的旋转餐厅，视野非常好，菜品很多，下次来想多吃些甜品', '2024-07-21', 5, '前台服务');
