INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a75e3c98b09417658a5', '来广州玩，最终选择广州花园酒店，因为它是白金五星级酒店，服务确实不错，进入酒店大堂的那一刻，就会让人肃然起敬，浓厚的艺术文化气息扑面而来。那一刻就觉得选对了，很值得！Echo非常热心的帮我们一家老小升级的房间，酒店服务也是相当贴心。', '["https://dimg04.c-ctrip.com/images/0233o12000f6iz83yEF0F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230m12000f6j5nc94E31_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233412000f6j3l9u6AA3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.3, 4, '2024-08-20', '花园大床房', '大床房', '家庭亲子', 116, 4.762173934797756, 0, 0.0, 16, 2.833213344056216, 8, '["前台服务", "整体满意度", "性价比"]'::jsonb, '前台服务', '整体满意度', '性价比', '未知酒店', '未知地点', '匿名', '来广州玩，最终选择广州花园酒店，因为它是白金五星级酒店，服务确实不错，进入酒店大', '来广州玩，最终选择广州花园酒店，因为它是白金五星级酒店，服务确实不错，进入酒店大堂的那一刻，就会让人肃然起敬，浓厚的艺术文化气息扑面而来。那一刻就觉得选对了，很值得！Echo非常热心的帮我们一家老小升级的房间，酒店服务也是相当贴心。', '2024-08-20', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a75e3c98b09417658a6', '非常好的酒店，酒店员工热情周到，设施很好，老牌酒店的风格浓郁。酒店里的博物馆值得去参观，有机会还会再来住。', '["https://dimg04.c-ctrip.com/images/0233d12000ghjl8vmDFB3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232512000ghk6arl440A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234812000ghjt1cd9AD5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-11-04', '花园大床房', '大床房', '独自旅行', 53, 3.9889840465642745, 0, 0.0, 17, 2.8903717578961645, 6, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '非常好的酒店，酒店员工热情周到，设施很好，老牌酒店的风格浓郁。酒店里的博物馆值得', '非常好的酒店，酒店员工热情周到，设施很好，老牌酒店的风格浓郁。酒店里的博物馆值得去参观，有机会还会再来住。', '2024-11-04', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a75e3c98b09417658a7', '花园酒店值得一住，前台客房餐厅碰到的服务员都很专业认真态度热情。1楼的自助早餐和3楼广式早茶行政酒廊小点心都很好吃。下次有机会来广州还住你们家。', '["https://dimg04.c-ctrip.com/images/0232312000fz7liqhFE9E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233z12000fz8ro4jE815_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000fz7w1tv49FE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000fz7w3e4255B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236o12000fz8jc4d75BF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000fz86ote249E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-04', '花园双床房', '双床房', '家庭亲子', 72, 4.290459441148391, 0, 0.0, 12, 2.5649493574615367, 8, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '花园酒店值得一住，前台客房餐厅碰到的服务员都很专业认真态度热情。1楼的自助早餐和', '花园酒店值得一住，前台客房餐厅碰到的服务员都很专业认真态度热情。1楼的自助早餐和3楼广式早茶行政酒廊小点心都很好吃。下次有机会来广州还住你们家。', '2024-10-04', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a75e3c98b09417658a8', '携程的套餐很划算。前台的小姐姐们有求必应，碰到的每位员工都微笑打招呼，客房服务还能根据前一天的使用情况增加备品，非常人性化。除开我住的房型淋浴跟浴缸在一起老人使用不方便外，都十分满意！', '["https://dimg04.c-ctrip.com/images/0236h12000fbxhpnoC03A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f12000fbxac5c662B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f12000fbx4ns21E2C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i12000fbxcnuu0697_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000fbxazxz4267_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x12000fbx7cw58EAF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-08-31', '花园双床房', '双床房', '家庭亲子', 92, 4.532599493153256, 0, 0.0, 8, 2.19722457733622, 9, '["性价比", "前台服务", "客房服务"]'::jsonb, '性价比', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '携程的套餐很划算。前台的小姐姐们有求必应，碰到的每位员工都微笑打招呼，客房服务还', '携程的套餐很划算。前台的小姐姐们有求必应，碰到的每位员工都微笑打招呼，客房服务还能根据前一天的使用情况增加备品，非常人性化。除开我住的房型淋浴跟浴缸在一起老人使用不方便外，都十分满意！', '2024-08-31', 4, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a75e3c98b09417658a9', '90年代住过的酒店之一，如今依然保留如初，每一个空间有着满满的回忆。 30楼的行政酒廊每天有下午茶和happy hour，这里每一位员工都很友好，特别是Carrie，我们对她印象深刻，是一位不可多得的优秀员工。', '["https://dimg04.c-ctrip.com/images/0233h424x8w0tnipn93E8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-21', '花园双床房', '双床房', '商务出差', 105, 4.663439094112067, 0, 0.0, 1, 0.6931471805599453, 8, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '90年代住过的酒店之一，如今依然保留如初，每一个空间有着满满的回忆。 30楼的行', '90年代住过的酒店之一，如今依然保留如初，每一个空间有着满满的回忆。 30楼的行政酒廊每天有下午茶和happy hour，这里每一位员工都很友好，特别是Carrie，我们对她印象深刻，是一位不可多得的优秀员工。', '2024-08-21', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a80e3c98b09417658aa', '老广来评一下～好久没来花园了，这次携程的套餐真的很给力，马上订了。结果原来花园的服务已经不太OK了～我们到前台，给了身份证之后，那个前台的男士很冷漠地让我们给500押金，说了房型，递了房卡。我就问，不是有花园小羊周边？
他：哦，是吗，然后才去找。接下来我再问，是有消费额度可以用晚餐吗。他继续冷漠说，你吃了告知服务员房号吧。（难道他不能说是的几个餐厅都可以）后来我只能留言问携程客服说是不是套餐的东西要让他们确认一遍，携程客服马上打去前台，没人接，我让客服不要打。算了，我们自己去日本餐厅问。
日餐东西OK，厨师很热情，服务员也可以，就是她们收桌很慢，会吃了很久的东西没位置放新的也不收。日餐带位小哥态度好。
房间中规中矩，干净，但是不新，有很多使用痕迹是打扫不了的。另外晚上11点多打电话想要个硬枕头也没人接电话……怎么会这样……
早餐我们选在桃源馆用，也不错～但是应该瀑布好吃点。退房还是要自己提醒前台我们是套餐有消费额度才行……哎，而且他从头到尾也没发现我是岭南会金卡，我理解携程订的不能用，但是对比洲际万豪等前台服务几乎为0……', '["https://dimg04.c-ctrip.com/images/0234p12000f62imgbA556_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000f62imgn8E55_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236u12000f62j7i19865_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2024-08-18', '红棉大床套房', '套房', '情侣出游', 471, 6.156978985585555, 5, 1.791759469228055, 2, 1.0986122886681098, 8, '["前台服务", "客房服务", "卫生状况"]'::jsonb, '前台服务', '客房服务', '卫生状况', '未知酒店', '未知地点', '匿名', '老广来评一下～好久没来花园了，这次携程的套餐真的很给力，马上订了。结果原来花园的', '老广来评一下～好久没来花园了，这次携程的套餐真的很给力，马上订了。结果原来花园的服务已经不太OK了～我们到前台，给了身份证之后，那个前台的男士很冷漠地让我们给500押金，说了房型，递了房卡。我就问，不是有花园小羊周边？
他：哦，是吗，然后才去找。接下来我再问，是有消费额度可以用晚餐吗。他继续冷漠说，你吃了告知服务员房号吧。（难道他不能说是的几个餐厅都可以）后来我只能留言问携程客服说是不是套餐的东西要让他们确认一遍，携程客服马上打去前台，没人接，我让客服不要打。算了，我们自己去日本餐厅问。
日餐东西OK，厨师很热情，服务员也可以，就是她们收桌很慢，会吃了很久的东西没位置放新的也不收。日餐带位小哥态度好。
房间中规中矩，干净，但是不新，有很多使用痕迹是打扫不了的。另外晚上11点多打电话想要个硬枕头也没人接电话……怎么会这样……
早餐我们选在桃源馆用，也不错～但是应该瀑布好吃点。退房还是要自己提醒前台我们是套餐有消费额度才行……哎，而且他从头到尾也没发现我是岭南会金卡，我理解携程订的不能用，但是对比洲际万豪等前台服务几乎为0……', '2024-08-18', 3, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a80e3c98b09417658ab', '三十年再次进住该店，风采依然。对比同市一众豪华品牌，不遑多让。一次过品尝了桃园、锦鲤吧与茘湾亭的美酒佳肴。遗憾的是，玻璃窗密封胶老化且无窗把锁扣，让窗外噪音有机可乘，扰人清梦。', '["https://dimg04.c-ctrip.com/images/0233t12000fdikzty8851_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230w12000fdinqu5A61F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2024-09-03', '红棉大床套房', '套房', '商务出差', 88, 4.48863636973214, 0, 0.0, 58, 4.07753744390572, 9, '["餐饮设施", "安静程度", "房间设施"]'::jsonb, '餐饮设施', '安静程度', '房间设施', '未知酒店', '未知地点', '匿名', '三十年再次进住该店，风采依然。对比同市一众豪华品牌，不遑多让。一次过品尝了桃园、', '三十年再次进住该店，风采依然。对比同市一众豪华品牌，不遑多让。一次过品尝了桃园、锦鲤吧与茘湾亭的美酒佳肴。遗憾的是，玻璃窗密封胶老化且无窗把锁扣，让窗外噪音有机可乘，扰人清梦。', '2024-09-03', 4, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a80e3c98b09417658ac', '房间很旧很小墙纸脏的，第一次服务人员给了一个带浴缸的房，淋雨要站到浴缸里去洗位置非常小，像三星级，不过经过沟通有更换！洗漱用品比较差，老酒店，酒店外观漂亮打卡地方多，就是外美内差表里不一', '["https://dimg04.c-ctrip.com/images/0236f12000f9tqmouE6FC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000f9tqza8B3A3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2024-08-27', '花园双床房', '双床房', '家庭亲子', 93, 4.543294782270004, 0, 0.0, 6, 1.9459101490553128, 8, '["房间设施", "卫生状况", "整体满意度"]'::jsonb, '房间设施', '卫生状况', '整体满意度', '未知酒店', '未知地点', '匿名', '房间很旧很小墙纸脏的，第一次服务人员给了一个带浴缸的房，淋雨要站到浴缸里去洗位置', '房间很旧很小墙纸脏的，第一次服务人员给了一个带浴缸的房，淋雨要站到浴缸里去洗位置非常小，像三星级，不过经过沟通有更换！洗漱用品比较差，老酒店，酒店外观漂亮打卡地方多，就是外美内差表里不一', '2024-08-27', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a80e3c98b09417658ad', '老牌五星酒店，地理位置很好，设施的维护也不错。刚入住的时候，对于酒店的服务态度是很满意的，没想到住了三晚，遇到两个状况感受很差。其一是早餐，一楼瀑布餐厅和三十楼，菜式基本上都是牛肉为主，完全没有猪肉菜式，当然早餐也没有海鲜这类的，对于我们这样因为宗教信仰而不吃牛肉的人而言，连续三天早餐素食度过，酒店的介绍完全不提及这个部分，否则我们定然不选择这个酒店，真是悲哀！非常难以接受！其二是退房，前台小女孩连数学计数都困难，我们付了1500押金，主动告知用了20元饮料费，她的原话是“剩下的148元我们会到时候退，但是什么时候不知道”再追问又回应说“押金150元用20元剩下148”，这就是著名的花园酒店吗？退房8个多小时，发现押金没退回，刚才联系携程客服，进行投诉反馈，酒店回应明天中午退。这令人非常不解，花园酒店的服务效率和品质都这么低下了吗？！', '["https://dimg04.c-ctrip.com/images/0234d12000f6gpi70417F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233012000f6goqx24B95_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236a12000f6gwd7o2482_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2024-08-19', '花园大床房', '大床房', '其他', 372, 5.921578419643816, 2, 1.0986122886681098, 35, 3.58351893845611, 9, '["餐饮设施", "退房/入住效率", "前台服务"]'::jsonb, '餐饮设施', '退房/入住效率', '前台服务', '未知酒店', '未知地点', '匿名', '老牌五星酒店，地理位置很好，设施的维护也不错。刚入住的时候，对于酒店的服务态度是', '老牌五星酒店，地理位置很好，设施的维护也不错。刚入住的时候，对于酒店的服务态度是很满意的，没想到住了三晚，遇到两个状况感受很差。其一是早餐，一楼瀑布餐厅和三十楼，菜式基本上都是牛肉为主，完全没有猪肉菜式，当然早餐也没有海鲜这类的，对于我们这样因为宗教信仰而不吃牛肉的人而言，连续三天早餐素食度过，酒店的介绍完全不提及这个部分，否则我们定然不选择这个酒店，真是悲哀！非常难以接受！其二是退房，前台小女孩连数学计数都困难，我们付了1500押金，主动告知用了20元饮料费，她的原话是“剩下的148元我们会到时候退，但是什么时候不知道”再追问又回应说“押金150元用20元剩下148”，这就是著名的花园酒店吗？退房8个多小时，发现押金没退回，刚才联系携程客服，进行投诉反馈，酒店回应明天中午退。这令人非常不解，花园酒店的服务效率和品质都这么低下了吗？！', '2024-08-19', 3, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a80e3c98b09417658ae', '暑期带娃出行，选了一圈最终选择了这家，果然没选错，设施和设备都是相当齐全，服务也是非常满意，泳池满足了小朋友游泳的的快乐！对于酒店不能只看新旧，主要看综合实力啊！房间有些旧算是瑕疵，但是综合评分不错的，推荐！', '["https://dimg04.c-ctrip.com/images/0236812000g0z2wc6635F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234s12000g0zgmdm8C8A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-10-07', '花园双床房', '双床房', '家庭亲子', 104, 4.653960350157523, 0, 0.0, 30, 3.4339872044851463, 7, '["公共设施", "整体满意度", "房间设施"]'::jsonb, '公共设施', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '暑期带娃出行，选了一圈最终选择了这家，果然没选错，设施和设备都是相当齐全，服务也', '暑期带娃出行，选了一圈最终选择了这家，果然没选错，设施和设备都是相当齐全，服务也是非常满意，泳池满足了小朋友游泳的的快乐！对于酒店不能只看新旧，主要看综合实力啊！房间有些旧算是瑕疵，但是综合评分不错的，推荐！', '2024-10-07', 4, '公共设施');
