INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a80e3c98b09417658b2', '房间比较小，如果白天长时间留在房间里感觉比较压抑，床是挺舒服的。酒店处于广州市中心商圈，交通还是挺方便的，工作人员也挺热情有礼貌，或许入住的客户中，国外客户在这个酒店的占比比较大，酒店各种服务都会不自觉的往国外客户倾斜，有感受到一定的区别对待。总的来说，还算可以的。', '["https://dimg04.c-ctrip.com/images/0230312000f86o6t228F4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235n12000f86eo8zFB20_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-08-23', '花园大床房', '大床房', '商务出差', 133, 4.897839799950911, 0, 0.0, 4, 1.6094379124341005, 7, '["房间设施", "交通便利性", "前台服务"]'::jsonb, '房间设施', '交通便利性', '前台服务', '未知酒店', '未知地点', '匿名', '房间比较小，如果白天长时间留在房间里感觉比较压抑，床是挺舒服的。酒店处于广州市中', '房间比较小，如果白天长时间留在房间里感觉比较压抑，床是挺舒服的。酒店处于广州市中心商圈，交通还是挺方便的，工作人员也挺热情有礼貌，或许入住的客户中，国外客户在这个酒店的占比比较大，酒店各种服务都会不自觉的往国外客户倾斜，有感受到一定的区别对待。总的来说，还算可以的。', '2024-08-23', 4, '房间设施');
