INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a8be3c98b09417658b5', '多次来广州都住这里。服务很棒，晚上到酒店晚，Betty看带着孩子，立即帮升级了房型，很贴心的问候关心，给个赞！房间干净，整洁。入住的朋友不少，酒店有三个早餐点，还有个旋转餐厅，菜品中西合并，品种繁多。露台的泳池是孩子最喜欢的。', '["https://dimg04.c-ctrip.com/images/0235712000f5z9a61200F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-18', '花园大床房', '大床房', '家庭亲子', 113, 4.736198448394496, 0, 0.0, 4, 1.6094379124341005, 9, '["前台服务", "卫生状况", "餐饮设施"]'::jsonb, '前台服务', '卫生状况', '餐饮设施', '未知酒店', '未知地点', '匿名', '多次来广州都住这里。服务很棒，晚上到酒店晚，Betty看带着孩子，立即帮升级了房', '多次来广州都住这里。服务很棒，晚上到酒店晚，Betty看带着孩子，立即帮升级了房型，很贴心的问候关心，给个赞！房间干净，整洁。入住的朋友不少，酒店有三个早餐点，还有个旋转餐厅，菜品中西合并，品种繁多。露台的泳池是孩子最喜欢的。', '2024-08-18', 5, '前台服务');
