INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a8be3c98b09417658b7', '广州花园酒店30楼行政酒廊的服务很赞很周到，到广州一定要来打卡这里的旋转餐厅，不但早餐丰富，下午茶也很美味。大赞几位美女，Carrie，Echo，Kitty，服务热情大方，笑容有感染力，真是一次身心愉悦的旅程，大大的推荐', '["https://dimg04.c-ctrip.com/images/0232x12000f3fdy8t1D0D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000f3fe2ln7A24_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000f3f3gtk8F35_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236812000f3fbcfz13F5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-12', '花园双床房', '双床房', '家庭亲子', 110, 4.709530201312334, 1, 0.6931471805599453, 2, 1.0986122886681098, 8, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '广州花园酒店30楼行政酒廊的服务很赞很周到，到广州一定要来打卡这里的旋转餐厅，不', '广州花园酒店30楼行政酒廊的服务很赞很周到，到广州一定要来打卡这里的旋转餐厅，不但早餐丰富，下午茶也很美味。大赞几位美女，Carrie，Echo，Kitty，服务热情大方，笑容有感染力，真是一次身心愉悦的旅程，大大的推荐', '2024-08-12', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a8be3c98b09417658b8', '卫生： 洗手间与沐浴间共用一扇玻璃门，如果要沐浴就影响了洗手间的使用，没法同时使用，环境很好，大堂富丽堂皇 设施很好，服务态度很好 地理位置很好，出行方便 ，是一次很好的入住体验。', '["https://dimg04.c-ctrip.com/images/0231f12000f8wu0aqBF69_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-08-25', '花园双床房', '双床房', '家庭亲子', 90, 4.51085950651685, 0, 0.0, 19, 2.995732273553991, 7, '["房间设施", "整体满意度", "交通便利性"]'::jsonb, '房间设施', '整体满意度', '交通便利性', '未知酒店', '未知地点', '匿名', '卫生： 洗手间与沐浴间共用一扇玻璃门，如果要沐浴就影响了洗手间的使用，没法同时使', '卫生： 洗手间与沐浴间共用一扇玻璃门，如果要沐浴就影响了洗手间的使用，没法同时使用，环境很好，大堂富丽堂皇 设施很好，服务态度很好 地理位置很好，出行方便 ，是一次很好的入住体验。', '2024-08-25', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a8be3c98b09417658b9', '40年前人们印象中的位于广州环市东路的花园酒店是一间超豪华的五星级酒店。其实历经四十年沧桑变化的今天，店内大多数的房间已经残旧不堪，非常落后 ！只有少数几年前重新装修的红棉套房和粤韵套房可以入住。房间面积狭窄，住进去很不舒服！洗手间阵阵霉味散发出来，厕所和洗漱间共用一扇趟门，关了厕所门，洗漱间的门就只能敞开，极不方便，还有，进入厕所后侧着身体才能把门关上。全广州26家五星级酒店都住过了，这里的性价比最低！
        大堂再豪华都无用，房间环境和设施才是住客的首要所在 ！', '["https://dimg04.c-ctrip.com/images/0235i12000f3nseqqA5EE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000f3n1l13BAD4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234i12000f3nh8u65271_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.0, 3, '2024-08-13', '花园双床房', '双床房', '其他', 240, 5.484796933490655, 4, 1.6094379124341005, 10, 2.3978952727983707, 9, '["房间设施", "性价比", "卫生状况"]'::jsonb, '房间设施', '性价比', '卫生状况', '未知酒店', '未知地点', '匿名', '40年前人们印象中的位于广州环市东路的花园酒店是一间超豪华的五星级酒店。其实历经', '40年前人们印象中的位于广州环市东路的花园酒店是一间超豪华的五星级酒店。其实历经四十年沧桑变化的今天，店内大多数的房间已经残旧不堪，非常落后 ！只有少数几年前重新装修的红棉套房和粤韵套房可以入住。房间面积狭窄，住进去很不舒服！洗手间阵阵霉味散发出来，厕所和洗漱间共用一扇趟门，关了厕所门，洗漱间的门就只能敞开，极不方便，还有，进入厕所后侧着身体才能把门关上。全广州26家五星级酒店都住过了，这里的性价比最低！
        大堂再豪华都无用，房间环境和设施才是住客的首要所在 ！', '2024-08-13', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a8be3c98b09417658ba', '服务周到规范，环境优美，位置优越，早餐品类丰富。尤其是那两个瀑布，让人印象深圳。美中不足的是，充电插口太少，卫生间没有放手机的架子。', '["https://dimg04.c-ctrip.com/images/0230712000fu0q07w2B3E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230r12000fu0c3vv604D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000fu0zkpt4F6B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000fu0xyeo0DB5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236812000fu0xx20AD33_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234c12000fu0l82f5179_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-09-29', '红棉大床套房', '套房', '家庭亲子', 66, 4.204692619390966, 0, 0.0, 81, 4.406719247264253, 7, '["房间设施", "整体满意度", "餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '服务周到规范，环境优美，位置优越，早餐品类丰富。尤其是那两个瀑布，让人印象深圳。', '服务周到规范，环境优美，位置优越，早餐品类丰富。尤其是那两个瀑布，让人印象深圳。美中不足的是，充电插口太少，卫生间没有放手机的架子。', '2024-09-29', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a8be3c98b09417658bb', '非常有年代和历史沉淀感的一家酒店，我呢，怀着对参观历史建筑一份期望入住此酒店。但却是我入住所有五星酒店里面体验感比较差的，我说的是前台和餐厅的服务，并不包括客房等服务，还有硬件维护的也不错。总结体验如下，1、之前订的房间是18到21层，而且当天一再要求高楼层，但是晚上我夫人过来取卡的时候却给了个第7层低楼层，后通过携程的交涉很圆满的解决了，但是现场服务人员却轻描淡写的说可能交接的时候有误，这是你们老牌五星酒店不应该的啊，虽然后面送了宝格丽的洗护小包装；2、第二天吃早餐的时候由于人多，服务员让我夫人去排队。排就排呗，但排队的同时，有一个非洲的朋友过来以后在门口停留了会，和领班聊了会，竟然直接由领班带进去了，当时我们就提出质疑，领班尽然信誓旦旦的说他的朋友已经在里面了，这就是空口说白话，实际上最后这个非洲的朋友是单独一张桌子（大家懂得都懂）。后来领班又说他们是一个团队的，所以可以不用排队，我们直接回复他-就算是一个团队有朋友在里面也不能代排队代占座、除非你们是一个房间的才可以，现在都什么时代了，尽然还有这种事情发生[尴尬]3、自助早餐品种少、味道一般、性价比不高、而且问现场的面点（下面条混沌）师傅、这个蒸点是酒店包的还是外面采购的？面点师傅含糊其辞打太极说不知道要问厨师，晕，本来准备入住三天的，最后第三天（前面二天已经付款无法退）果断退房换了天河的酒店（扇子??）4、第三天早餐的时候也是排队，发现已经没有人押队了，秩序井井有条；5、客房服务不错，衣服洗的很干净（但价格比三亚丽思高30%，当天就干了1100洗衣）；6、硬件维护的不错，也很大气，可以看出当初设计的前卫和投入；希望花园酒店能够适当提升下服务水准，国人与外国人统一对待！如果没有上述1、2条，则酒店还是很完美的体验', '["https://dimg04.c-ctrip.com/images/0201512000f31r4ml65F2_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0233g12000f31nky6A2BC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236j12000f31jf4t46A2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230p12000f31dg8fC5BB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230712000f31nbqv544A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236512000f31gw3x2B55_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2024-08-11', '花园双床房', '双床房', '家庭亲子', 746, 6.616065185132817, 5, 1.791759469228055, 23, 3.1780538303479458, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '非常有年代和历史沉淀感的一家酒店，我呢，怀着对参观历史建筑一份期望入住此酒店。但', '非常有年代和历史沉淀感的一家酒店，我呢，怀着对参观历史建