INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a8be3c98b09417658bc', '酒店不错，续住了，周边景点很多', '["https://dimg04.c-ctrip.com/images/0233p12000hkn1qf15507_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000hkmi42jDACF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235112000hkmoejv83F0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-03', '花园双床房', '双床房', '家庭亲子', 15, 2.772588722239781, 0, 0.0, 7, 2.079441541679836, 4, '["周边配套", "整体满意度"]'::jsonb, '周边配套', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '酒店不错，续住了，周边景点很多', '酒店不错，续住了，周边景点很多', '2025-01-03', 5, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a8be3c98b09417658bd', '因为订的酒店出了点问题，改住的花园酒店，老牌五星级，服务不错，设施比较老旧，没有现代感，厕所和浴室只能关一边门。但是酒店整体感觉还是很不错的，瀑布孩子很喜欢，每次回酒店都要去逛一逛，双床拼起来很大，我们两大两小睡着还挺宽敞，有儿童洗漱用品。最惊喜的是，酒店送来的生日蛋糕！', '["https://dimg04.c-ctrip.com/images/0235212000f3krnuu5C09_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000f3kmmhxB425_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236a12000f3kb954E523_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-12', '花园双床房', '双床房', '家庭亲子', 136, 4.919980925828125, 1, 0.6931471805599453, 10, 2.3978952727983707, 8, '["房间设施", "整体满意度", "前台服务"]'::jsonb, '房间设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '因为订的酒店出了点问题，改住的花园酒店，老牌五星级，服务不错，设施比较老旧，没有', '因为订的酒店出了点问题，改住的花园酒店，老牌五星级，服务不错，设施比较老旧，没有现代感，厕所和浴室只能关一边门。但是酒店整体感觉还是很不错的，瀑布孩子很喜欢，每次回酒店都要去逛一逛，双床拼起来很大，我们两大两小睡着还挺宽敞，有儿童洗漱用品。最惊喜的是，酒店送来的生日蛋糕！', '2024-08-12', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a97e3c98b09417658be', '酒店酒店位置离地铁机场都很近，高峰期间能订到距离不远交通也方便的酒店确实不容易，这家酒店相当不错，很感谢前台灵灵邀请我们过来行政酒廊，这里的服务让我感觉到非常的温馨，一进来Aimee就很热情的跟我们打招呼，Echo也非常热情的询问我们要喝些什么，需不需要中式点心，非常的热情，Kitty笑容也很甜美，这是我们旅行中最难忘的体验之一，强烈推荐任何人', '["https://dimg04.c-ctrip.com/images/0234g12000f3gnqik66BC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231112000f3gus2uF90C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231512000f3gz63s1DB4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-12', '花园双床房', '双床房', '其他', 173, 5.159055299214529, 1, 0.6931471805599453, 2, 1.0986122886681098, 9, '["前台服务", "交通便利性", "整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店酒店位置离地铁机场都很近，高峰期间能订到距离不远交通也方便的酒店确实不容易，', '酒店酒店位置离地铁机场都很近，高峰期间能订到距离不远交通也方便的酒店确实不容易，这家酒店相当不错，很感谢前台灵灵邀请我们过来行政酒廊，这里的服务让我感觉到非常的温馨，一进来Aimee就很热情的跟我们打招呼，Echo也非常热情的询问我们要喝些什么，需不需要中式点心，非常的热情，Kitty笑容也很甜美，这是我们旅行中最难忘的体验之一，强烈推荐任何人', '2024-08-12', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a97e3c98b09417658bf', '酒店早餐的瀑布景色怡人，吃早餐心情好。酒店在老城区，交通方便，边上就是地铁站。附近美食多，只觉得卫生间做成封闭式就更好了。', '["https://dimg04.c-ctrip.com/images/0235y12000g1dl8au025B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-10-08', '花园双床房', '双床房', '家庭亲子', 61, 4.127134385045092, 0, 0.0, 8, 2.19722457733622, 7, '["餐饮设施", "交通便利性", "周边配套"]'::jsonb, '餐饮设施', '交通便利性', '周边配套', '未知酒店', '未知地点', '匿名', '酒店早餐的瀑布景色怡人，吃早餐心情好。酒店在老城区，交通方便，边上就是地铁站。附', '酒店早餐的瀑布景色怡人，吃早餐心情好。酒店在老城区，交通方便，边上就是地铁站。附近美食多，只觉得卫生间做成封闭式就更好了。', '2024-10-08', 4, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a97e3c98b09417658c0', '酒店非常漂亮，地理位置佳，作为名副其实的五星级酒店，服务和设施非常棒，映入眼帘的大堂红楼梦主题的烫金壁画彰显酒店地位和独特气质。特别感谢前台办理入住的小姐姐，服务态度极其专业，笑容温暖人心，见我带娃出行，为我们升了套房，特别棒，而且早餐有三个餐厅可以选择，自助餐吃得比较多，尝试了三楼粤式茶点早餐，米其林级的餐饮品质让人印象深刻，孩子非常喜欢。早餐后逛了漂亮的后花园，喂了锦鲤，逛了园子，看了瀑布，美不胜收。这次广州之行花园酒店给我留下了特别棒的印象，下次来广州我一定继续选择入住花园酒店。', '["https://dimg04.c-ctrip.com/images/0234112000f3fhbvo9F2C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000f3fmd3zBFE7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236r12000f3fh2ru5DF4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000f3fejc1CFD6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000f3fnrksADBB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-12', '花园双床房', '双床房', '家庭亲子', 245, 5.5053315359323625, 0, 0.0, 2, 1.0986122886681098, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店非常漂亮，地理位置佳，作为名副其实的五星级酒店，服务和设施非常棒，映入眼帘的', '酒店非常漂亮，地理位置佳，作为名副其实的五星级酒店，服务和设施非常棒，映入眼帘的大堂红楼梦主题的烫金壁画彰显酒店地位和独特气质。特别感谢前台办理入住的小姐姐，服务态度极其专业，笑容温暖人心，见我带娃出行，为我们升了套房，特别棒，而且早餐有三个餐厅可以选择，自助餐吃得比较多，尝试了三楼粤式茶点早餐，米其林级的餐饮品质让人印象深刻，孩子非常喜欢。早餐后逛了漂亮的后花园，喂了锦鲤，逛了园子，看了瀑布，美不胜收。这次广州之行花园酒店给我留下了特别棒的印象，下次来广州我一定继续选择入住花园酒店。', '2024-08-12', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a97e3c98b09417658c1', '花园真的名副其实 挺适合带老人孩子 我妈妈非常喜欢 四楼还有一个博物馆 花园很大非常漂亮 拍照很好看 一楼进门就不停的哇 看点评说房间有味道 入住后并没有 可能回南天会有一点吧 房间总体很大格局设置很好 美中不足的是硬件设施略微陈旧 床边的音响感觉很古老 现在都用蓝牙了 淋浴花洒有点难拧 最不好的就是马桶了 不是智能马桶倒是无所谓 但是不能连个阻尼都没有 第一次放下马桶圈 嗙好大一声 吓一大跳 然后每一次都要提醒自己小心翼翼 马桶的抽水按键对美甲很不友好 而且需要按好久才能抽干净 太旧了 前台入住的时候可以主动多一些酒店的介绍就好了 每个楼层都有一个管家小姐姐 服务很好  入住的时候酒店有个打卡活动 很好的一个活动但是酒店并没有介绍和告知 还是看了小红书才知道的 总体来说很不错 瑕不掩瑜 下次还住', '["https://dimg04.c-ctrip.com/images/0236e12000f0jycmpAF72_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000f0jkj7rA3B9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234712000f0jzxfy55AF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234112000f0jybza1BEA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c12000f0joipt8418_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231412000f0jqya40BF4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234b12000f0k3mve9DD0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235t12000f0jybze315C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230a12000f0jxl6v9CB7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-08-05', '红棉双床套房', '套房', '家庭亲子', 353, 5.869296913133774, 0, 0.0, 8, 2.19722457733622, 9, '["房间设施", "整体满意度", "前台服务"]'::jsonb, '房间设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '花园真的名副其实 挺适合带老人孩子 我妈妈非常喜欢 四楼还有一个博物馆 花园很大', '花园真的名副其实 挺适合带老人孩子 我妈妈非常喜欢 四楼还有一个博物馆 花园很大非常漂亮 拍照很好看 一楼进门就不停的哇 看点评说房间有味道 入住后并没有 可能回南天会有一点吧 房间总体很大格局设置很好 美中不足的是硬件设施略微陈旧 床边的音响感觉很古老 现在都用蓝牙了 淋浴花洒有点难拧 最不好的就是马桶了 不是智能马桶倒是无所谓 但是不能连个阻尼都没有 第一次放下马桶圈 嗙好大一声 吓一大跳 然后每一次都要提醒自己小心翼翼 马桶的抽水按键对美甲很不友好 而且需要按好久才能抽干净 太旧了 前台入住的时候可以主动多一些酒店的介绍就好了 每个楼层都有一个管家小姐姐 服务很好  入住的时候酒店有个打卡活动 很好的一个活动但是酒店并没有介绍和告知 还是看了小红书才知道的 总体来说很不错 瑕不掩瑜 下次还住', '2024-08-05', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a97e3c98b09417658c2', '补充一下，一定要在瀑布餐厅用个餐，这种感觉真的只有这一家。我女儿很喜欢花园，以后还会下榻，他说这里比长隆睡得好、吃的好。唯独就是不要睡在修路那一侧，真的真的很吵，是你睡不着的那种。泳池的蓝色水很好玩。感受一下吧', '["https://dimg04.c-ctrip.com/images/0233r12000f4uld0s7A6B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f12000f4uc9qcC0F0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000f4uinly2335_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-08-15', '红棉大床套房', '套房', '家庭亲子', 105, 4.663439094112067, 0, 0.0, 20, 3.044522437723423, 8, '["餐饮设施", "安静程度", "公共设施"]'::jsonb, '餐饮设施', '安静程度', '公共设施', '未知酒店', '未知地点', '匿名', '补充一下，一定要在瀑布餐厅用个餐，这种感觉真的只有这一家。我女儿很喜欢花园，以后', '补充一下，一定要在瀑布餐厅用个餐，这种感觉真的只有这一家。我女儿很喜欢花园，以后还会下榻，他说这里比长隆睡得好、吃的好。唯独就是不要睡在修路那一侧，真的真的很吵，是你睡不着的那种。泳池的蓝色水很好玩。感受一下吧', '2024-08-15', 4, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a97e3c98b09417658c3', '花园酒店很美，酒店内好多外国人，但各种服务都很到位，因为楼下在施工，但一点不影响入住的体验，Mandy的服务也很好，总体来说比较满意的一次入住～', '["https://dimg04.c-ctrip.com/images/0236412000j88068nD932_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230m12000j87m92l0C7A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-21', '花园大床房', '大床房', '情侣出游', 72, 4.290459441148391, 0, 0.0, 15, 2.772588722239781, 6, '["整体满意度", "前台服务", "安静程度"]'::jsonb, '整体满意度', '前台服务', '安静程度', '未知酒店', '未知地点', '匿名', '花园酒店很美，酒店内好多外国人，但各种服务都很到位，因为楼下在施工，但一点不影响', '花园酒店很美，酒店内好多外国人，但各种服务都很到位，因为楼下在施工，但一点不影响入住的体验，Mandy的服务也很好，总体来说比较满意的一次入住～', '2025-03-21', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a97e3c98b09417658c4', '生日布置敷衍就算了(用的塑料花瓣铺床上），卫生还差，床上居然有包装残物。', '["https://dimg04.c-ctrip.com/images/0236a12000gpqkc1899CB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235b12000gppvmkm5444_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.0, 1, '2024-11-16', '红棉大床套房', '套房', '独自旅行', 36, 3.610917912644224, 10, 2.3978952727983707, 2, 1.0986122886681098, 7, '["卫生状况", "客房服务"]'::jsonb, '卫生状况', '客房服务', NULL, '未知酒店', '未知地点', '匿名', '生日布置敷衍就算了(用的塑料花瓣铺床上），卫生还差，床上居然有包装残物。', '生日布置敷衍就算了(用的塑料花瓣铺床上），卫生还差，床上居然有包装残物。', '2024-11-16', 1, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a97e3c98b09417658c5', '环境不错，大堂金碧辉煌，有那种old money的感觉，那个人造瀑布呢，就是个噱头，个人觉得近看有点山寨，酒店博物馆值得一看，登记就行不用门票。位置也不错，去永庆坊、北京路还都挺方便的，唯一吐槽的是早餐，就是比较适合外国人（土耳其）人的菜式，如果你想尝试广式餐点的建议还是去对面的广州酒家或者酒店里面就有个餐厅。', '["https://dimg04.c-ctrip.com/images/0231g12000f4msf570702_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x12000f4mglxkF706_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234l12000f4m3ac45349_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-08-15', '花园大床房', '大床房', '家庭亲子', 156, 5.056245805348308, 0, 0.0, 13, 2.6390573296152584, 8, '["周边配套", "餐饮设施", "整体满意度"]'::jsonb, '周边配套', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '环境不错，大堂金碧辉煌，有那种old money的感觉，那个人造瀑布呢，就是个噱', '环境不错，大堂金碧辉煌，有那种old money的感觉，那个人造瀑布呢，就是个噱头，个人觉得近看有点山寨，酒店博物馆值得一看，登记就行不用门票。位置也不错，去永庆坊、北京路还都挺方便的，唯一吐槽的是早餐，就是比较适合外国人（土耳其）人的菜式，如果你想尝试广式餐点的建议还是去对面的广州酒家或者酒店里面就有个餐厅。', '2024-08-15', 4, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a97e3c98b09417658c6', '酒店很豪华很漂亮，可是入住体验却很差，是最后两天客房服务人员优秀的服务态度给加了分。
入住体验差是因为下订单时就要求无烟房，办入住时还特意强调因为带孩子需要安静一点的房间，谁知第一天早上7点就给外面施工地方打地的声音吵醒，以为是不巧碰到，谁知第二天又是这样，本来游玩就很累还每天一早就吵醒太难受了，只能立马投诉要求换房，（虽然这种施工不是酒店发生的行为但是酒店人员肯定知道那些房间外面施工会影响到客户，而且是在特意要求需要安静环境下还这样安排就不合理了）
虽然客房服务态度很好立马就安排了，但是定房时酒店显示楼层应该是26-28层，入住就只给安排了14层，换房后更低了就12楼，一进门客厅就是一股烟味，这下好了，特意要求避开的两点全给我安排上了??????
原来想着这次入住体验太糟糕了，在这种不爽的情绪下却碰到了一个超级细心的客服服务人员，不但给孩子拿来了儿童洗漱用品（第一天和第二天根本没有孩子的洗漱用品）还贴心的把化妆品全部摆列整齐，更是知道房间有烟味后把空气净化器搬来消除味道，更感动的是还手写了留言，为这糟糕的心情增添了很多美好。
所以如果要评价的话酒店给50分，客房人员给100分。', '["https://dimg04.c-ctrip.com/images/0232k12000f2enk46BDFC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234912000f2dy1fqEF20_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-08-10', '红棉大床套房', '套房', '家庭亲子', 497, 6.210600077024653, 3, 1.3862943611198906, 6, 1.9459101490553128, 9, '["客房服务", "安静程度", "卫生状况"]'::jsonb, '客房服务', '安静程度', '卫生状况', '未知酒店', '未知地点', '匿名', '酒店很豪华很漂亮，可是入住体验却很差，是最后两天客房服务人员优秀的服务态度给加了', '酒店很豪华很漂亮，可是入住体验却很差，是最后两天客房服务人员优秀的服务态度给加了分。
入住体验差是因为下订单时就要求无烟房，办入住时还特意强调因为带孩子需要安静一点的房间，谁知第一天早上7点就给外面施工地方打地的声音吵醒，以为是不巧碰到，谁知第二天又是这样，本来游玩就很累还每天一早就吵醒太难受了，只能立马投诉要求换房，（虽然这种施工不是酒店发生的行为但是酒店人员肯定知道那些房间外面施工会影响到客户，而且是在特意要求需要安静环境下还这样安排就不合理了）
虽然客房服务态度很好立马就安排了，但是定房时酒店显示楼层应该是26-28层，入住就只给安排了14层，换房后更低了就12楼，一进门客厅就是一股烟味，这下好了，特意要求避开的两点全给我安排上了??????
原来想着这次入住体验太糟糕了，在这种不爽的情绪下却碰到了一个超级细心的客服服务人员，不但给孩子拿来了儿童洗漱用品（第一天和第二天根本没有孩子的洗漱用品）还贴心的把化妆品全部摆列整齐，更是知道房间有烟味后把空气净化器搬来消除味道，更感动的是还手写了留言，为这糟糕的心情增添了很多美好。
所以如果要评价的话酒店给50分，客房人员给100分。', '2024-08-10', 4, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027a97e3c98b09417658c7', '酒店给升级了套房，小孩很高兴，缺点是套房没有浴缸，不能尽情地耍了，酒店泳池没有儿童的设施，小孩玩了一会就没兴趣了，30楼的行政酒廊不错，酒店瀑布餐厅挺有特色，还有很多大锦鲤', '["https://dimg04.c-ctrip.com/images/0234j12000f9y8lvxD1A8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230x12000f9xqxud6A29_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-08-27', '花园双床房', '双床房', '家庭亲子', 86, 4.465908118654584, 0, 0.0, 1, 0.6931471805599453, 7, '["房间设施", "公共设施", "餐饮设施"]'::jsonb, '房间设施', '公共设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店给升级了套房，小孩很高兴，缺点是套房没有浴缸，不能尽情地耍了，酒店泳池没有儿', '酒店给升级了套房，小孩很高兴，缺点是套房没有浴缸，不能尽情地耍了，酒店泳池没有儿童的设施，小孩玩了一会就没兴趣了，30楼的行政酒廊不错，酒店瀑布餐厅挺有特色，还有很多大锦鲤', '2024-08-27', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aa2e3c98b09417658c8', '第一次入住广州花园酒店，选择完全正确。大堂很宏伟，金碧辉煌。前台ECHO小姐姐看我们路途劳累，特意送了行政酒廊的下午茶，很贴心。我们在行政酒廊又遇到了一位印度小姐姐Carrie和Berrle,没有想到又是以为的惊喜，印度小姐姐中文很棒，一直在了解我们的需求，还邀请我们第二天下午可以继续去行政酒廊喝下午茶，还为我们预约了时间。因为我们有事去不了，感觉有点遗憾，喜欢花园酒店，下次我们会再次入住。再次感谢印度美女姐姐的热情服务。', '["https://dimg04.c-ctrip.com/images/0234u12000f0yumn28922_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h12000f0yujbwF8FE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235d12000f0yusngC63D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000f0yuuv23454_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230812000f0yuq1z2640_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232w12000f0yuq29EF38_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-06', '红棉双床套房', '套房', '家庭亲子', 213, 5.365976015021851, 1, 0.6931471805599453, 1, 0.6931471805599453, 9, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '第一次入住广州花园酒店，选择完全正确。大堂很宏伟，金碧辉煌。前台ECHO小姐姐看', '第一次入住广州花园酒店，选择完全正确。大堂很宏伟，金碧辉煌。前台ECHO小姐姐看我们路途劳累，特意送了行政酒廊的下午茶，很贴心。我们在行政酒廊又遇到了一位印度小姐姐Carrie和Berrle,没有想到又是以为的惊喜，印度小姐姐中文很棒，一直在了解我们的需求，还邀请我们第二天下午可以继续去行政酒廊喝下午茶，还为我们预约了时间。因为我们有事去不了，感觉有点遗憾，喜欢花园酒店，下次我们会再次入住。再次感谢印度美女姐姐的热情服务。', '2024-08-06', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aa2e3c98b09417658c9', '中秋假期带家人出行，入住了美丽的花园酒店，得到了用心用情的照顾，全家人都十分满意。特此感谢根据我们需求帮我们办理入住的Cassie女士，感谢带我们参观游览26个打卡点的金牌导览Hohn先生，感谢为我们送上手写信件和中秋月饼的客房房口部迎送岗 Adeline女士。你们的专业非常值得称颂，下次来广州，一定会再次入住的。也祝你们中秋节快乐！', '["https://dimg04.c-ctrip.com/images/0230712000flteukz90C0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-17', '花园大床房', '大床房', '家庭亲子', 168, 5.1298987149230735, 0, 0.0, 6, 1.9459101490553128, 9, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '中秋假期带家人出行，入住了美丽的花园酒店，得到了用心用情的照顾，全家人都十分满意', '中秋假期带家人出行，入住了美丽的花园酒店，得到了用心用情的照顾，全家人都十分满意。特此感谢根据我们需求帮我们办理入住的Cassie女士，感谢带我们参观游览26个打卡点的金牌导览Hohn先生，感谢为我们送上手写信件和中秋月饼的客房房口部迎送岗 Adeline女士。你们的专业非常值得称颂，下次来广州，一定会再次入住的。也祝你们中秋节快乐！', '2024-09-17', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aa2e3c98b09417658ca', '房间64平，宽敞。服务热情周到。环境优美，装修大气，作为白金五星酒店性价比很高，出行方便，只要不去长隆玩，离广州所有玩的地方，像永庆坊，陈家祠，海心沙，沙面，北京路，圣心大教堂，珠江夜游都不远。', '["https://dimg04.c-ctrip.com/images/0231812000f321zrj345B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231u12000f31ztkxC777_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233b12000f31tqn496AD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-11', '红棉大床套房', '套房', '家庭亲子', 97, 4.584967478670572, 0, 0.0, 2, 1.0986122886681098, 9, '["性价比", "交通便利性", "整体满意度"]'::jsonb, '性价比', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '房间64平，宽敞。服务热情周到。环境优美，装修大气，作为白金五星酒店性价比很高，', '房间64平，宽敞。服务热情周到。环境优美，装修大气，作为白金五星酒店性价比很高，出行方便，只要不去长隆玩，离广州所有玩的地方，像永庆坊，陈家祠，海心沙，沙面，北京路，圣心大教堂，珠江夜游都不远。', '2024-08-11', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aa2e3c98b09417658cb', '酒店已经三十九年了，但很多硬件设施还是很好，工作人员的服务也很棒！特别30楼行政酒廊的Carrie，Kitty和Rose，服务热情周到，赞！', '["https://dimg04.c-ctrip.com/images/0230u12000flu74q9C853_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232712000flu1ni4E4BD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231612000flu4wrz6A58_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-17', '花园大床房', '大床房', '家庭亲子', 70, 4.262679877041316, 0, 0.0, 5, 1.791759469228055, 8, '["房间设施", "前台服务"]'::jsonb, '房间设施', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '酒店已经三十九年了，但很多硬件设施还是很好，工作人员的服务也很棒！特别30楼行政', '酒店已经三十九年了，但很多硬件设施还是很好，工作人员的服务也很棒！特别30楼行政酒廊的Carrie，Kitty和Rose，服务热情周到，赞！', '2024-09-17', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aa2e3c98b09417658cc', '酒店很有历史厚重感，大堂很气派也维护地很好，房间偏小但是重新装修后挺温馨，泳池桑拿冰水池等等设施很完善，床品枕头都很舒服合适，墙面柜子个别地方有点点发霉的地方可以加强维护，另外还有漂亮小花园和酒店博物馆整个入住的体验都很愉快休闲放松。', '["https://dimg04.c-ctrip.com/images/0235v12000f056674CEEE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231912000f053jox6DF3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231z12000f050bk57E57_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2024-08-04', '花园双床房', '双床房', '朋友出游', 117, 4.770684624465665, 1, 0.6931471805599453, 5, 1.791759469228055, 9, '["公共设施", "整体满意度", "房间设施"]'::jsonb, '公共设施', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '酒店很有历史厚重感，大堂很气派也维护地很好，房间偏小但是重新装修后挺温馨，泳池桑', '酒店很有历史厚重感，大堂很气派也维护地很好，房间偏小但是重新装修后挺温馨，泳池桑拿冰水池等等设施很完善，床品枕头都很舒服合适，墙面柜子个别地方有点点发霉的地方可以加强维护，另外还有漂亮小花园和酒店博物馆整个入住的体验都很愉快休闲放松。', '2024-08-04', 4, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aa2e3c98b09417658cd', '对花园品牌从未失望，广州花园酒店更是意外之惊喜！感谢贴心客房管家，热情的客房清扫员，和一楼瀑布餐厅，30F酒廊的优质餐食，下次来广州依然会选择花园酒店！', '["https://dimg04.c-ctrip.com/images/0230712000fi6ypjr45BB_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231012000fi6zxe7BEBD_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2024-09-11', '花园大床房', '大床房', '商务出差', 76, 4.343805421853684, 0, 0.0, 11, 2.4849066497880004, 7, '["客房服务", "餐饮设施", "整体满意度"]'::jsonb, '客房服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '对花园品牌从未失望，广州花园酒店更是意外之惊喜！感谢贴心客房管家，热情的客房清扫', '对花园品牌从未失望，广州花园酒店更是意外之惊喜！感谢贴心客房管家，热情的客房清扫员，和一楼瀑布餐厅，30F酒廊的优质餐食，下次来广州依然会选择花园酒店！', '2024-09-11', 5, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aa2e3c98b09417658ce', '第一次入住传说中的白金六星级酒店，其他两家都住过；环境确实被惊艳到了，房间也很棒，行政酒廊的早餐非常棒，只是早餐厅服务员的态度就很牵强了，没有亲和力的服务，站门口对客人也是不理不睬的，这点是有待提升的', '["https://dimg04.c-ctrip.com/images/0232x12000gbemno4D118_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230s12000gbecnmc18F2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000gbemno69D25_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-25', '花园大床房', '大床房', '商务出差', 100, 4.61512051684126, 0, 0.0, 82, 4.418840607796598, 8, '["整体满意度", "餐饮设施", "前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '第一次入住传说中的白金六星级酒店，其他两家都住过；环境确实被惊艳到了，房间也很棒', '第一次入住传说中的白金六星级酒店，其他两家都住过；环境确实被惊艳到了，房间也很棒，行政酒廊的早餐非常棒，只是早餐厅服务员的态度就很牵强了，没有亲和力的服务，站门口对客人也是不理不睬的，这点是有待提升的', '2024-10-25', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aa2e3c98b09417658cf', '特别好的酒店，每一个人都很专业。服务热情周到。房间干净整洁。娃的玩具临走之前落在了酒店房间里，打电话给酒店，也给找到并且快递到家了。酒店地理位置也很好。', '["https://dimg04.c-ctrip.com/images/02316224x8wa2umuaD4D7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02316224x8wa2x5bp0601_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233h224x8wa2m638D455_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02361224x8wa2sw4x6935_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-08', '花园双床房', '双床房', '家庭亲子', 76, 4.343805421853684, 0, 0.0, 2, 1.0986122886681098, 8, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '特别好的酒店，每一个人都很专业。服务热情周到。房间干净整洁。娃的玩具临走之前落在', '特别好的酒店，每一个人都很专业。服务热情周到。房间干净整洁。娃的玩具临走之前落在了酒店房间里，打电话给酒店，也给找到并且快递到家了。酒店地理位置也很好。', '2024-09-08', 5, '整体满意度');
