INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aade3c98b09417658d8', '服务很好，免费升级了套房，行政酒廊的Kan Chan, Deepa, Beryle, Mira都很nice，下午茶和欢乐时光都很丰盛，整体入住体验非常好！值得推荐！', '["https://dimg04.c-ctrip.com/images/0232u12000fa0v4h78BB6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230k12000fa17gciCA16_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236e12000fa15k7y2B38_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-28', '花园双床房', '双床房', '家庭亲子', 82, 4.418840607796598, 0, 0.0, 1, 0.6931471805599453, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '服务很好，免费升级了套房，行政酒廊的Kan Chan, Deepa, Beryl', '服务很好，免费升级了套房，行政酒廊的Kan Chan, Deepa, Beryle, Mira都很nice，下午茶和欢乐时光都很丰盛，整体入住体验非常好！值得推荐！', '2024-08-28', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aade3c98b09417658d9', '这次在酒店的入住体验真的格外舒心，前台 Betty 和礼宾 Roy 提供的优质服务给我
 前台 Betty办理入住手续时，她的操作既熟练又迅速，每一个环节都耐心细致地为我们讲解，还主动告知酒店的各项设施以及相关注意事项，让初来乍到的我们对接下来的住宿安排一清二楚。而且，无论我们提出什么样的问题，她总是能第一时间给予专业且周到的解答，那种耐心和热情自始至终都没有丝毫减退，哪怕是面对酒店入住高峰期，她也能有条不紊地应对每一位宾客，服务质量丝毫不打折扣，真的特别让人钦佩。还有礼宾 Roy，他同样给我们留下了深刻的印象。刚到酒店门口，Roy 就热情地迎了上来，主动帮忙拿行李，动作十分麻利又小心翼翼，让人感觉自己的物品被妥善照顾着。在引导我们前往房间的途中，他还一路热情地介绍酒店的特色之处，让这段路程变得轻松又愉快。不仅如此，在我们后续出行需要帮忙叫车或者咨询周边景点信息时，Roy 也总是能迅速给出实用的建议，帮忙安排得妥妥当当。
 谢谢 Betty 和 Roy 用他们的专业素养、热情态度以及无微不至的服务，为我们打造了一次难忘的酒店入住体验，也期待下次再来。', '["https://dimg04.c-ctrip.com/images/0230e12000jehevkx783A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000jehtj558655_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-29', '花园大床房', '大床房', '朋友出游', 482, 6.180016653652572, 0, 0.0, 2, 1.0986122886681098, 9, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '这次在酒店的入住体验真的格外舒心，前台 Betty 和礼宾 Roy 提供的优质服', '这次在酒店的入住体验真的格外舒心，前台 Betty 和礼宾 Roy 提供的优质服务给我
