 谢谢 Betty 和 Roy 用他们的专业素养、热情态度以及无微不至的服务，为我们打造了一次难忘的酒店入住体验，也期待下次再来。', '2025-03-29', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aade3c98b09417658da', '酒店金卡会员升级了房间，前台Arrie和Wnnie服务挺好的。行政酒廊Carrie和Echo很热情，欢乐时光比下午茶多东西吃，房间确实是有一些年份了，很干净，但也有一些老化的部分。总的来说还是很不错的，下次再来。美中不足的是入住时没人帮忙拿行李，五星级酒店不应该啊！', '["https://dimg04.c-ctrip.com/images/0236312000exoioif04FA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000exojurg18A3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000exo90xg2A69_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000exo2ohbAA0C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-07-29', '花园大床房', '大床房', '情侣出游', 133, 4.897839799950911, 0, 0.0, 8, 2.19722457733622, 7, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店金卡会员升级了房间，前台Arrie和Wnnie服务挺好的。行政酒廊Carri', '酒店金卡会员升级了房间，前台Arrie和Wnnie服务挺好的。行政酒廊Carrie和Echo很热情，欢乐时光比下午茶多东西吃，房间确实是有一些年份了，很干净，但也有一些老化的部分。总的来说还是很不错的，下次再来。美中不足的是入住时没人帮忙拿行李，五星级酒店不应该啊！', '2024-07-29', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ab9e3c98b09417658dc', '四年前住过这次来广州还是入住了这家酒店，本来是会员可以升房间的但是十一期间房间很紧张没有给我升房间，但是送了3天的早餐，特别要说一下客房服务员刘美丽很贴心因为天气热每天都会给我们补充足够的饮用水。', '["https://dimg04.c-ctrip.com/images/0235w12000g0czwnnD114_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d12000g0dbdfr19AF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230k12000g0d38teAD76_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i12000g0d4zf6300D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-06', '花园双床房', '双床房', '家庭亲子', 98, 4.59511985013459, 0, 0.0, 8, 2.19722457733622, 8, '["客房服务", "餐饮设施"]'::jsonb, '客房服务', '餐饮设施', NULL, '未知酒店', '未知地点', '匿名', '四年前住过这次来广州还是入住了这家酒店，本来是会员可以升房间的但是十一期间房间很', '四年前住过这次来广州还是入住了这家酒店，本来是会员可以升房间的但是十一期间房间很紧张没有给我升房间，但是送了3天的早餐，特别要说一下客房服务员刘美丽很贴心因为天气热每天都会给我们补充足够的饮用水。', '2024-10-06', 5, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ab9e3c98b09417658dd', '历史悠久的酒店，深藏着文化底蕴。门面气派，环境一流，服务也特别好，很热情粤韵大床套房很新很干净，住了很舒服。', '["https://dimg04.c-ctrip.com/images/0234h12000g1jcm2t14BE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000g1jjmmb3EF5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230s12000g1jit7e1624_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231512000g1j9h0s3223_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231g12000g1j0wep06C8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000g1jayedC4ED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-08', '花园双床房', '双床房', '家庭亲子', 54, 4.007333185232471, 0, 0.0, 3, 1.3862943611198906, 6, '["整体满意度", "房间设施", "卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况', '未知酒店', '未知地点', '匿名', '历史悠久的酒店，深藏着文化底蕴。门面气派，环境一流，服务也特别好，很热情粤韵大床', '历史悠久的酒店，深藏着文化底蕴。门面气派，环境一流，服务也特别好，很热情粤韵大床套房很新很干净，住了很舒服。', '2024-10-08', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ab9e3c98b09417658de', '这次来广州听取老婆意见试试老牌五星酒店，从进酒店开始礼宾到服务员都很热情礼貌，太nice了房间是一厅一房特别的舒适。这次入住真的是我来广州住的最舒服的一次，酒店本身就是一个可以逛和参观的地方，它的底蕴真的是其他酒店无法比拟的。', '["https://dimg04.c-ctrip.com/images/0234i12000exgcemkC897_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000exfkbztB6D3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236g12000exfzfqx1270_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-28', '花园大床房', '大床房', '家庭亲子', 113, 4.736198448394496, 0, 0.0, 6, 1.9459101490553128, 7, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '这次来广州听取老婆意见试试老牌五星酒店，从进酒店开始礼宾到服务员都很热情礼貌，太', '这次来广州听取老婆意见试试老牌五星酒店，从进酒店开始礼宾到服务员都很热情礼貌，太nice了房间是一厅一房特别的舒适。这次入住真的是我来广州住的最舒服的一次，酒店本身就是一个可以逛和参观的地方，它的底蕴真的是其他酒店无法比拟的。', '2024-07-28', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ab9e3c98b09417658df', '酒店处于市中心  交通便利  打车方便  门口就是地铁环境非常优美  到处都是好闻的香味  酒店管理非常到位  服务热情周到  房间床品非常舒适  房间设施唯一不足是卫浴半开放  洗澡要跨进浴缸  和厕所的门是公用移门  使用起来有点尴尬  酒店早餐非常丰盛  品种很多  酒店内也有几个特色餐厅  看上去也不错', '["https://dimg04.c-ctrip.com/images/0234w12000eysjcn508F7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-08-01', '花园双床房', '双床房', '朋友出游', 156, 5.056245805348308, 0, 0.0, 6, 1.9459101490553128, 8, '["交通便利性", "房间设施", "餐饮设施"]'::jsonb, '交通便利性', '房间设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店处于市中心  交通便利  打车方便  门口就是地铁环境非常优美  到处都是好', '酒店处于市中心  交通便利  打车方便  门口就是地铁环境非常优美  到处都是好闻的香味  酒店管理非常到位  服务热情周到  房间床品非常舒适  房间设施唯一不足是卫浴半开放  洗澡要跨进浴缸  和厕所的门是公用移门  使用起来有点尴尬  酒店早餐非常丰盛  品种很多  酒店内也有几个特色餐厅  看上去也不错', '2024-08-01', 4, '交通便利性');
