INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ab9e3c98b09417658e3', '订的红棉套房套餐。优惠较多，性价比极好。3楼桃园餐厅菜品不错，但价格有些贵，但套餐送了些餐券儿，还好。服务人员很nice。', '["https://dimg04.c-ctrip.com/images/0234212000g04etw24DF0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p12000g046zst3B38_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235212000g041a6d4F0A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-06', '红棉大床套房', '套房', '家庭亲子', 61, 4.127134385045092, 0, 0.0, 15, 2.772588722239781, 7, '["性价比", "餐饮设施", "前台服务"]'::jsonb, '性价比', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '订的红棉套房套餐。优惠较多，性价比极好。3楼桃园餐厅菜品不错，但价格有些贵，但套', '订的红棉套房套餐。优惠较多，性价比极好。3楼桃园餐厅菜品不错，但价格有些贵，但套餐送了些餐券儿，还好。服务人员很nice。', '2024-10-06', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ab9e3c98b09417658e4', '酒店位置不好，周围吃饭选择很多，所有工作人员都很热情，会主动打招呼，礼宾部Eva服务很好很热情。酒店早餐也不错，品质很高，房间是有点老了，但是维护的还不错', '["https://dimg04.c-ctrip.com/images/0232s12000jlsgb8p7051_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-06', '花园双床房', '双床房', '家庭亲子', 77, 4.356708826689592, 0, 0.0, 31, 3.4657359027997265, 8, '["周边配套", "前台服务", "餐饮设施"]'::jsonb, '周边配套', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店位置不好，周围吃饭选择很多，所有工作人员都很热情，会主动打招呼，礼宾部Eva', '酒店位置不好，周围吃饭选择很多，所有工作人员都很热情，会主动打招呼，礼宾部Eva服务很好很热情。酒店早餐也不错，品质很高，房间是有点老了，但是维护的还不错', '2025-04-06', 5, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ab9e3c98b09417658e5', '这次是我第二次入住花园酒店，体验依旧无与伦比，必须给个满分好评！ 从前台办理入住起，前厅部副经理吴灵伶就展现出了非凡的专业与贴心。得知同行有老人家，她精心为我安排了安静舒适的房间，让我们一进酒店就感受到满满的关怀。到了房间，楼层服务员Adan更是细致入微，了解情况后迅速为我额外准备了几块地巾，以防老人滑倒，这一举动真的太暖心了。酒店房间设施设备一如既往地齐全，各种用品一应俱全，完全满足了我们的需求，每次入住都有喜出望外之感。 可没想到，3月25日晚上，家人生病了，情况紧急。酒店值班经理Yannis得知后，毫不犹豫地忙前忙后，安排人员带着老人家前往医院，一路悉心照料。礼宾部的罗家俊也不辞辛劳，专门陪同到医院，帮忙处理各种事务。他们的热情与担当，让慌乱中的我有了十足的安全感。真心感谢花园酒店的吴灵伶、Yannis、Adan、罗家俊，因为你们，让我在这异乡感受到了家一般的温暖，下次出行，我依然只选花园酒店！', '["https://dimg04.c-ctrip.com/images/0231y12000jc7inpfF826_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000jc80buj7CAB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000jc8bhea6CB4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-26', '花园大床房', '大床房', '家庭亲子', 406, 6.008813185442595, 0, 0.0, 1, 0.6931471805599453, 10, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '这次是我第二次入住花园酒店，体验依旧无与伦比，必须给个满分好评！ 从前台办理入住', '这次是我第二次入住花园酒店，体验依旧无与伦比，必须给个满分好评！ 从前台办理入住起，前厅部副经理吴灵伶就展现出了非凡的专业与贴心。得知同行有老人家，她精心为我安排了安静舒适的房间，让我们一进酒店就感受到满满的关怀。到了房间，楼层服务员Adan更是细致入微，了解情况后迅速为我额外准备了几块地巾，以防老人滑倒，这一举动真的太暖心了。酒店房间设施设备一如既往地齐全，各种用品一应俱全，完全满足了我们的需求，每次入住都有喜出望外之感。 可没想到，3月25日晚上，家人生病了，情况紧急。酒店值班经理Yannis得知后，毫不犹豫地忙前忙后，安排人员带着老人家前往医院，一路悉心照料。礼宾部的罗家俊也不辞辛劳，专门陪同到医院，帮忙处理各种事务。他们的热情与担当，让慌乱中的我有了十足的安全感。真心感谢花园酒店的吴灵伶、Yannis、Adan、罗家俊，因为你们，让我在这异乡感受到了家一般的温暖，下次出行，我依然只选花园酒店！', '2025-03-26', 5, '前台服务');
