INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ac3e3c98b09417658e9', '临时决定入住，酒店免费升档成套房。服务、环境和自助早餐一流，顺带参观了四楼的酒店博物馆，非常值得看看，了解下广州众多著名酒店的前世今生。', '["https://dimg04.c-ctrip.com/images/0230e12000ffxbttsED28_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000ffxrto9DCD0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232i12000ffxk9hh4A54_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-07', '花园大床房', '大床房', '家庭亲子', 68, 4.23410650459726, 0, 0.0, 1, 0.6931471805599453, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '临时决定入住，酒店免费升档成套房。服务、环境和自助早餐一流，顺带参观了四楼的酒店', '临时决定入住，酒店免费升档成套房。服务、环境和自助早餐一流，顺带参观了四楼的酒店博物馆，非常值得看看，了解下广州众多著名酒店的前世今生。', '2024-09-07', 5, '整体满意度');
