INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ac3e3c98b09417658ee', '楼层过道和房间内部都不错，干净整洁。早餐是套餐制的，可以品尝地道广州早茶。接待的小姐姐和小哥哥们也都非常热情。', '["https://dimg04.c-ctrip.com/images/0235y12000gicbryvD589_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000gicpfpr793D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000gicd8383366_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-05', '花园大床房', '大床房', '商务出差', 55, 4.02535169073515, 0, 0.0, 1, 0.6931471805599453, 7, '["卫生状况", "餐饮设施", "前台服务"]'::jsonb, '卫生状况', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '楼层过道和房间内部都不错，干净整洁。早餐是套餐制的，可以品尝地道广州早茶。接待的', '楼层过道和房间内部都不错，干净整洁。早餐是套餐制的，可以品尝地道广州早茶。接待的小姐姐和小哥哥们也都非常热情。', '2024-11-05', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ad3e3c98b09417658f0', '房间紧凑吧还好，住老酒店看重的是服务品质，晚上九点多到店，问前台可以免费升级房型吗？前台说客房已满了抱歉，可以送你四份早餐吗（我们是两个大人两个小孩），这突来的惊喜确实把我惊了一跳（早餐单价是2百多一点一位），第二天孩子要游泳，致电前台可以免费延时退房吗？前台回答可以的这边给你延时到两点退房，随后叫客房服务员拿件小孩浴衣，结果不仅拿了浴衣还拿了小孩的洗发水和沐浴露，这服务真是太贴心了，特别说一下这个酒店的游泳池很棒，泳池边的三个救生员让你能安心把孩子放在那里玩，还有免费的饮品喝哦。酒店门口随时有出租车等候，出行太方便，下次还会入住。', '["https://dimg04.c-ctrip.com/images/0232e12000ewdl1uvEF5F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-07-25', '花园双床房', '双床房', '家庭亲子', 269, 5.598421958998375, 1, 0.6931471805599453, 13, 2.6390573296152584, 9, '["前台服务", "客房服务", "公共设施"]'::jsonb, '前台服务', '客房服务', '公共设施', '未知酒店', '未知地点', '匿名', '房间紧凑吧还好，住老酒店看重的是服务品质，晚上九点多到店，问前台可以免费升级房型', '房间紧凑吧还好，住老酒店看重的是服务品质，晚上九点多到店，问前台可以免费升级房型吗？前台说客房已满了抱歉，可以送你四份早餐吗（我们是两个大人两个小孩），这突来的惊喜确实把我惊了一跳（早餐单价是2百多一点一位），第二天孩子要游泳，致电前台可以免费延时退房吗？前台回答可以的这边给你延时到两点退房，随后叫客房服务员拿件小孩浴衣，结果不仅拿了浴衣还拿了小孩的洗发水和沐浴露，这服务真是太贴心了，特别说一下这个酒店的游泳池很棒，泳池边的三个救生员让你能安心把孩子放在那里玩，还有免费的饮品喝哦。酒店门口随时有出租车等候，出行太方便，下次还会入住。', '2024-07-25', 4, '前台服务');
