INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ad3e3c98b09417658f3', '????花园?行政酒廊特别表扬Echo,beryle,kanchan', '["https://dimg04.c-ctrip.com/images/0233w12000ggxxn9j89DA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233w12000ggy8p6tDB8B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-03', '城央绿意双床房', '双床房', '商务出差', 34, 3.555348061489413, 0, 0.0, 2, 1.0986122886681098, 2, '["餐饮设施", "前台服务"]'::jsonb, '餐饮设施', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '????花园?行政酒廊特别表扬Echo,beryle,kanchan', '????花园?行政酒廊特别表扬Echo,beryle,kanchan', '2024-11-03', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ad3e3c98b09417658f4', '老牌的五星酒店，虽然年代久远，却维护得很好，只是房间狭小，设施陈旧，房间空间矮，这个没办法，硬伤，但是酒店环境挺好，楼上的博物馆值得看看。先说入住，没有半个小时也有二十分钟，等得太久了，小姐姐一人送了两只康乃馨表示歉意，这个速度得提高，退房五秒，交卡就走。30楼的旋转早餐厅很好，没有人来人往的嘈杂，比较安静，需要等位但是不久，唯一这里让我不太痛快的就是明明鸡蛋里加的料都是我一个个点的，怎么我后面来排队的老黑就先拿了，留我愣在那，然后厨师又重复一遍我要加的东西给我做好，我去国外好像也没得到太多优待吧，国内还被区别？？那我就干脆专找外籍服务生服务吧，两个貌似印度人的员工态度都很好，耐心的帮我拍照，名字忘记了。最后一点，酒店很贴心的送了一大盘水果，可惜，除了火龙果其他的都酸掉牙，采购部门用点心啊', '["https://dimg04.c-ctrip.com/images/0236112000eulqymb5A9F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231e12000eulcxzfEC04_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233a12000ev060l364BC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000euzw2gy1BAF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236s12000ev06ryu6092_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-07-22', '花园双床房', '双床房', '朋友出游', 349, 5.857933154483459, 0, 0.0, 17, 2.8903717578961645, 8, '["退房/入住效率", "餐饮设施", "整体满意度"]'::jsonb, '退房/入住效率', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '老牌的五星酒店，虽然年代久远，却维护得很好，只是房间狭小，设施陈旧，房间空间矮，', '老牌的五星酒店，虽然年代久远，却维护得很好，只是房间狭小，设施陈旧，房间空间矮，这个没办法，硬伤，但是酒店环境挺好，楼上的博物馆值得看看。先说入住，没有半个小时也有二十分钟，等得太久了，小姐姐一人送了两只康乃馨表示歉意，这个速度得提高，退房五秒，交卡就走。30楼的旋转早餐厅很好，没有人来人往的嘈杂，比较安静，需要等位但是不久，唯一这里让我不太痛快的就是明明鸡蛋里加的料都是我一个个点的，怎么我后面来排队的老黑就先拿了，留我愣在那，然后厨师又重复一遍我要加的东西给我做好，我去国外好像也没得到太多优待吧，国内还被区别？？那我就干脆专找外籍服务生服务吧，两个貌似印度人的员工态度都很好，耐心的帮我拍照，名字忘记了。最后一点，酒店很贴心的送了一大盘水果，可惜，除了火龙果其他的都酸掉牙，采购部门用点心啊', '2024-07-22', 4, '退房/入住效率');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ad3e3c98b09417658f5', '房间整洁干净，有宾至如归的感觉，不愧是老牌五星级酒店，尤其是酒店居然有博物馆，给孩子们提供了参观场所', '["https://dimg04.c-ctrip.com/images/0235c12000fzvwausC405_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000fzvhaqz2C2D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232h12000fzvkrxh6364_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233012000fzw1yx10A9A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-05', '花园大床房', '大床房', '家庭亲子', 50, 3.9318256327243257, 0, 0.0, 10, 2.3978952727983707, 7, '["卫生状况", "整体满意度", "公共设施"]'::jsonb, '卫生状况', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '房间整洁干净，有宾至如归的感觉，不愧是老牌五星级酒店，尤其是酒店居然有博物馆，给', '房间整洁干净，有宾至如归的感觉，不愧是老牌五星级酒店，尤其是酒店居然有博物馆，给孩子们提供了参观场所', '2024-10-05', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ad3e3c98b09417658f6', '这次来广州听取老公意见试试老牌五星酒店，从进酒店开始礼宾到服务员都很热情礼貌，这里要重点谢谢办入住的帅哥Tony 接待热情耐心听我说要新点房间直接就帮我升级粤韵大床房,是我原来订的房型的一倍价格，太nice 了房间是一厅一房特别的舒适。这次入住真的是我来广州住的最舒服的一次，酒店本身就是一个可以逛和参观的地方，它的底蕴真的是其他酒店无法比拟的。', '["https://dimg04.c-ctrip.com/images/0232x12000eunhu8y2C51_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231g12000eune0nwE428_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c12000eune0ny09BF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230u12000eunfpn20965_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236n12000eun6ihvE999_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234412000eung0d87686_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-21', '花园双床房', '双床房', '家庭亲子', 173, 5.159055299214529, 0, 0.0, 4, 1.6094379124341005, 9, '["前台服务", "整体满意度", "房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '这次来广州听取老公意见试试老牌五星酒店，从进酒店开始礼宾到服务员都很热情礼貌，这', '这次来广州听取老公意见试试老牌五星酒店，从进酒店开始礼宾到服务员都很热情礼貌，这里要重点谢谢办入住的帅哥Tony 接待热情耐心听我说要新点房间直接就帮我升级粤韵大床房,是我原来订的房型的一倍价格，太nice 了房间是一厅一房特别的舒适。这次入住真的是我来广州住的最舒服的一次，酒店本身就是一个可以逛和参观的地方，它的底蕴真的是其他酒店无法比拟的。', '2024-07-21', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ad3e3c98b09417658f7', '住了第一晚就开始出疹，痒的要死，一开始没在意，后面越来越厉害，房间也是洗水池脏的要死，房间里设施陈旧，一点都标不起五星酒店的称号，希望大家避雷吧', '["https://dimg04.c-ctrip.com/images/0233d12000fbjju0fF8D3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2024-08-31', '城央绿意双床房', '双床房', '家庭亲子', 72, 4.290459441148391, 0, 0.0, 2, 1.0986122886681098, 8, '["卫生状况", "房间设施", "整体满意度"]'::jsonb, '卫生状况', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '住了第一晚就开始出疹，痒的要死，一开始没在意，后面越来越厉害，房间也是洗水池脏的', '住了第一晚就开始出疹，痒的要死，一开始没在意，后面越来越厉害，房间也是洗水池脏的要死，房间里设施陈旧，一点都标不起五星酒店的称号，希望大家避雷吧', '2024-08-31', 3, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ad3e3c98b09417658f8', '每次去广州首选花园酒店，服务态度好，酒店环境好，尤其是酒店一楼的花园老人孩子都喜欢，交通也十分方便？', '["https://dimg04.c-ctrip.com/images/0201i12000fzstjb5C9CE_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0236s12000fzsaj8o47B6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000fzsb1sbCB16_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000fzs3pb0D764_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-05', '花园双床房', '双床房', '家庭亲子', 50, 3.9318256327243257, 0, 0.0, 1, 0.6931471805599453, 6, '["整体满意度", "交通便利性", "公共设施"]'::jsonb, '整体满意度', '交通便利性', '公共设施', '未知酒店', '未知地点', '匿名', '每次去广州首选花园酒店，服务态度好，酒店环境好，尤其是酒店一楼的花园老人孩子都喜', '每次去广州首选花园酒店，服务态度好，酒店环境好，尤其是酒店一楼的花园老人孩子都喜欢，交通也十分方便？', '2024-10-05', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ad3e3c98b09417658f9', '地道老广州，粤语服务有味道', '["https://dimg04.c-ctrip.com/images/0234812000h7y1d19F9A2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-12-15', '花园双床房', '双床房', '家庭亲子', 13, 2.6390573296152584, 0, 0.0, 68, 4.23410650459726, 4, '["前台服务"]'::jsonb, '前台服务', NULL, NULL, '未知酒店', '未知地点', '匿名', '地道老广州，粤语服务有味道', '地道老广州，粤语服务有味道', '2024-12-15', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ae0e3c98b09417658fa', '服务：Echo,beryle,mira,Cathy非常棒
广州花园酒店设施完善，大堂历史悠久。
大堂非常的富丽堂皇，房间也不错，行政酒廊服务更是没的说，然后广州花园酒店的位置离地铁站也非常的近。然后离北京路，越秀公园，动物园，珠江新城，越秀公园，天河区都挺近的，去广州塔也不远，酒店很棒，尤其要点名表扬酒店三十楼行政酒廊，行政酒廊的小姐姐们，Echo,beryle
,cathy,mira,kitty,gretta,kanchan,她们都非常的贴心，善良，美丽，大方，这次入住体验非常的棒，因为有她们他们每一个小姐姐的笑容都很甜，其中一进来Beryle就热情的接待我们，给我们介绍酒店哪里有好玩好吃的地方，Echo也会非常积极的服务，我们看到什么空的盘子啊都会过来询问我们，然后询问要不要收走。中秋节入住期间，行政酒廊有给我们送了月饼，让我们真情实意的感受到了中秋的氛围。Carrie是一个印度人，他的中文很棒。这都让我们感到非常舒服，你们的服务态度也很好，租个台也很热情，打招呼能感受到30楼的服务意识都很好，看着这一群可爱的小妹妹们的校友，我们用餐的也很开心,我们介绍了酒店的26个打卡点，有博物馆还有后花园的打卡点，因为广州花园酒店有他们，所以过年我也会回来广州花园酒店入住的，希望下次回来入住，还能看见Echo,Carrie,kitty这群小姐姐们
过年见
设施：很棒', '["https://dimg04.c-ctrip.com/images/0236a12000fn0xn783B3A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000fn0w5ej6A07_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000fn0zefy9939_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000fn0ztwxE8D3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000fn0yl6571EC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000fn0x7ij7D24_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000fn0w5en77F3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000fn0yt6qF523_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231112000fn0vtjtCECB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-19', '花园大床房', '大床房', '情侣出游', 590, 6.3818160174060985, 1, 0.6931471805599453, 5, 1.791759469228055, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '服务：Echo,beryle,mira,Cathy非常棒', '服务：Echo,beryle,mira,Cathy非常棒
