INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ae0e3c98b09417658ff', '看了各个平台的评论加上有岭南金的会员卡才来订的酒店，但入住感觉很一般。入住时报了金卡会员号，前台没有任何关于金卡会员的介绍。客房没升级、免费早餐也不提、酒廊礼遇还是在我特意询问后才给了一张一个人的礼遇卡。什么欢迎水果，入住三天毛都没看见。我也是开了眼了！
