INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aeae3c98b0941765906', '花园酒店属罕见的城区花园式酒店，山水园林特别吸舒适，大堂辉煌有特色吸引眼球。借此机会还参观了博物馆了解酒店的历史底蕴。每到一处服务人员都很温柔礼貌，细心体贴。感谢酒店前台Gillian免费升级了红棉大房，还赠送了下午茶，如果房间能见到园林就更好了。下次还是会入住。', '["https://dimg04.c-ctrip.com/images/0234i12000es36dqeD570_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000es38e1iDB24_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230s12000es2zrep9E44_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000es36mek2A8F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000es35ndjC675_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232812000es341tx69BA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235d12000es36rfp2D1F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231f12000es33hq59620_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234i12000es37r6052DE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-14', '花园双床房', '双床房', '家庭亲子', 132, 4.890349128221754, 1, 0.6931471805599453, 10, 2.3978952727983707, 9, '["整体满意度", "前台服务", "景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向', '未知酒店', '未知地点', '匿名', '花园酒店属罕见的城区花园式酒店，山水园林特别吸舒适，大堂辉煌有特色吸引眼球。借此', '花园酒店属罕见的城区花园式酒店，山水园林特别吸舒适，大堂辉煌有特色吸引眼球。借此机会还参观了博物馆了解酒店的历史底蕴。每到一处服务人员都很温柔礼貌，细心体贴。感谢酒店前台Gillian免费升级了红棉大房，还赠送了下午茶，如果房间能见到园林就更好了。下次还是会入住。', '2024-07-14', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aeae3c98b0941765907', '带父母和宝宝休假，房间无烟很安静，但空调口上方的墙壁发霉了没有清理。楼层房间的清洁阿姨和服务人员特别好。桃园馆的早茶的牛奶因为天气热了有点发酸，没有宝宝的餐具提供，而且有一个穿深蓝色西装的**男领班不会收餐盘，上水果时因为桌上有很多宝宝用过的纸巾和空盘子，当着客人的面很为难和不耐烦的叹气，好像不知道怎么处理似的，还需要我主动把一个空盘子递给他拿走才处理好，令人感觉很不舒服，服务意识和水平很低。服务细节需要提高培训。瀑布餐厅和荔湾亭的餐食和服务很满意，宝宝正在好动的年纪，但服务员对宝宝很有耐心，有很高的服务意识，餐食也很新鲜美味。前期打酒店电话预约时感觉接电话的服务人员和餐厅沟通协调不是很好，没有及时帮忙预约餐厅位置。到店后遇到的服务人员总体还不错。', '["https://dimg04.c-ctrip.com/images/0234d12000eudc7dz78F7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231l12000eudeojlE37A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000eudlpjhB58D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-07-20', '花园双床房', '双床房', '家庭亲子', 328, 5.796057750765372, 1, 0.6931471805599453, 18, 2.9444389791664403, 8, '["客房服务", "餐饮设施", "整体满意度"]'::jsonb, '客房服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '带父母和宝宝休假，房间无烟很安静，但空调口上方的墙壁发霉了没有清理。楼层房间的清', '带父母和宝宝休假，房间无烟很安静，但空调口上方的墙壁发霉了没有清理。楼层房间的清洁阿姨和服务人员特别好。桃园馆的早茶的牛奶因为天气热了有点发酸，没有宝宝的餐具提供，而且有一个穿深蓝色西装的**男领班不会收餐盘，上水果时因为桌上有很多宝宝用过的纸巾和空盘子，当着客人的面很为难和不耐烦的叹气，好像不知道怎么处理似的，还需要我主动把一个空盘子递给他拿走才处理好，令人感觉很不舒服，服务意识和水平很低。服务细节需要提高培训。瀑布餐厅和荔湾亭的餐食和服务很满意，宝宝正在好动的年纪，但服务员对宝宝很有耐心，有很高的服务意识，餐食也很新鲜美味。前期打酒店电话预约时感觉接电话的服务人员和餐厅沟通协调不是很好，没有及时帮忙预约餐厅位置。到店后遇到的服务人员总体还不错。', '2024-07-20', 4, '客房服务');
