INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aeae3c98b0941765909', '好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好', '["https://dimg04.c-ctrip.com/images/0203h12000fl9iiu99657_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0204w12000fl9jpsg19AC_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0201z12000fl9itbd4AB5_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0230u12000fl8xbj64E67_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000fl98iie1204_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000fl94cl56CA6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-16', '花园大床房', '大床房', '独自旅行', 56, 4.04305126783455, 0, 0.0, 66, 4.204692619390966, 0.0, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好', '好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好', '2024-09-16', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aeae3c98b094176590a', '太满意了，性价比极高，服务巨好。体验感极佳，行政酒廊的小姐姐（名字如图）又漂亮又温柔，客房，硬件都非常优秀！住了2晚换了希尔顿，后悔中……', '["https://dimg04.c-ctrip.com/images/0236912000faf6zecE545_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233z12000faf6y0q1ED9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-28', '花园双床房', '双床房', '家庭亲子', 69, 4.248495242049359, 0, 0.0, 2, 1.0986122886681098, 8, '["性价比", "整体满意度", "前台服务"]'::jsonb, '性价比', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '太满意了，性价比极高，服务巨好。体验感极佳，行政酒廊的小姐姐（名字如图）又漂亮又', '太满意了，性价比极高，服务巨好。体验感极佳，行政酒廊的小姐姐（名字如图）又漂亮又温柔，客房，硬件都非常优秀！住了2晚换了希尔顿，后悔中……', '2024-08-28', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aeae3c98b094176590b', '广州花园酒店，一家有着历史文化感的酒店，一家来了后会让你惊艳的酒店，一家需要专业讲解的酒店，一步一景，从金碧辉煌的大堂壁画到瀑布餐厅，后花园，到酒店自带的博物馆，都给人无限惊喜。床品很舒适，睡的很舒服，酒店服务很周到，给我们送了早餐和下午茶。特别感谢三十楼旋转餐厅的CARRIE和大堂的HENRY（带我们一路参观讲解酒店的历史文化景致，孩子很喜欢听）。总之，很值得入住的一家老牌酒店，适合亲子家庭出游入住，下次来还会选择。', '["https://dimg04.c-ctrip.com/images/0232h12000eqmxhqz46DB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000eqmxtym28BE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236m12000eqmxg1rBB08_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231i12000eqmxqgu99D4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p12000eqmy7dvFBF2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000eqmxumnB71D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000eqmy7ge6D9F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-10', '花园大床房', '大床房', '家庭亲子', 211, 5.356586274672012, 0, 0.0, 5, 1.791759469228055, 9, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '广州花园酒店，一家有着历史文化感的酒店，一家来了后会让你惊艳的酒店，一家需要专业', '广州花园酒店，一家有着历史文化感的酒店，一家来了后会让你惊艳的酒店，一家需要专业讲解的酒店，一步一景，从金碧辉煌的大堂壁画到瀑布餐厅，后花园，到酒店自带的博物馆，都给人无限惊喜。床品很舒适，睡的很舒服，酒店服务很周到，给我们送了早餐和下午茶。特别感谢三十楼旋转餐厅的CARRIE和大堂的HENRY（带我们一路参观讲解酒店的历史文化景致，孩子很喜欢听）。总之，很值得入住的一家老牌酒店，适合亲子家庭出游入住，下次来还会选择。', '2024-07-10', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aeae3c98b094176590c', '偶然花园暑假推出特惠套餐，时隔几年再次带妹来打卡，非常惊喜，推出打卡点活动，参观酒店博物馆，晚上在荔湾亭任点任食茶点，早上望着瀑布品尝丰富早餐，一系列活动令行程丰富多彩，宝宝乐而忘返', '["https://dimg04.c-ctrip.com/images/0232w12000eupf8vxA8F5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234a12000eupd8y9013C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236s12000eupfw0q3E1B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-21', '花园双床房', '双床房', '家庭亲子', 91, 4.5217885770490405, 0, 0.0, 16, 2.833213344056216, 8, '["餐饮设施", "整体满意度", "公共设施"]'::jsonb, '餐饮设施', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '偶然花园暑假推出特惠套餐，时隔几年再次带妹来打卡，非常惊喜，推出打卡点活动，参观', '偶然花园暑假推出特惠套餐，时隔几年再次带妹来打卡，非常惊喜，推出打卡点活动，参观酒店博物馆，晚上在荔湾亭任点任食茶点，早上望着瀑布品尝丰富早餐，一系列活动令行程丰富多彩，宝宝乐而忘返', '2024-07-21', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027aeae3c98b094176590d', '服务我真的是想打超五星的评价，太贴心了，非常友好。
