INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027af5e3c98b094176590e', '广州的老品牌高档酒店，商务出差，来到这里下榻。总体的感觉还是挺不错的，大堂富丽堂皇，房间干净清新，只是房内的设施稍显陈旧，客房大楼没有负一负二层，得到另外一个地下停车场停车，其他都挺好的。', '["https://dimg04.c-ctrip.com/images/0235012000esfoxpf02B0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234y12000esfoni2C76C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232w12000esfomcgB461_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-15', '花园大床房', '大床房', '商务出差', 94, 4.553876891600541, 0, 0.0, 48, 3.8918202981106265, 7, '["房间设施", "整体满意度", "卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '广州的老品牌高档酒店，商务出差，来到这里下榻。总体的感觉还是挺不错的，大堂富丽堂', '广州的老品牌高档酒店，商务出差，来到这里下榻。总体的感觉还是挺不错的，大堂富丽堂皇，房间干净清新，只是房内的设施稍显陈旧，客房大楼没有负一负二层，得到另外一个地下停车场停车，其他都挺好的。', '2024-07-15', 5, '房间设施');
