INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027af5e3c98b0941765914', '昨天交通很便利，门口就有地铁。服务非常周到，每层都有服务员。购买的套餐在楼顶的旋转餐厅吃早餐感觉很好。后面有一个很大的很美的花园。', '["https://dimg04.c-ctrip.com/images/0230b12000g2r8limD094_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236k12000g2r5qs046E3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233z12000g2rvqu3C73D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-10', '花园大床房', '大床房', '其他', 65, 4.189654742026425, 0, 0.0, 9, 2.302585092994046, 7, '["交通便利性", "餐饮设施", "周边配套"]'::jsonb, '交通便利性', '餐饮设施', '周边配套', '未知酒店', '未知地点', '匿名', '昨天交通很便利，门口就有地铁。服务非常周到，每层都有服务员。购买的套餐在楼顶的旋', '昨天交通很便利，门口就有地铁。服务非常周到，每层都有服务员。购买的套餐在楼顶的旋转餐厅吃早餐感觉很好。后面有一个很大的很美的花园。', '2024-10-10', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027af5e3c98b0941765915', '?? 广州花园酒店——一场无与伦比的入住体验 ??
朋友们，我刚从广州花园酒店回来，心情还沉浸在那无比美妙的时光里！必须要跟大家分享一下我这次超赞的入住经历！
当我踏入广州花园酒店的那一刻，就仿佛走进了一个充满魅力和故事的世界。酒店那悠久的历史气息扑面而来，每一处细节都仿佛在诉说着过去的辉煌，让我心生敬畏和好奇。
不得不提的是酒店的博物馆，这简直是一个隐藏的宝藏！在那里，我仿佛穿越了时空，领略到了酒店一路走来的风风雨雨，以及背后蕴含的深厚文化底蕴。那些珍贵的展品、精彩的介绍，让我对这座酒店有了更深层次的认识和理解。
而行政酒廊更是给我带来了惊喜不断！舒适优雅的环境，丰富多样的饮品和小吃，每一口都是极致的享受。在这里，我可以放松身心，尽情地享受属于自己的惬意时光。特别是主管carrie，美丽的印度小姐姐（周三还有来自尼泊尔的Kanchan小姐姐），提供了非常好的服务，happy hour的氛围很好，人也不多，顶楼可以看到广州老的CBD环市东的风景
但最让我感到温暖和满意的，还是酒店工作人员那无与伦比的热情态度。从进门的那一刻起，每一个微笑、每一句问候，都让我感受到了家一般的亲切。他们总是能在第一时间满足我的需求，无论是解答疑问还是提供帮助，都表现得专业而贴心。
还有酒店那美丽的花园！漫步其中，花香四溢，绿树成荫，仿佛置身于人间仙境。在这里，我可以暂时忘却外界的喧嚣和烦恼，尽情地享受大自然的恩赐。
总之，在广州花园酒店的这次入住体验，无论是硬件设施还是软件服务，都堪称完美。我真的非常喜欢这里，已经迫不及待地想要再次回来！强烈推荐给大家，相信你们也一定会爱上这个充满魅力的地方！', '["https://dimg04.c-ctrip.com/images/0233p12000eq7xlwm4875_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000eq827m03F7E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234n12000eq8249fB2FE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-09', '花园大床房', '大床房', '独自旅行', 711, 6.568077911411976, 0, 0.0, 1, 0.6931471805599453, 9, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '?? 广州花园酒店——一场无与伦比的入住体验 ??', '?? 广州花园酒店——一场无与伦比的入住体验 ??
