INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027af5e3c98b0941765916', '房间有点小，床品不错，还贴心地提供了荞麦枕。服务一如既往地好。', '["https://dimg04.c-ctrip.com/images/0232f12000gb6zjwhD03C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231f12000gb66npi1A30_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000gb6t43c9B00_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-10-25', '城央绿意大床房', '大床房', '商务出差', 31, 3.4657359027997265, 0, 0.0, 9, 2.302585092994046, 6, '["房间设施", "客房服务"]'::jsonb, '房间设施', '客房服务', NULL, '未知酒店', '未知地点', '匿名', '房间有点小，床品不错，还贴心地提供了荞麦枕。服务一如既往地好。', '房间有点小，床品不错，还贴心地提供了荞麦枕。服务一如既往地好。', '2024-10-25', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027af5e3c98b0941765917', '进门的香水味有点浓，外宾比较多，工作人员服务还不错，房间卫生也不错，隔音我觉得没有其他评价说的那么差，位置也方便，就是开窗需要工作人员来开比较麻烦。', '["https://dimg04.c-ctrip.com/images/0235o12000f3wiv4g3E88_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-08-13', '红棉双床套房', '套房', '家庭亲子', 74, 4.31748811353631, 0, 0.0, 4, 1.6094379124341005, 7, '["前台服务", "卫生状况", "安静程度"]'::jsonb, '前台服务', '卫生状况', '安静程度', '未知酒店', '未知地点', '匿名', '进门的香水味有点浓，外宾比较多，工作人员服务还不错，房间卫生也不错，隔音我觉得没', '进门的香水味有点浓，外宾比较多，工作人员服务还不错，房间卫生也不错，隔音我觉得没有其他评价说的那么差，位置也方便，就是开窗需要工作人员来开比较麻烦。', '2024-08-13', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b02e3c98b0941765918', '感觉这酒店是给歪果仁开的
服务很一般（清扫服务员除外）
台灯坏了，打电话半天没人接，接了态度也不好，来人换灯进门不打招呼换完带有怨气的走了
硬件设施不错，估计这也是评上金榜的原因
但是房间一般，泳池一般，服务员高高在上。。。
