INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b02e3c98b0941765919', '花园酒店虽然经常光顾荔湾亭餐饮，住房还是头一次。酒店服务的确不错，无论进大堂门口，还是礼宾部，再进服务台前的礼仪小姐到服务台的登记，都是笑脸相迎，中途叫外卖在礼宾部那里收货，站开关门的小姐姐看到我行动不太方便主动帮忙提上客房，特别的感动。21楼兰英客房服务员每天不辞辛劳的打扫卫生，每每出去游玩回来之后，都有宾至如归的感觉。十天的旅游行程转眼就过去，到了退房时间，一大早21楼朱小姐的迎送、礼宾部刘先生帮忙把行李拿到礼宾部暂存，酒店无论是环境还是接待，都是一流的服务质量，下次有机会还是我首选的住宿地方。设施虽陈旧一点，其他都很好。', '["https://dimg04.c-ctrip.com/images/0205v12000f9jyltb78CF_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0233112000f9ivqwp4043_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236d12000f9ive4b9421_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000f9j0j0d7904_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234412000f9jmykhE367_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000f9j1unjF141_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-27', '花园双床房', '双床房', '家庭亲子', 266, 5.58724865840025, 0, 0.0, 3, 1.3862943611198906, 9, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '花园酒店虽然经常光顾荔湾亭餐饮，住房还是头一次。酒店服务的确不错，无论进大堂门口', '花园酒店虽然经常光顾荔湾亭餐饮，住房还是头一次。酒店服务的确不错，无论进大堂门口，还是礼宾部，再进服务台前的礼仪小姐到服务台的登记，都是笑脸相迎，中途叫外卖在礼宾部那里收货，站开关门的小姐姐看到我行动不太方便主动帮忙提上客房，特别的感动。21楼兰英客房服务员每天不辞辛劳的打扫卫生，每每出去游玩回来之后，都有宾至如归的感觉。十天的旅游行程转眼就过去，到了退房时间，一大早21楼朱小姐的迎送、礼宾部刘先生帮忙把行李拿到礼宾部暂存，酒店无论是环境还是接待，都是一流的服务质量，下次有机会还是我首选的住宿地方。设施虽陈旧一点，其他都很好。', '2024-08-27', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b02e3c98b094176591a', '升级住了红棉双床房，房间很大，送的迎宾点心很精致。酒店的环境非常好，玩携程铂金的行政酒廊在30楼旋转餐厅，早餐非常丰富，下午有点心水果和饮料。行政酒廊的Carrie是印度人，中文讲得很好，也非常热情。', '["https://dimg04.c-ctrip.com/images/0232t224x8vufbnce2813_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x224x8vuegeyf3D9E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234b224x8vuen1a2FABE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230s224x8vuep9bn4FC1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231r224x8vued9qr8061_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230h224x8vuecxd03E63_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234b224x8vudnycr89FF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d224x8vueaib31500_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-05', '花园双床房', '双床房', '家庭亲子', 100, 4.61512051684126, 1, 0.6931471805599453, 1, 0.6931471805599453, 8, '["餐饮设施", "整体满意度", "房间设施"]'::jsonb, '餐饮设施', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '升级住了红棉双床房，房间很大，送的迎宾点心很精致。酒店的环境非常好，玩携程铂金的', '升级住了红棉双床房，房间很大，送的迎宾点心很精致。酒店的环境非常好，玩携程铂金的行政酒廊在30楼旋转餐厅，早餐非常丰富，下午有点心水果和饮料。行政酒廊的Carrie是印度人，中文讲得很好，也非常热情。', '2024-08-05', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b02e3c98b094176591b', '各方面都不错，有很多打卡点！大堂壁画和中国风的文化装饰值得体验！更值得惊艳的是藏在酒店里的博物馆！令本土广州人回忆了一把！', '["https://dimg04.c-ctrip.com/images/0230r12000fa87mhq07BB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236412000fa87t0w1FC2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236q12000fa87vbcF154_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-28', '花园双床房', '双床房', '朋友出游', 61, 4.127134385045092, 0, 0.0, 4, 1.6094379124341005, 7, '["公共设施", "整体满意度"]'::jsonb, '公共设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '各方面都不错，有很多打卡点！大堂壁画和中国风的文化装饰值得体验！更值得惊艳的是藏', '各方面都不错，有很多打卡点！大堂壁画和中国风的文化装饰值得体验！更值得惊艳的是藏在酒店里的博物馆！令本土广州人回忆了一把！', '2024-08-28', 5, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b02e3c98b094176591c', '十一假期在花园酒店度过了两个晚上，我们一家都觉得很满意，以后有机会还会继续入住。', '["https://dimg04.c-ctrip.com/images/0230512000fyhn74iD916_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000fyiqmme15CD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000fyivqajF1F7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236612000fyian0sBEF4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000fyirh7fA5C1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000fyhn74m92FC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-04', '城央绿意双床房', '双床房', '家庭亲子', 40, 3.713572066704308, 0, 0.0, 19, 2.995732273553991, 5, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '十一假期在花园酒店度过了两个晚上，我们一家都觉得很满意，以后有机会还会继续入住。', '十一假期在花园酒店度过了两个晚上，我们一家都觉得很满意，以后有机会还会继续入住。', '2024-10-04', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b02e3c98b094176591d', '服务满分，酒店活动送的小羊很可爱，自带的花园很漂亮，早餐也不错。掉了一根电源线在酒店马上联系我快递过来，体验感很棒。', '["https://dimg04.c-ctrip.com/images/0231l12000fc4xnph9088_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230s12000fc4sdj84089_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000fc51yo33BEF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000fc52rnx3E65_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-01', '红棉双床套房', '套房', '朋友出游', 58, 4.07753744390572, 0, 0.0, 12, 2.5649493574615367, 8, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '服务满分，酒店活动送的小羊很可爱，自带的花园很漂亮，早餐也不错。掉了一根电源线在', '服务满分，酒店活动送的小羊很可爱，自带的花园很漂亮，早餐也不错。掉了一根电源线在酒店马上联系我快递过来，体验感很棒。', '2024-09-01', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b02e3c98b094176591e', '房间很干净不错，床非常柔软舒适，整个酒店的人员服务非常到位（点名echo哦！），不愧是白金五星酒店，感觉服务人员比宾客还要多！', '["https://dimg04.c-ctrip.com/images/0230x12000f8x73tqDCE9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a12000f8x8eid6BF8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000f8x3a0yAE0F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234912000f8xadqwD2D8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000f8x9q0b6EEE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-25', '花园大床房', '大床房', '情侣出游', 63, 4.158883083359672, 0, 0.0, 13, 2.6390573296152584, 7, '["整体满意度", "房间设施", "卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况', '未知酒店', '未知地点', '匿名', '房间很干净不错，床非常柔软舒适，整个酒店的人员服务非常到位（点名echo哦！），', '房间很干净不错，床非常柔软舒适，整个酒店的人员服务非常到位（点名echo哦！），不愧是白金五星酒店，感觉服务人员比宾客还要多！', '2024-08-25', 5, '整体满意度');
