INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b02e3c98b0941765920', '酒店公共设施装修的很好，酒店工作人员非常礼貌、周到??，连按电梯都有专门服务，我们准备 中午十二点退房时，航司短信提示延误 2 个小时，酒店特意安排我们可以延迟退房，这个太贴心了??????。但是缺点还是要说的，客房内部装修有点老，希望酒店能够将客房内部装修再提升下，以后再来还会选择入住。', '["https://dimg04.c-ctrip.com/images/0235t12000en2x7fp4962_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231j12000en36zfx31F4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231c12000en2xglqBEB6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-07-01', '花园双床房', '双床房', '家庭亲子', 145, 4.983606621708336, 2, 1.0986122886681098, 10, 2.3978952727983707, 8, '["前台服务", "公共设施", "房间设施"]'::jsonb, '前台服务', '公共设施', '房间设施', '未知酒店', '未知地点', '匿名', '酒店公共设施装修的很好，酒店工作人员非常礼貌、周到??，连按电梯都有专门服务，我', '酒店公共设施装修的很好，酒店工作人员非常礼貌、周到??，连按电梯都有专门服务，我们准备 中午十二点退房时，航司短信提示延误 2 个小时，酒店特意安排我们可以延迟退房，这个太贴心了??????。但是缺点还是要说的，客房内部装修有点老，希望酒店能够将客房内部装修再提升下，以后再来还会选择入住。', '2024-07-01', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b02e3c98b0941765921', '酒店大堂富丽堂皇，服务宾至如归，有人主动帮忙提行李，开门，连电梯口也有服务员帮忙按电梯，前台的小姐姐isabella不仅人漂亮热情服务周到，而且还帮我升级了房间，太开心啦！以后过来旅游还会住这家酒店的。', '["https://dimg04.c-ctrip.com/images/0233t12000erfil4v9C0C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000erfh7lr543E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234g12000erfeob6EA21_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-12', '花园大床房', '大床房', '独自旅行', 101, 4.624972813284271, 0, 0.0, 13, 2.6390573296152584, 9, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '酒店大堂富丽堂皇，服务宾至如归，有人主动帮忙提行李，开门，连电梯口也有服务员帮忙', '酒店大堂富丽堂皇，服务宾至如归，有人主动帮忙提行李，开门，连电梯口也有服务员帮忙按电梯，前台的小姐姐isabella不仅人漂亮热情服务周到，而且还帮我升级了房间，太开心啦！以后过来旅游还会住这家酒店的。', '2024-07-12', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b0de3c98b0941765922', '前台小姐姐Viria人超nice，看到小朋友免费升级了房间还赠送了小朋友的早餐，房间也很干净整洁大气，花园酒店博物馆也很有意思，酒店充满中国传统文化和西方文化元素的完美融合，金光闪闪的太豪了，还有很多好吃的餐厅，很棒！', '["https://dimg04.c-ctrip.com/images/0230r12000emp86zr8427_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233112000emp794a7E92_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232k12000emp8ig8B659_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000emp003p49B2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000emp4axfF0A7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000emp86zt6068_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-06-30', '花园大床房', '大床房', '家庭亲子', 109, 4.700480365792417, 0, 0.0, 5, 1.791759469228055, 9, '["前台服务", "整体满意度", "卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '前台小姐姐Viria人超nice，看到小朋友免费升级了房间还赠送了小朋友的早餐，', '前台小姐姐Viria人超nice，看到小朋友免费升级了房间还赠送了小朋友的早餐，房间也很干净整洁大气，花园酒店博物馆也很有意思，酒店充满中国传统文化和西方文化元素的完美融合，金光闪闪的太豪了，还有很多好吃的餐厅，很棒！', '2024-06-30', 5, '前台服务');
