INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b0de3c98b0941765924', '3楼的旋转餐厅是亮点，每次出差我都住花园酒店，接待都是外籍加英文服务 非常国际化，老牌广州高端酒店，周边餐馆也很多', '["https://dimg04.c-ctrip.com/images/0232q224x8w7b7busA518_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d224x8w78d33j0CDB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-03', '花园大床房', '大床房', '商务出差', 57, 4.060443010546419, 0, 0.0, 46, 3.8501476017100575, 7, '["餐饮设施", "前台服务", "周边配套"]'::jsonb, '餐饮设施', '前台服务', '周边配套', '未知酒店', '未知地点', '匿名', '3楼的旋转餐厅是亮点，每次出差我都住花园酒店，接待都是外籍加英文服务 非常国际化', '3楼的旋转餐厅是亮点，每次出差我都住花园酒店，接待都是外籍加英文服务 非常国际化，老牌广州高端酒店，周边餐馆也很多', '2024-09-03', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b0de3c98b0941765925', '这次入住广州花园酒店体验超棒！必须夸夸前台的Rem。从踏入酒店的那一刻起，Rem就热情相迎，脸上洋溢着真诚的笑容，瞬间驱散了旅途的疲惫。办理入住时，他业务非常熟练，快速又高效地处理好了各项手续，还耐心解答我各种问题，给出游玩和用餐建议。Rem用专业与热忱诠释优质服务，让我有宾至如归之感，下次还选广州花园酒店 ，也期待再遇Rem ！', '["https://dimg04.c-ctrip.com/images/0233e12000j7rmks94254_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-21', '红棉大床套房', '套房', '情侣出游', 166, 5.117993812416755, 0, 0.0, 3, 1.3862943611198906, 9, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '这次入住广州花园酒店体验超棒！必须夸夸前台的Rem。从踏入酒店的那一刻起，Rem', '这次入住广州花园酒店体验超棒！必须夸夸前台的Rem。从踏入酒店的那一刻起，Rem就热情相迎，脸上洋溢着真诚的笑容，瞬间驱散了旅途的疲惫。办理入住时，他业务非常熟练，快速又高效地处理好了各项手续，还耐心解答我各种问题，给出游玩和用餐建议。Rem用专业与热忱诠释优质服务，让我有宾至如归之感，下次还选广州花园酒店 ，也期待再遇Rem ！', '2025-03-21', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b0de3c98b0941765926', '房间非常干净。特别是前台小姐姐吴灵玲的服务非常令我感到满意??，让我体会到宾至如归的感觉。给她点个赞！', '["https://dimg04.c-ctrip.com/images/0231512000fn5m8c67212_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-19', '花园大床房', '大床房', '商务出差', 51, 3.951243718581428, 0, 0.0, 1, 0.6931471805599453, 7, '["前台服务", "卫生状况"]'::jsonb, '前台服务', '卫生状况', NULL, '未知酒店', '未知地点', '匿名', '房间非常干净。特别是前台小姐姐吴灵玲的服务非常令我感到满意??，让我体会到宾至如', '房间非常干净。特别是前台小姐姐吴灵玲的服务非常令我感到满意??，让我体会到宾至如归的感觉。给她点个赞！', '2024-09-19', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b0de3c98b0941765927', '之前看评价，说有什么霉味，心中有些许忐忑，结果到达第一天，踏进酒店的第一步就消除了所有顾虑，前台工作人员Vann（不知道名字是否正确？）帮忙升级了两间房，房间非常漂亮舒适，设施也很齐全，房间收拾的非常精致干净，工作人员也很友好，几乎每层楼都有工作人员帮忙按电梯，入住非常满意！后来因为航班取消，因为有老人，跟酒店商量，原房续住，工作人员很快速地帮忙协调解决，非常感谢！酒店的后花园环境很好，就是蚊子有点生猛，哈哈??', '["https://dimg04.c-ctrip.com/images/0232112000ekpgsi58683_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231612000ekph1tm6E6C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000ekpgsi714F7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000ekpgcapE923_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000ekpdmvl4626_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235o12000ekph2h89CA1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233z12000ekpdmvn2AAB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-06-25', '花园双床房', '双床房', '家庭亲子', 208, 5.342334251964811, 0, 0.0, 1, 0.6931471805599453, 9, '["前台服务", "整体满意度", "卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '之前看评价，说有什么霉味，心中有些许忐忑，结果到达第一天，踏进酒店的第一步就消除', '之前看评价，说有什么霉味，心中有些许忐忑，结果到达第一天，踏进酒店的第一步就消除了所有顾虑，前台工作人员Vann（不知道名字是否正确？）帮忙升级了两间房，房间非常漂亮舒适，设施也很齐全，房间收拾的非常精致干净，工作人员也很友好，几乎每层楼都有工作人员帮忙按电梯，入住非常满意！后来因为航班取消，因为有老人，跟酒店商量，原房续住，工作人员很快速地帮忙协调解决，非常感谢！酒店的后花园环境很好，就是蚊子有点生猛，哈哈??', '2024-06-25', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b0de3c98b0941765928', '环境：酒店就在地铁口附近，很方便。酒店外部环境和内部装修陈列很讲究的。酒店外被绿色的植物包围和点缀，自然和谐；酒店内部随处可见的艺术品和讲究的装修设计，更让我对这家酒店有了新的认识。
设施：虽然开业很久，但是维护很好，根本不像其他老酒店一样，用陈旧的设施和老气装修来体现酒店“年代”和“经典”。各种设施设备配套很完善，不过还是有一点意外房间客厅电视屏幕有问题，希望及时检查维修；房间衣柜门开关的凹槽位置太锋利了，很容易划破手。
服务：从大堂的迎宾，到电梯口的员工，让这份服务从进入酒店就开始了，感觉无处不在。但是，好像去早了没房间，规定必须两点入住，无论是节假日还是工作日，去早了就要被 upsell ，虽然没多少钱，但是好像别人替我已经做好了选择。已经有点累了，还是加钱升级了，入住后才看到别人的会员金卡原来可以免费升级。
其他：早餐选择比较多，旋转餐厅景色也很好。
总的来说我很建议外地来广州的朋友去体验一下，感受来说比万豪希尔顿凯悦不一样，纯住宿角度来说也比白天鹅更推荐。', '["https://dimg04.c-ctrip.com/images/0232312000ekudkvk5E46_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235o12000eku8yjgF0C4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236912000eku4txn1F84_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230812000ekub8wyA9D7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235412000eku9ge3E2D9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000ekudapd2DFA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232n12000eku2mtq5422_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000eku9o6g75EB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2024-06-26', '花园大床房', '大床房', '独自旅行', 439, 6.0867747269123065, 0, 0.0, 11, 2.4849066497880004, 9, '["交通便利性", "房间设施", "整体满意度"]'::jsonb, '交通便利性', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '环境：酒店就在地铁口附近，很方便。酒店外部环境和内部装修陈列很讲究的。酒店外被绿', '环境：酒店就在地铁口附近，很方便。酒店外部环境和内部装修陈列很讲究的。酒店外被绿色的植物包围和点缀，自然和谐；酒店内部随处可见的艺术品和讲究的装修设计，更让我对这家酒店有了新的认识。
设施：虽然开业很久，但是维护很好，根本不像其他老酒店一样，用陈旧的设施和老气装修来体现酒店“年代”和“经典”。各种设施设备配套很完善，不过还是有一点意外房间客厅电视屏幕有问题，希望及时检查维修；房间衣柜门开关的凹槽位置太锋利了，很容易划破手。
服务：从大堂的迎宾，到电梯口的员工，让这份服务从进入酒店就开始了，感觉无处不在。但是，好像去早了没房间，规定必须两点入住，无论是节假日还是工作日，去早了就要被 upsell ，虽然没多少钱，但是好像别人替我已经做好了选择。已经有点累了，还是加钱升级了，入住后才看到别人的会员金卡原来可以免费升级。
其他：早餐选择比较多，旋转餐厅景色也很好。
总的来说我很建议外地来广州的朋友去体验一下，感受来说比万豪希尔顿凯悦不一样，纯住宿角度来说也比白天鹅更推荐。', '2024-06-26', 4, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b0de3c98b0941765929', '家庭出游，订的套餐，服务非常好，提前打电话准备好房间，提醒天气情况。早餐偏西式，选择在瀑布餐厅，餐后后花园散散步，很惬意。', '["https://dimg04.c-ctrip.com/images/0231s12000f7i587dBE7C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230z12000f7itxdi9846_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233n12000f7ivra5FBA2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-22', '花园双床房', '双床房', '家庭亲子', 61, 4.127134385045092, 0, 0.0, 2, 1.0986122886681098, 7, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '家庭出游，订的套餐，服务非常好，提前打电话准备好房间，提醒天气情况。早餐偏西式，', '家庭出游，订的套餐，服务非常好，提前打电话准备好房间，提醒天气情况。早餐偏西式，选择在瀑布餐厅，餐后后花园散散步，很惬意。', '2024-08-22', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b0de3c98b094176592a', '广州有点热，客房服务很贴心多准备了饮用水。第一天看演唱会，第二天出去玩原本回来想问客房多要几瓶水的，没想到都准备好了，非常满意。酒店很漂亮，出行便捷，门口就有地铁站。', '["https://dimg04.c-ctrip.com/images/0237412000eunv3f800FB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234312000eunz5zb0C01_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000eunwhznEFAB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232g12000euo6lad144E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-21', '红棉双床套房', '套房', '朋友出游', 83, 4.430816798843313, 0, 0.0, 11, 2.4849066497880004, 8, '["客房服务", "交通便利性", "整体满意度"]'::jsonb, '客房服务', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '广州有点热，客房服务很贴心多准备了饮用水。第一天看演唱会，第二天出去玩原本回来想', '广州有点热，客房服务很贴心多准备了饮用水。第一天看演唱会，第二天出去玩原本回来想问客房多要几瓶水的，没想到都准备好了，非常满意。酒店很漂亮，出行便捷，门口就有地铁站。', '2024-07-21', 5, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b0de3c98b094176592b', '在预定前就了解到花园酒店的背景，也考虑到酒店因为装修比较老旧可能会有一些体验上的不足。但实际入住后觉得一直被惊喜到。酒店迎宾很体贴，能看到我（其实并未主动提出）的特殊入住需求，也给了很多实用建议。房间虽然不大，也没有智能马桶，但对我提出要除湿机马上就能响应。酒店的早餐很惊艳，虽说是网红餐厅但并没有因为客人众多而服务有任何缺失，其他餐厅预定也很方便。一层的花园人非常少，吃完早餐去溜达一下很悠闲。酒店位置也非常便利，出门就是地铁，周围都是餐厅，不想出门就订外卖，外卖柜位置虽然隐秘但知道在哪里后就挺好找的。', '["https://dimg04.c-ctrip.com/images/0234j12000emsnbm08233_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233412000emslgbm2CE3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231s12000emscou3CCA6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-06-30', '花园大床房', '大床房', '独自旅行', 253, 5.537334267018537, 0, 0.0, 2, 1.0986122886681098, 9, '["前台服务", "餐饮设施", "交通便利性"]'::jsonb, '前台服务', '餐饮设施', '交通便利性', '未知酒店', '未知地点', '匿名', '在预定前就了解到花园酒店的背景，也考虑到酒店因为装修比较老旧可能会有一些体验上的', '在预定前就了解到花园酒店的背景，也考虑到酒店因为装修比较老旧可能会有一些体验上的不足。但实际入住后觉得一直被惊喜到。酒店迎宾很体贴，能看到我（其实并未主动提出）的特殊入住需求，也给了很多实用建议。房间虽然不大，也没有智能马桶，但对我提出要除湿机马上就能响应。酒店的早餐很惊艳，虽说是网红餐厅但并没有因为客人众多而服务有任何缺失，其他餐厅预定也很方便。一层的花园人非常少，吃完早餐去溜达一下很悠闲。酒店位置也非常便利，出门就是地铁，周围都是餐厅，不想出门就订外卖，外卖柜位置虽然隐秘但知道在哪里后就挺好找的。', '2024-06-30', 4, '前台服务');
