INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b24e3c98b0941765937', '前台服务很热情，大堂造型很顶，入住时才知道花园酒店是中国三家白金五星酒店之一，还有个酒店博物馆。整体感觉不错。', '["https://dimg04.c-ctrip.com/images/0233r224x8w26llli14ED_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02323224x8w28gvji3736_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231q224x8w29k1v127E4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-24', '花园双床房', '双床房', '家庭亲子', 55, 4.02535169073515, 0, 0.0, 1, 0.6931471805599453, 7, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '前台服务很热情，大堂造型很顶，入住时才知道花园酒店是中国三家白金五星酒店之一，还', '前台服务很热情，大堂造型很顶，入住时才知道花园酒店是中国三家白金五星酒店之一，还有个酒店博物馆。整体感觉不错。', '2024-08-24', 5, '前台服务');
