INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b24e3c98b0941765939', '老牌五星级酒店，细节很有特色和文化底蕴，早餐在一楼和三十楼都可以，菜品很丰富，三十楼的旋转餐厅可360度观景，用下午茶时30楼行政酒廊的印度小姐姐carrie中文流利、热情大方，第二天早餐后还收到了全英文的祝福小卡片，下次还会入住。', '["https://dimg04.c-ctrip.com/images/0233e12000eny75s57C84_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236s12000enxxek479CF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-03', '红棉大床套房', '套房', '其他', 116, 4.762173934797756, 0, 0.0, 2, 1.0986122886681098, 9, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '老牌五星级酒店，细节很有特色和文化底蕴，早餐在一楼和三十楼都可以，菜品很丰富，三', '老牌五星级酒店，细节很有特色和文化底蕴，早餐在一楼和三十楼都可以，菜品很丰富，三十楼的旋转餐厅可360度观景，用下午茶时30楼行政酒廊的印度小姐姐carrie中文流利、热情大方，第二天早餐后还收到了全英文的祝福小卡片，下次还会入住。', '2024-07-03', 5, '餐饮设施');
