INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b24e3c98b094176593b', '入住广州花园酒店是我在广东住的最满意的酒店，一进大堂，富丽堂皇！虽然是老五星，很有年代感，服务却很到位！后花园真的漂亮，小朋友特别喜欢，喷泉瀑布园林花草！特别是前台的小洪美女细心的在身份证上看到当天的生日，贴心的为我们免费升级了房间，让我们在酒店过了一个难忘的生日！真心感谢！还有迎宾的李雯美女，送了礼物给了我家的小朋友，谢谢你们！', '["https://dimg04.c-ctrip.com/images/0235d12000j9rs8b10667_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p12000j9s1dtq13B0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f12000j9ray9lCE58_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230z12000j9s1bp4DABB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000j9ripa3934F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-23', '花园双床房', '双床房', '家庭亲子', 166, 5.117993812416755, 0, 0.0, 5, 1.791759469228055, 9, '["前台服务", "整体满意度", "公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '入住广州花园酒店是我在广东住的最满意的酒店，一进大堂，富丽堂皇！虽然是老五星，很', '入住广州花园酒店是我在广东住的最满意的酒店，一进大堂，富丽堂皇！虽然是老五星，很有年代感，服务却很到位！后花园真的漂亮，小朋友特别喜欢，喷泉瀑布园林花草！特别是前台的小洪美女细心的在身份证上看到当天的生日，贴心的为我们免费升级了房间，让我们在酒店过了一个难忘的生日！真心感谢！还有迎宾的李雯美女，送了礼物给了我家的小朋友，谢谢你们！', '2025-03-23', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b24e3c98b094176593c', '酒店不错！', '["https://dimg04.c-ctrip.com/images/0233212000gzwyoi1EDA4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234y12000gzxoqqg018E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231712000gzxgkij341A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-12-02', '花园大床房', '大床房', '家庭亲子', 5, 1.791759469228055, 0, 0.0, 14, 2.70805020110221, 1, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '酒店不错！', '酒店不错！', '2024-12-02', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b24e3c98b094176593d', '花园酒店，名副其实！环境真的很美，酒店的每处的花艺设计都非常高级！尤其是瀑布餐厅，只能用哇塞来形容了??????拍照巨出片！
再来夸一下服务，从到酒店大门下车，从迎宾开始的每一位工作人员都很有耐心，满脸笑容！真的让我体会到了宾至如归的感觉！因为是zijiz人带着1岁多的宝宝，有的时候来不及照看宝宝的时候，大厅里的工作人员都会帮忙照顾，非常贴心！
虽然花园酒店是老牌五星酒店，但是房间设施还是一样很好！唯一的建议就是希望贵酒店能够提供儿童围栏就更加完美了！', '["https://dimg04.c-ctrip.com/images/0230s12000ergsov65807_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000ergp7q8D3CB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236y12000ergpnpb9297_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236012000ergsb4s919A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232e12000ero0gc8F764_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235n12000erntfco2AC3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-13', '花园大床房', '大床房', '家庭亲子', 228, 5.43372200355424, 0, 0.0, 2, 1.0986122886681098, 9, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '花园酒店，名副其实！环境真的很美，酒店的每处的花艺设计都非常高级！尤其是瀑布餐厅', '花园酒店，名副其实！环境真的很美，酒店的每处的花艺设计都非常高级！尤其是瀑布餐厅，只能用哇塞来形容了??????拍照巨出片！
再来夸一下服务，从到酒店大门下车，从迎宾开始的每一位工作人员都很有耐心，满脸笑容！真的让我体会到了宾至如归的感觉！因为是zijiz人带着1岁多的宝宝，有的时候来不及照看宝宝的时候，大厅里的工作人员都会帮忙照顾，非常贴心！
虽然花园酒店是老牌五星酒店，但是房间设施还是一样很好！唯一的建议就是希望贵酒店能够提供儿童围栏就更加完美了！', '2024-07-13', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b24e3c98b094176593e', '带爸妈一起出游，入住3晚的红棉套房，非常好的体验，前台的工作人员Winne Wei热情负责。
酒店保养了不错，比较新。打车去各景点都比较近，餐饮配套齐全，这点特别方便。留了一点小遗憾，来不及去打卡瀑布餐厅下午茶。', '["https://dimg04.c-ctrip.com/images/0234u12000fyatoe0AF18_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234l12000fy9iizb4969_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232112000fya7brhCBE6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000fy94hl8A6FC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x12000fy9g4li13CF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-03', '花园双床房', '双床房', '家庭亲子', 107, 4.68213122712422, 0, 0.0, 2, 1.0986122886681098, 7, '["前台服务", "周边配套", "交通便利性"]'::jsonb, '前台服务', '周边配套', '交通便利性', '未知酒店', '未知地点', '匿名', '带爸妈一起出游，入住3晚的红棉套房，非常好的体验，前台的工作人员Winne We', '带爸妈一起出游，入住3晚的红棉套房，非常好的体验，前台的工作人员Winne Wei热情负责。
酒店保养了不错，比较新。打车去各景点都比较近，餐饮配套齐全，这点特别方便。留了一点小遗憾，来不及去打卡瀑布餐厅下午茶。', '2024-10-03', 5, '前台服务');
