INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b2fe3c98b0941765946', '满分好评，感谢Rebecca女士帮我们升级了套房房型，让旅行十分完美！@Rebecca
老牌白金五星酒店，瀑布餐厅超级壮观。
最主要是房间整洁、宽敞，新中式的装修风格给人留下了深刻印象，电动窗帘和中式酒柜的设计也很别出心裁。
