INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b39e3c98b094176594d', '出差多年，五星级酒店也住过很多，第一次特别想写点评给花园酒店，不管是套房旋转餐厅还是服务人员的服务态意识，水准都非常高！景色太棒了(ˉ▽ˉ)??，太适合我们这样出差没时间逛的客人了，酒吧乐队水平也很高，请每位喝了一瓶啤酒，性价比绝高，推荐给朋友100次(‐＾▽＾‐)??', '["https://dimg04.c-ctrip.com/images/0234s12000e8qgpzt9FAC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230x12000e8r02e67F52_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000e8r056gED09_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000e8qvne6CF6B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230x12000e8qu5hr006F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000e8r05e04F45_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230112000e8qe27v44F2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000e8r056iDB19_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234i12000e8qnafeFE50_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-30', '花园大床房', '大床房', '商务出差', 135, 4.912654885736052, 0, 0.0, 11, 2.4849066497880004, 8, '["整体满意度", "性价比", "前台服务"]'::jsonb, '整体满意度', '性价比', '前台服务', '未知酒店', '未知地点', '匿名', '出差多年，五星级酒店也住过很多，第一次特别想写点评给花园酒店，不管是套房旋转餐厅', '出差多年，五星级酒店也住过很多，第一次特别想写点评给花园酒店，不管是套房旋转餐厅还是服务人员的服务态意识，水准都非常高！景色太棒了(ˉ▽ˉ)??，太适合我们这样出差没时间逛的客人了，酒吧乐队水平也很高，请每位喝了一瓶啤酒，性价比绝高，推荐给朋友100次(‐＾▽＾‐)??', '2024-05-30', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b39e3c98b094176594e', '这次总共入住4晚，可爱的前厅Virina小姐姐(名字拼写不知道有没有写错)让我们用很优惠的价格升级到粤韵双床房，还送了早餐！
