超级棒的入住体验，酒店出门就是地铁去哪都很方便。下次去广州还会选择花园酒店！', '2024-06-09', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b39e3c98b094176594f', '体验非常好，不愧是老牌五星酒店，打卡过上海花园酒店，慕名来到广州花园酒店。感谢客房部姚师傅，非常细心周到，下次还会去', '["https://dimg04.c-ctrip.com/images/0236o12000hzukicj630C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000hzupp3g77D9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-22', '红棉大床套房', '套房', '家庭亲子', 58, 4.07753744390572, 0, 0.0, 10, 2.3978952727983707, 6, '["整体满意度", "客房服务"]'::jsonb, '整体满意度', '客房服务', NULL, '未知酒店', '未知地点', '匿名', '体验非常好，不愧是老牌五星酒店，打卡过上海花园酒店，慕名来到广州花园酒店。感谢客', '体验非常好，不愧是老牌五星酒店，打卡过上海花园酒店，慕名来到广州花园酒店。感谢客房部姚师傅，非常细心周到，下次还会去', '2025-01-22', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b39e3c98b0941765950', '和同事出差，一如既往的历史的沉淀的稳重的高级感。热情的服务，布置精美的鲜花出其不意的出现在各个角落。健身房环境也很赞完成了一个5公里', '["https://dimg04.c-ctrip.com/images/0230f12000fewetmjA171_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235o12000fewc5761E5A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-05', '花园大床房', '大床房', '商务出差', 66, 4.204692619390966, 0, 0.0, 23, 3.1780538303479458, 7, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '和同事出差，一如既往的历史的沉淀的稳重的高级感。热情的服务，布置精美的鲜花出其不', '和同事出差，一如既往的历史的沉淀的稳重的高级感。热情的服务，布置精美的鲜花出其不意的出现在各个角落。健身房环境也很赞完成了一个5公里', '2024-09-05', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b39e3c98b0941765951', '第一次住花园酒店，设施卫生环境都很好，前台的Viria非常nice，想人所想急人所急，表扬一下，老板该给加薪了。??因为不错的服务又续住了几晚，下次还会再来。', '["https://dimg04.c-ctrip.com/images/0234x12000epphwhr81C5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236412000epprkqx19EB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p12000eppqzyv35D7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-08', '花园双床房', '双床房', '家庭亲子', 79, 4.382026634673881, 0, 0.0, 5, 1.791759469228055, 7, '["前台服务", "整体满意度", "卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '第一次住花园酒店，设施卫生环境都很好，前台的Viria非常nice，想人所想急人', '第一次住花园酒店，设施卫生环境都很好，前台的Viria非常nice，想人所想急人所急，表扬一下，老板该给加薪了。??因为不错的服务又续住了几晚，下次还会再来。', '2024-07-08', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b39e3c98b0941765952', '花园酒店是老牌的五星酒店了，地段就在闹市中心，大堂金碧辉煌，带一个大大的后花园，四楼还有一个酒店博物馆，酒店自带10家餐厅，可以说无敌方便了。30楼的旋转餐厅可以俯瞰360度风景，环境雅致，早餐品种很丰富，下午提供下午茶、五点后还有happy hour，来自印度的Carrie讲得一口流利的中文，笑容甜美，热心帮我们介绍了很多美食，还有美酒、现做的烤饼，还会热情跟小朋友互动，Aimee、Mignon服务效率特别高，还有Lina，都让人感受到宾至如归，一家人都留下难忘的美好回忆，下次还会再来的！', '["https://dimg04.c-ctrip.com/images/0231u12000eeeo6wl33C1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235912000eeep36cF8D2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000eeegvxt159D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000eeeojmx8172_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231712000eeekpz91501_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-06-09', '花园大床房', '大床房', '家庭亲子', 248, 5.517452896464707, 0, 0.0, 2, 1.0986122886681098, 9, '["餐饮设施", "整体满意度", "周边配套"]'::jsonb, '餐饮设施', '整体满意度', '周边配套', '未知酒店', '未知地点', '匿名', '花园酒店是老牌的五星酒店了，地段就在闹市中心，大堂金碧辉煌，带一个大大的后花园，', '花园酒店是老牌的五星酒店了，地段就在闹市中心，大堂金碧辉煌，带一个大大的后花园，四楼还有一个酒店博物馆，酒店自带10家餐厅，可以说无敌方便了。30楼的旋转餐厅可以俯瞰360度风景，环境雅致，早餐品种很丰富，下午提供下午茶、五点后还有happy hour，来自印度的Carrie讲得一口流利的中文，笑容甜美，热心帮我们介绍了很多美食，还有美酒、现做的烤饼，还会热情跟小朋友互动，Aimee、Mignon服务效率特别高，还有Lina，都让人感受到宾至如归，一家人都留下难忘的美好回忆，下次还会再来的！', '2024-06-09', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b39e3c98b0941765953', '花园酒店名不虚传！', '["https://dimg04.c-ctrip.com/images/0236c12000gvu4b5s2559_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-26', '红棉双床套房', '套房', '商务出差', 9, 2.302585092994046, 0, 0.0, 8, 2.19722457733622, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '花园酒店名不虚传！', '花园酒店名不虚传！', '2024-11-26', 5, '整体满意度');
