INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b4ce3c98b094176595a', '房间卫生干净服务很好热情周到，一楼西餐厅也不错就是太多美洲飞洲伊朗等外国人，周边没什么可吃的离地铁比较近出门就是打车也方便门口就有很多', '["https://dimg04.c-ctrip.com/images/0232v12000et5l7wk75E7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232o12000et5ithw9486_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232812000et5vz277A67_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231612000et5rly436C8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000et5qjp1965E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000et5k13q7C84_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-17', '花园双床房', '双床房', '家庭亲子', 67, 4.219507705176107, 0, 0.0, 8, 2.19722457733622, 6, '["卫生状况", "交通便利性", "餐饮设施"]'::jsonb, '卫生状况', '交通便利性', '餐饮设施', '未知酒店', '未知地点', '匿名', '房间卫生干净服务很好热情周到，一楼西餐厅也不错就是太多美洲飞洲伊朗等外国人，周边', '房间卫生干净服务很好热情周到，一楼西餐厅也不错就是太多美洲飞洲伊朗等外国人，周边没什么可吃的离地铁比较近出门就是打车也方便门口就有很多', '2024-07-17', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b4ce3c98b094176595b', '强烈推荐花园酒店，在这里度过了非常愉快的时光。本来看了些差评有些犹豫，但酒店就在地铁口，交通方便，而且由于是从天河区换到这边住，来不及再选了，就想先过来看看，事实证明来对了。一进门就被酒店大堂吸引，中西合璧的布置非常漂亮，工作人员很多但井然有序。前台办理入住的viria小姐姐人美心善，专业高效，很快就办好了手续，主动升级了套房，住的非常舒心，还送了行政酒廊的下午茶，非常感谢。一整天一直在下雨，懒得出门，但行政酒廊的食材新鲜，服务超好，也是很好的体验，mignon一直在介绍酒店各个餐厅，推荐各类饮品和餐食，还按照我的要求，特调了一杯很清淡的酒，非常好喝。Carrie是一个印度小姐姐，聊了一会儿weather，aimee和lina也非常热情周到！早餐在旋转餐厅吃的，俯瞰下去景色很美，小哥哥们服务周到。雨停了，去花园转了一圈，步步有景，鱼很漂亮也很肥，很多人拍照。4层的博物馆比想象中大而全，不仅有酒店的历史，也有些广州的历史和酒店行业的发展史。', '["https://dimg04.c-ctrip.com/images/0233v12000ea5scmuD3C8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000ea64e5kE23B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000ea613h93442_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236912000ea61jx8AB55_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-06-02', '花园大床房', '大床房', '独自旅行', 425, 6.054439346269371, 0, 0.0, 8, 2.19722457733622, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '强烈推荐花园酒店，在这里度过了非常愉快的时光。本来看了些差评有些犹豫，但酒店就在', '强烈推荐花园酒店，在这里度过了非常愉快的时光。本来看了些差评有些犹豫，但酒店就在地铁口，交通方便，而且由于是从天河区换到这边住，来不及再选了，就想先过来看看，事实证明来对了。一进门就被酒店大堂吸引，中西合璧的布置非常漂亮，工作人员很多但井然有序。前台办理入住的viria小姐姐人美心善，专业高效，很快就办好了手续，主动升级了套房，住的非常舒心，还送了行政酒廊的下午茶，非常感谢。一整天一直在下雨，懒得出门，但行政酒廊的食材新鲜，服务超好，也是很好的体验，mignon一直在介绍酒店各个餐厅，推荐各类饮品和餐食，还按照我的要求，特调了一杯很清淡的酒，非常好喝。Carrie是一个印度小姐姐，聊了一会儿weather，aimee和lina也非常热情周到！早餐在旋转餐厅吃的，俯瞰下去景色很美，小哥哥们服务周到。雨停了，去花园转了一圈，步步有景，鱼很漂亮也很肥，很多人拍照。4层的博物馆比想象中大而全，不仅有酒店的历史，也有些广州的历史和酒店行业的发展史。', '2024-06-02', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b4ce3c98b094176595c', '酒店老牌五星，大厅很大气，房间很好，前台小姐姐ANN免费升级了房间，唯一就是停车场在边上，要走几步。', '["https://dimg04.c-ctrip.com/images/0233e12000f3ka90d3CF2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231l12000f3kac4s95E6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-12', '花园双床房', '双床房', '家庭亲子', 50, 3.9318256327243257, 0, 0.0, 10, 2.3978952727983707, 6, '["前台服务", "公共设施", "整体满意度"]'::jsonb, '前台服务', '公共设施', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店老牌五星，大厅很大气，房间很好，前台小姐姐ANN免费升级了房间，唯一就是停车', '酒店老牌五星，大厅很大气，房间很好，前台小姐姐ANN免费升级了房间，唯一就是停车场在边上，要走几步。', '2024-08-12', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027b4ce3c98b094176595d', '旧地重游『白金五星级酒店』：广州花园酒店，园林的建筑景观，定会让你宾至如归。每次下榻位于闹中取静的市中心——花园酒店，都能给我一种好温馨的感觉。在这里，我遇到了酒店行政酒廊的Carrie姐姐和她的同事Aimee，得知我们是一家人来城央度假为我们的其中一间房间升级为粤韵房和给了我们一家人的行政酒廊使用权。这次的行政酒廊是在30楼，凌旋阁广州最大的旋转餐厅——可容纳两千多人同时进餐的凌旋阁，北眺云山，南望珠水，可以尽览广州的景色。早餐选择丰富且中西结合。同行老人家都不得不赞叹一个字“靓”。用餐过程中行政酒廊的Carrie姐姐会不定时过来询问是否需要帮助，入住期间还去了后花园观赏锦鲤，感觉“老朋友”都被养得胖嘟嘟了。在这里，Carrie姐姐和Aimee的服务很好的诠释了白金五星级酒店的水平。再次感谢您们对我们一家的款待。期待下次再见！', '["https://dimg04.c-ctrip.com/images/0236u12000e2jzvkgF44E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232i12000e2jzyz1585F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000e2jzv2f8EBB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233a12000e2k00oiBC72_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000e2k007g8E18_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000e2k008q7B1F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236912000e2k189z7F8A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000e2k03wk3C0C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c12000e2k02niD1B2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-19', '红棉双床套房', '套房', '家庭亲子', 369, 5.91350300563827, 1, 0.6931471805599453, 3, 1.3862943611198906, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '旧地重游『白金五星级酒店』：广州花园酒店，园林的建筑景观，定会让你宾至如归。每次', '旧地重游『白金五星级酒店』：广州花园酒店，园林的建筑景观，定会让你宾至如归。每次下榻位于闹中取静的市中心——花园酒店，都能给我一种好温馨的感觉。在这里，我遇到了酒店行政酒廊的Carrie姐姐和她的同事Aimee，得知我们是一家人来城央度假为我们的其中一间房间升级为粤韵房和给了我们一家人的行政酒廊使用权。这次的行政酒廊是在30楼，凌旋阁广州最大的旋转餐厅——可容纳两千多人同时进餐的凌旋阁，北眺云山，南望珠水，可以尽览广州的景色。早餐选择丰富且中西结合。同行老人家都不得不赞叹一个字“靓”。用餐过程中行政酒廊的Carrie姐姐会不定时过来询问是否需要帮助，入住期间还去了后花园观赏锦鲤，感觉“老朋友”都被养得胖嘟嘟了。在这里，Carrie姐姐和Aimee的服务很好的诠释了白金五星级酒店的水平。再次感谢您们对我们一家的款待。期待下次再见！', '2024-05-19', 5, '前台服务');
